// ── v4.9.0 ResolutionMatters #4: alert-resolution timeline (MTTR) ────────────
async function loadAlertMttr() {
  const daysEl = document.getElementById('mttr-days');
  const days = (daysEl && daysEl.value) || '30';
  const summary = document.getElementById('mttr-summary');
  const hostsBox = document.getElementById('mttr-hosts');
  const tb = document.getElementById('mttr-tbody');
  if (summary) summary.textContent = 'Loading…';
  const data = await api('GET', `/alerts/resolution-stats?days=${encodeURIComponent(days)}`);
  if (!data) { if (summary) summary.textContent = 'Failed to load'; return; }
  if (summary) summary.textContent =
    `${data.resolved_count} resolved · MTTR mean ${_fmtDuration(data.mttr_mean)} · median ${_fmtDuration(data.mttr_median)} · MTTA ${_fmtDuration(data.mtta_mean)}`;
  if (hostsBox) {
    const hosts = (data.hosts || []).slice(0, 12);
    hostsBox.innerHTML = hosts.length
      ? '<div class="hint mb-8">Per host:</div>' + hosts.map(h =>
          `<span class="group-badge" title="${escAttr(h.host)} · ${h.count} resolved · mean MTTR ${_fmtDuration(h.mttr_mean)}">${escHtml(h.host)} ${h.count} · ${escHtml(_fmtDuration(h.mttr_mean))}</span>`).join(' ')
      : '';
  }
  if (!tb) return;
  const sevCls = { critical: 'c-red', high: 'c-red', medium: 'c-amber', low: 'c-muted', info: 'c-muted' };
  const howBadge = { auto: 'c-green', manual: 'c-accent', muted: 'c-muted', unknown: 'c-muted' };
  const rows = data.timeline || [];
  tb.innerHTML = rows.length ? rows.map(t => {
    const when = t.resolved_at ? new Date(t.resolved_at * 1000).toLocaleString() : '—';
    const by = t.how === 'manual' ? (t.resolved_by || t.acknowledged_by || '—') : (t.how === 'auto' ? 'recover event' : (t.resolved_by || '—'));
    const note = t.note ? `<div class="hint">${escHtml(t.note)}</div>` : '';
    return `<tr><td class="meta-sm-nm">${escHtml(when)}</td>`
      + `<td class="${sevCls[t.severity] || 'c-muted'}">${escHtml(t.severity || '')}</td>`
      + `<td>${escHtml(t.title || t.event || '')}${note}</td>`
      + `<td>${escHtml(t.host || '')}</td>`
      + `<td class="meta-sm-nm">${t.mttr != null ? escHtml(_fmtDuration(t.mttr)) : '—'}</td>`
      + `<td class="${howBadge[t.how] || 'c-muted'}">${escHtml(t.how || '')}</td>`
      + `<td>${escHtml(by)}</td></tr>`;
  }).join('') : '<tr><td colspan="7" class="hint">No resolved alerts in this window.</td></tr>';
}

// ── v4.1.0: Checks page (CheckMK-style per-host service status) ──────────────
let _checksRows = [];
async function loadChecks() {
  const tbody = document.getElementById('checks-tbody');
  if (!tbody) return;
  tableCtl.wireSortOnly('checks-thead', 'checks', renderChecks);
  tbody.innerHTML = _skeletonRows(6);
  try {
    const data = await api('GET', '/checks');
    // Flatten the host matrix into one row per (host, check).
    _checksRows = [];
    for (const h of ((data && data.hosts) || [])) {
      for (const c of (h.checks || [])) {
        _checksRows.push({ device_id: h.device_id, host: h.name, group: h.group || '',
          monitored: h.monitored !== false,
          key: c.key, check: c.name, cgroup: c.group || '', status: c.status,
          output: c.output || '', enabled: c.enabled !== false });
      }
    }
    renderChecks();
  } catch (e) {
    tbody.innerHTML = '<tr><td colspan="6" class="c-red">Failed to load checks.</td></tr>';
  }
}
const _CHK_RANK = { critical: 0, warning: 1, unknown: 2, ok: 3 };
function renderChecks() {
  const tbody = document.getElementById('checks-tbody');
  if (!tbody) return;
  const statusSel = (document.getElementById('checks-filter-status') || {}).value || '';
  const q = ((document.getElementById('checks-filter-text') || {}).value || '').trim().toLowerCase();
  const hideDisabled = !!(document.getElementById('checks-hide-disabled') || {}).checked;
  const hideUnmonEl = document.getElementById('checks-hide-unmon');
  const hideUnmon = hideUnmonEl ? hideUnmonEl.checked : true;   // hidden by default
  let rows = _checksRows.filter(r => {
    if (hideUnmon && r.monitored === false) return false;
    if (hideDisabled && !r.enabled) return false;
    if (statusSel === 'notok') { if (r.status === 'ok') return false; }
    else if (statusSel && r.status !== statusSel) return false;
    if (q && !(`${r.host} ${r.group} ${r.check} ${r.cgroup} ${r.output}`.toLowerCase().includes(q))) return false;
    return true;
  });
  // Summary counts over the (unfiltered) enabled checks.
  const sum = { ok: 0, warning: 0, critical: 0, unknown: 0 };
  _checksRows.forEach(r => {
    if (hideUnmon && r.monitored === false) return;
    if (r.enabled) sum[r.status] = (sum[r.status] || 0) + 1;
  });
  const se = document.getElementById('checks-summary');
  if (se) se.innerHTML =
    `<span class="chk-pill chk-critical">CRIT ${sum.critical}</span> ` +
    `<span class="chk-pill chk-warning">WARN ${sum.warning}</span> ` +
    `<span class="chk-pill chk-unknown">UNK ${sum.unknown}</span> ` +
    `<span class="chk-pill chk-ok">OK ${sum.ok}</span>`;
  rows = tableCtl.sortRows('checks', rows, r => ({
    host: r.host.toLowerCase(), group: r.group.toLowerCase(),
    check: r.check.toLowerCase(), status: _CHK_RANK[r.status] ?? 9,
    output: r.output.toLowerCase(),
  }));
  if (!rows.length) { tbody.innerHTML = '<tr><td colspan="6" class="hint">No checks match.</td></tr>'; return; }
  tbody.innerHTML = rows.map(r => {
    const arg = `${r.device_id}|${r.key}`;
    const toggle = r.enabled
      ? `<button class="btn-icon btn-xs" data-action="toggleHostCheck" data-arg="${escAttr(arg)}|0" title="Disable this check on ${escAttr(r.host)}">Disable</button>`
      : `<button class="btn-icon btn-xs" data-action="toggleHostCheck" data-arg="${escAttr(arg)}|1">Enable</button>`;
    return `<tr class="chk-row${r.enabled ? '' : ' disabled'}">
      <td><button class="tl-devchip" data-action="openDeviceTimeline" data-arg="${escAttr(r.device_id)}">${escHtml(r.host)}</button></td>
      <td class="hint">${escHtml(r.group || '—')}</td>
      <td>${escHtml(r.check)}<div class="hint">${escHtml(r.cgroup)}</div></td>
      <td><span class="chk-pill chk-${r.status}">${r.status}</span></td>
      <td class="fs-12">${escHtml(r.output)}</td>
      <td class="nowrap">${toggle}</td></tr>`;
  }).join('');
}
async function toggleHostCheck(arg) {
  const [device_id, key, en] = String(arg).split('|');
  const enabled = en === '1';
  const r = await api('POST', '/checks/toggle', { device_id, check: key, enabled });
  if (r && r.ok) {
    const row = _checksRows.find(x => x.device_id === device_id && x.key === key);
    if (row) row.enabled = enabled;
    renderChecks();
  } else { toast((r && r.error) || 'Failed', 'error'); }
}

// ── Custom checks (v4.1.0) ─────────────────────────────────────────────────
const _CC_PARAM_LABELS = {
  process: 'Process name', port_open: 'Port', port_closed: 'Port',
  file_present: 'File path', file_absent: 'File path', job_fresh: 'File path',
  log_errors: 'Pattern (regex)',
};
const _CC_PARAM_PH = {
  process: 'nginx', port_open: '443', port_closed: '23',
  file_present: '/etc/myapp.conf', file_absent: '/etc/nologin',
  job_fresh: '/var/backups/last-run.stamp', log_errors: 'error|fail|panic',
};
function ccKindChanged() {
  const kind = document.getElementById('cc-kind')?.value || 'all';
  document.getElementById('cc-target-grp')?.classList.toggle('hidden', kind === 'all');
  const lbl = document.getElementById('cc-target-label');
  const inp = document.getElementById('cc-target');
  if (lbl) lbl.textContent = kind === 'host' ? 'Device ID' : kind === 'tag' ? 'Tag' : 'Group';
  if (inp) inp.placeholder = kind === 'host' ? 'device id' : kind === 'tag' ? 'tag name' : 'group name';
}
function ccTypeChanged() {
  const t = document.getElementById('cc-type')?.value || 'process';
  const lbl = document.getElementById('cc-param-label');
  if (lbl) lbl.textContent = _CC_PARAM_LABELS[t] || 'Value';
  const inp = document.getElementById('cc-param');
  if (inp) inp.placeholder = _CC_PARAM_PH[t] || '';
  document.getElementById('cc-log-grp')?.classList.toggle('hidden', t !== 'log_errors');
  document.getElementById('cc-job-grp')?.classList.toggle('hidden', t !== 'job_fresh');
}
let _ccCache = [];
let _ccEditId = null;
function _ccResetForm() {
  _ccEditId = null;
  ['cc-name', 'cc-param', 'cc-target', 'cc-window', 'cc-warn', 'cc-crit', 'cc-unit', 'cc-maxage']
    .forEach(id => { const e = document.getElementById(id); if (e) e.value = ''; });
  const k = document.getElementById('cc-kind'); if (k) k.value = 'all';
  const t = document.getElementById('cc-type'); if (t) t.value = 'process';
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Add check';
  ccKindChanged(); ccTypeChanged();
}
async function openCustomChecks() {
  _ccResetForm();
  openModal('custom-checks-modal');
  loadCustomCheckList();
}
async function loadCustomCheckList() {
  const el = document.getElementById('cc-list');
  if (!el) return;
  const data = await api('GET', '/checks/custom');
  const checks = (data && data.checks) || [];
  _ccCache = checks;
  if (!checks.length) { el.innerHTML = '<div class="empty-state">No custom checks yet.</div>'; return; }
  const scope = c => c.target_kind === 'all' ? 'whole fleet' : `${c.target_kind}: ${escHtml(c.target)}`;
  const editBtn = id => `<button class="btn-icon btn-xs" data-action="editCustomCheck" data-arg="${escAttr(id)}" title="Edit this check">${_icon('edit',14)}</button>`;
  el.innerHTML = `<div class="table-card"><table><thead><tr><th>Name</th><th>Type</th><th>Param</th><th>Applies to</th><th></th></tr></thead><tbody>${
    checks.map(c => `<tr><td class="fw-500">${escHtml(c.name)}</td><td><span class="patch-badge ok fs-11">${escHtml(c.type)}</span></td><td class="mono-12">${escHtml(c.param)}</td><td class="hint">${scope(c)}</td><td><div class="user-actions">${editBtn(c.id)}<button class="btn-icon btn-xs c-danger-outline" title="Delete" data-action="deleteCustomCheck" data-arg="${escAttr(c.id)}">${_icon('trash',14)}</button></div></td></tr>`).join('')
  }</tbody></table></div>`;
}
function editCustomCheck(id) {
  const c = (_ccCache || []).find(x => x.id === id);
  if (!c) { toast('Check not found', 'error'); return; }
  _ccEditId = id;
  const setv = (eid, v) => { const e = document.getElementById(eid); if (e) e.value = (v === undefined || v === null) ? '' : v; };
  setv('cc-name', c.name); setv('cc-type', c.type || 'process'); setv('cc-param', c.param);
  setv('cc-kind', c.target_kind || 'all'); setv('cc-target', c.target);
  setv('cc-window', c.window_min); setv('cc-warn', c.warn); setv('cc-crit', c.crit);
  setv('cc-unit', c.unit); setv('cc-maxage', c.max_age_hours);
  ccKindChanged(); ccTypeChanged();
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Save changes';
  const nm = document.getElementById('cc-name'); if (nm) nm.focus();
}
async function saveCustomCheck() {
  const body = {
    name: document.getElementById('cc-name')?.value.trim() || '',
    type: document.getElementById('cc-type')?.value || 'process',
    param: document.getElementById('cc-param')?.value.trim() || '',
    target_kind: document.getElementById('cc-kind')?.value || 'all',
    target: document.getElementById('cc-target')?.value.trim() || '',
  };
  if (_ccEditId) body.id = _ccEditId;   // update-in-place keyed on id
  if (!body.param) { toast('A value is required', 'error'); return; }
  const numOf = id => { const v = parseInt(document.getElementById(id)?.value, 10); return isNaN(v) ? undefined : v; };
  if (body.type === 'log_errors') {
    body.window_min = numOf('cc-window');
    body.warn = numOf('cc-warn');
    body.crit = numOf('cc-crit');
    body.unit = document.getElementById('cc-unit')?.value.trim() || '';
  } else if (body.type === 'job_fresh') {
    body.max_age_hours = numOf('cc-maxage');
  }
  const r = await api('POST', '/checks/custom', body);
  if (r && r.ok) {
    toast(_ccEditId ? 'Custom check saved' : 'Custom check added', 'success');
    _ccResetForm();
    loadCustomCheckList();
  } else { toast((r && r.error) || 'Failed', 'error'); }
}
async function deleteCustomCheck(id) {
  const r = await api('POST', '/checks/custom/delete', {id});
  if (r && r.ok) { loadCustomCheckList(); } else { toast((r && r.error) || 'Failed', 'error'); }
}

function _renderAlertsSummary(summary) {
  const el = document.getElementById('alerts-summary');
  if (!el) return;
  if (!summary) { el.innerHTML = ''; return; }
  const bs = summary.by_severity || {};
  el.innerHTML =
    `<span class="alerts-summary-pill">Open: <strong>${summary.open || 0}</strong></span>` +
    `<span class="alerts-summary-pill">Acknowledged: <strong>${summary.acknowledged || 0}</strong></span>` +
    `<span class="alerts-summary-pill">Resolved: <strong>${summary.resolved || 0}</strong></span>` +
    (bs.critical ? `<span class="alerts-summary-pill sev-pill sev-critical">Critical: ${bs.critical}</span>` : '') +
    (bs.high ? `<span class="alerts-summary-pill sev-pill sev-high">High: ${bs.high}</span>` : '');
}

const _ALERT_SEV_RANK = { critical: 0, high: 1, medium: 2, low: 3, info: 4 };
const _ALERT_SEV_NAME = ['critical', 'high', 'medium', 'low'];
// v4.1.0: per-host grouping state. Default grouped; collapsed set persists
// across re-renders within the session.
const _alertGroupsCollapsed = new Set();
function _alertHostKey(a) {
  return a.device_id || (a.device_name ? 'name:' + a.device_name : '__fleet__');
}
// One alert <tr>. role: '' | 'root' | 'symptom' (controls the badge + indent).
function _alertRowHtml(a, role) {
  const isResolved = !!a.resolved_at;
  const ackBy = a.acknowledged_by ? _escapeHtml(a.acknowledged_by) : '—';
  const sev = (a.severity || 'medium');
  const sevPill = `<span class="sev-pill sev-${sev}">${sev}</span>`;
  const dev = a.device_name || a.device_id || '—';
  const ts = _formatTs(a.ts);
  let actions = '';
  if (!isResolved) {
    actions += `<button class="btn-icon btn-xs" data-action="aiInvestigateAlert" data-arg="${a.id}" title="AI: investigate this alert and suggest fixes">${_icon('sparkles',14)} Investigate</button> `;
    if (!a.acknowledged_at) {
      actions += `<button class="btn-icon btn-xs" data-action="ackAlert" data-arg="${a.id}">Ack</button> `;
    } else {
      actions += `<button class="btn-icon btn-xs" data-action="unackAlert" data-arg="${a.id}">Un-ack</button> `;
    }
    actions += `<button class="btn-icon btn-xs c-success" data-action="resolveAlert" data-arg="${a.id}">Resolve</button>`;
    if (window._ticketsOn && !a.rp_ticket) {
      actions += ` <button class="btn-icon btn-xs" data-action="createTicketFromAlert" data-arg="${a.id}" title="Open an incident ticket from this alert">Ticket</button>`;
    }
  } else {
    const byWho = a.resolved_by === 'auto' ? 'auto' : _escapeHtml(a.resolved_by || '');
    actions = `<span class="c-muted">resolved by ${byWho}</span>`;
  }
  const cb = isResolved ? '' :
    `<input type="checkbox" class="alerts-row-cb" data-id="${a.id}" data-action="updateBulkResolveBtn">`;
  const badge = role === 'root'
    ? ' <span class="alert-rc-badge rc-root">root cause</span>'
    : role === 'symptom' ? ' <span class="alert-rc-badge rc-symptom">symptom</span>' : '';
  const titleCls = role === 'symptom' ? ' class="alert-symptom-cell"' : '';
  // v5.0.0: ITSM ticket opened on ack — link straight to it.
  const ticketLink = a.ticket_ref
    ? (a.ticket_url
        ? ` <a href="${escAttr(a.ticket_url)}" target="_blank" rel="noopener" class="patch-badge ok fs-10" title="Open the linked ticket">Ticket ${_escapeHtml(a.ticket_ref)} ↗</a>`
        : ` <span class="patch-badge ok fs-10" title="Linked ticket">Ticket ${_escapeHtml(a.ticket_ref)}</span>`)
    : '';
  return `<tr class="alerts-row${isResolved ? ' resolved' : ''}${role ? ' alert-' + role : ''}">
    <td>${cb}</td>
    <td>${sevPill}</td>
    <td class="nowrap">${ts}</td>
    <td${titleCls}>${_escapeHtml(a.title || a.event || '')}${badge}${ticketLink}${a.rp_ticket ? ` <span class="patch-badge ok fs-10" title="Built-in ticket">${_escapeHtml(_tkNo(a.rp_ticket))}</span>` : ''}${a.alertid ? `<div class="hint">${_escapeHtml(_rpNo(a.alertid))}</div>` : ''}</td>
    <td>${_escapeHtml(dev)}</td>
    <td>${ackBy}</td>
    <td class="nowrap">${actions}</td>
  </tr>`;
}
function renderAlerts() {
  const filterEl = document.getElementById('alerts-filter-text');
  const q = ((filterEl && filterEl.value) || '').trim().toLowerCase();
  let rows = _alertsCache;
  if (q) {
    rows = rows.filter(a =>
      (a.title || '').toLowerCase().includes(q) ||
      (a.device_name || '').toLowerCase().includes(q) ||
      (a.event || '').toLowerCase().includes(q));
  }
  tableCtl.wireSortOnly('alerts-thead', 'alerts', renderAlerts);
  const tbody = document.getElementById('alerts-tbody');
  if (!tbody) return;
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty-state">No alerts in this view.</td></tr>';
    _updateBulkResolveBtn();
    return;
  }
  const groupEl = document.getElementById('alerts-group-host');
  const grouped = groupEl ? groupEl.checked : true;
  if (grouped) { _renderAlertsGrouped(rows); }
  else { _renderAlertsFlat(rows); }
  _updateBulkResolveBtn();
}
function _renderAlertsFlat(rows) {
  // v3.2.1: sortable. Default = ts desc (newest first); operator can override.
  rows = tableCtl.sortRows('alerts', rows, (a) => ({
    severity:        _ALERT_SEV_RANK[a.severity] ?? 99,
    ts:              a.ts || 0,
    title:           (a.title || '').toLowerCase(),
    device_name:     (a.device_name || '').toLowerCase(),
    acknowledged_by: a.acknowledged_by || '',
  }));
  document.getElementById('alerts-tbody').innerHTML =
    rows.map(a => _alertRowHtml(a, '')).join('');
}
function _renderAlertsGrouped(rows) {
  // Bucket by host, then order groups worst-severity → most-open → name.
  const groups = new Map();
  for (const a of rows) {
    const k = _alertHostKey(a);
    if (!groups.has(k)) groups.set(k, []);
    groups.get(k).push(a);
  }
  const arr = [...groups.entries()].map(([key, items]) => {
    const worst = Math.min(99, ...items.map(a => _ALERT_SEV_RANK[a.severity] ?? 99));
    const openCount = items.filter(a => !a.resolved_at).length;
    return {
      key, items,
      name: items[0].device_name || items[0].device_id || 'Fleet / no host',
      worst, openCount, hasRoot: items.some(a => a._root_cause),
    };
  });
  arr.sort((x, y) => x.worst - y.worst || y.openCount - x.openCount
    || x.name.localeCompare(y.name));
  const order = a => a._root_cause ? 0 : a._symptom_of ? 1 : 2;
  let html = '';
  for (const g of arr) {
    if (g.items.length === 1) { html += _alertRowHtml(g.items[0], ''); continue; }
    const items = g.items.slice().sort((a, b) =>
      order(a) - order(b)
      || (_ALERT_SEV_RANK[a.severity] ?? 9) - (_ALERT_SEV_RANK[b.severity] ?? 9)
      || (b.ts || 0) - (a.ts || 0));
    const collapsed = _alertGroupsCollapsed.has(g.key);
    const worstName = _ALERT_SEV_NAME[g.worst] || 'low';
    const caret = collapsed ? '▸' : '▾';
    const rootNote = g.hasRoot ? ' · host offline — symptoms folded' : '';
    let groupActions = '';
    if (g.openCount) {
      groupActions =
        `<button class="btn-icon btn-xs" data-action="ackGroup" data-arg="${escAttr(g.key)}">Ack all</button> ` +
        `<button class="btn-icon btn-xs c-success" data-action="resolveGroup" data-arg="${escAttr(g.key)}">Resolve all</button>`;
    }
    html += `<tr class="alerts-group-row">
      <td colspan="6"><button class="alerts-group-toggle" data-action="toggleAlertGroup" data-arg="${escAttr(g.key)}">${caret} <strong>${_escapeHtml(g.name)}</strong></button> <span class="sev-pill sev-${worstName}">${worstName}</span> <span class="hint">${g.openCount} open / ${g.items.length} total${rootNote}</span></td>
      <td class="nowrap">${groupActions}</td></tr>`;
    if (!collapsed) {
      for (const a of items) {
        html += _alertRowHtml(a, a._root_cause ? 'root' : a._symptom_of ? 'symptom' : '');
      }
    }
  }
  document.getElementById('alerts-tbody').innerHTML = html;
}
function toggleAlertGroup(key) {
  if (_alertGroupsCollapsed.has(key)) _alertGroupsCollapsed.delete(key);
  else _alertGroupsCollapsed.add(key);
  renderAlerts();
}
async function ackGroup(key) {
  const ids = (_alertsCache || []).filter(a =>
    _alertHostKey(a) === key && !a.resolved_at && !a.acknowledged_at).map(a => a.id);
  if (!ids.length) { toast('Nothing to acknowledge on this host', 'info'); return; }
  const body = { ids };
  if (_alertsAckCommentEnabled) {
    const note = await uiPrompt({message: `Add a comment to ${ids.length} acknowledgement(s) (optional):`, value: ''});
    if (note === null) return;
    if (note.trim()) body.note = note.trim();
  }
  const r = await api('POST', '/alerts/bulk-ack', body);
  if (r && r.ok) { toast(`Acknowledged ${r.acked}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}
async function resolveGroup(key) {
  const ids = (_alertsCache || []).filter(a =>
    _alertHostKey(a) === key && !a.resolved_at).map(a => a.id);
  if (!ids.length) return;
  if (!await uiConfirm(`Resolve ${ids.length} alert(s) on this host?`)) return;
  const r = await api('POST', '/alerts/bulk-resolve', { ids });
  if (r && r.ok) { toast(`Resolved ${r.resolved}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

function _formatTs(ts) {
  if (!ts) return '';
  const d = new Date(ts * 1000);
  return d.toLocaleString();
}

function _escapeHtml(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

async function ackAlert(id) {
  const body = {};
  // v4.1.0 (#56): optional comment on ack (can be turned off in Settings).
  if (_alertsAckCommentEnabled) {
    const note = await uiPrompt({message: 'Add a comment to this acknowledgement (optional):', value: ''});
    if (note === null) return;   // cancelled
    if (note.trim()) body.note = note.trim();
  }
  const r = await api('POST', `/alerts/${encodeURIComponent(id)}/ack`, body);
  if (r && r.ok) { toast('Alert acknowledged', 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// v4.1.0 (#53): acknowledge every selected open alert in one call.
async function bulkAckAlerts() {
  const ids = Array.from(document.querySelectorAll('.alerts-row-cb:checked'))
    .map(cb => cb.dataset.id);
  if (!ids.length) return;
  const body = { ids };
  if (_alertsAckCommentEnabled) {
    const note = await uiPrompt({message: `Add a comment to ${ids.length} acknowledgement(s) (optional):`, value: ''});
    if (note === null) return;   // cancelled
    if (note.trim()) body.note = note.trim();
  }
  const r = await api('POST', '/alerts/bulk-ack', body);
  if (r && r.ok) { toast(`Acknowledged ${r.acked}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function unackAlert(id) {
  const r = await api('POST', `/alerts/${encodeURIComponent(id)}/unack`, {});
  if (r && r.ok) { loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function resolveAlert(id) {
  if (!await uiConfirm('Mark this alert resolved?')) return;
  const r = await api('POST', `/alerts/${encodeURIComponent(id)}/resolve`, {});
  if (r && r.ok) { toast('Alert resolved', 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}


function toggleAllAlerts(checked) {
  document.querySelectorAll('.alerts-row-cb').forEach(cb => { cb.checked = checked; });
  _updateBulkResolveBtn();
}

function updateBulkResolveBtn() { _updateBulkResolveBtn(); }
function _updateBulkResolveBtn() {
  const cbs = document.querySelectorAll('.alerts-row-cb:checked');
  const btn = document.getElementById('alerts-bulk-resolve-btn');
  if (btn) btn.classList.toggle('d-none', cbs.length === 0);
  // v4.1.0 (#53): "Ack selected" shows only when a selected row is still
  // un-acked (acking an already-acked alert is a no-op).
  const ackBtn = document.getElementById('alerts-bulk-ack-btn');
  if (ackBtn) {
    const anyUnacked = Array.from(cbs).some(cb => {
      const a = (_alertsCache || []).find(x => x.id === cb.dataset.id);
      return a && !a.acknowledged_at;
    });
    ackBtn.classList.toggle('d-none', !anyUnacked);
  }
}

async function bulkResolveAlerts() {
  const ids = Array.from(document.querySelectorAll('.alerts-row-cb:checked'))
    .map(cb => cb.dataset.id);
  if (!ids.length) return;
  if (!await uiConfirm(`Resolve ${ids.length} alert(s)?`)) return;
  const r = await api('POST', '/alerts/bulk-resolve', { ids });
  if (r && r.ok) { toast(`Resolved ${r.resolved}`, 'success'); loadAlerts(); refreshAlertsBadge(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// v3.2.0 follow-up: bulk-purge resolved or all alerts
async function clearResolvedAlerts() {
  if (!await uiConfirm('Remove every alert in "resolved" state? Open and acknowledged rows stay.')) return;
  const r = await api('DELETE', '/alerts?scope=resolved');
  if (r && r.ok) {
    toast(`Cleared ${r.removed} resolved alert(s)`, 'success');
    loadAlerts(); refreshAlertsBadge();
  } else toast((r && r.error) || 'Failed', 'error');
}

async function clearAllAlerts() {
  if (!await uiConfirm('Remove EVERY alert — including open and acknowledged ones?\n\nThis cannot be undone. Use "Clear resolved" if you only want to purge resolved.')) return;
  const r = await api('DELETE', '/alerts?scope=all');
  if (r && r.ok) {
    toast(`Cleared ${r.removed} alert(s)`, 'success');
    loadAlerts(); refreshAlertsBadge();
  } else toast((r && r.error) || 'Failed', 'error');
}

function _paintAlertsBadge(n) {
  const badge = document.getElementById('alerts-badge');
  if (!badge) return;
  // v3.2.0: always visible — green at 0 (the "all clear" signal), red
  // when anything is open. The icon-only sidebar is misread as "nothing
  // to look at" without a present-tense indicator.
  badge.classList.remove('d-none');
  badge.textContent = n > 99 ? '99+' : String(n);
  badge.classList.toggle('nav-badge-ok', n === 0);
  badge.classList.toggle('nav-badge-alert', n > 0);
  badge.title = n === 0 ? 'No open alerts' :
                n === 1 ? '1 open alert' :
                `${n} open alerts`;
}

async function refreshAlertsBadge() {
  try {
    const s = await api('GET', '/alerts/summary');
    if (s) _paintAlertsBadge(s.open || 0);
  } catch (_) { /* non-fatal */ }
}

// ─── v3.2.0 (A1): MCP Confirmations queue ──────────────────────────────────

async function loadConfirmations() {
  try {
    const data = await api('GET', '/confirmations');
    _renderConfirmations((data && data.confirmations) || []);
    refreshConfirmationsBadge();
  } catch (e) {
    toast('Failed to load confirmations', 'error');
  }
}

function _renderConfirmations(arr) {
  const tbody = document.getElementById('confirmations-tbody');
  if (!tbody) return;
  // v3.2.1: wire sort + apply current sort order
  tableCtl.wireSortOnly('confirmations-thead', 'confirmations', () => loadConfirmations());
  const _statusRank = {pending: 0, approved: 1, rejected: 2, failed: 3, expired: 4};
  arr = tableCtl.sortRows('confirmations', arr, (c) => ({
    status:        _statusRank[c.status] ?? 99,
    requested_at:  c.requested_at || 0,
    action:        c.action || '',
    device_name:   c.device_name || c.device_id || '',
    ai_host:       c.ai_host || '',
    ai_prompt:     c.ai_prompt || '',
  }));
  if (!arr.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty-state">No pending or recent MCP confirmations.</td></tr>';
    return;
  }
  tbody.innerHTML = arr.map(c => {
    const status = c.status || 'pending';
    const statusPill =
      status === 'pending'  ? '<span class="sev-pill sev-medium">pending</span>' :
      status === 'approved' ? '<span class="sev-pill sev-success">approved</span>' :
      status === 'rejected' ? '<span class="sev-pill sev-low">rejected</span>' :
      status === 'expired'  ? '<span class="sev-pill sev-low">expired</span>' :
      status === 'failed'   ? '<span class="sev-pill sev-critical">failed</span>' :
      `<span class="sev-pill sev-low">${_escapeHtml(status)}</span>`;
    const actionLabel = c.action === 'run_saved_script' && c.script_name
      ? `${_escapeHtml(c.action)} <span class="hint">(${_escapeHtml(c.script_name)})</span>`
      : _escapeHtml(c.action || '');
    let buttons = '';
    if (status === 'pending') {
      buttons = `<button class="btn-icon btn-xs c-success" data-action="approveConfirmation" data-arg="${c.id}">Approve</button> ` +
                `<button class="btn-icon btn-xs c-danger-outline" data-action="rejectConfirmation" data-arg="${c.id}">Reject</button>`;
    }
    return `<tr>
      <td>${statusPill}</td>
      <td class="hint nowrap">${_formatTs(c.requested_at)}</td>
      <td>${actionLabel}</td>
      <td>${_escapeHtml(c.device_name || c.device_id || '')}</td>
      <td><code>${_escapeHtml(c.ai_host || '—')}</code></td>
      <td class="hint">${_escapeHtml(c.ai_prompt || '')}</td>
      <td class="nowrap">${buttons}</td>
    </tr>`;
  }).join('');
}

async function approveConfirmation(id) {
  if (!await uiConfirm('Approve this MCP write action? The server will execute it now.')) return;
  const r = await api('POST', `/confirmations/${encodeURIComponent(id)}/approve`, {});
  if (r && r.ok) { toast('Approved — action queued', 'success'); loadConfirmations(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function rejectConfirmation(id) {
  const note = await uiPrompt({title: 'Reject write action',
    message: 'Reject this MCP write action. Optional note:',
    placeholder: 'reason (optional)', confirmText: 'Reject', danger: true});
  if (note === null) return;     // cancelled — leave the action pending
  const r = await api('POST', `/confirmations/${encodeURIComponent(id)}/reject`, { note });
  if (r && r.ok) { toast('Rejected', 'success'); loadConfirmations(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function clearConfirmations() {
  if (!await uiConfirm('Clear all resolved (approved / rejected / expired) entries? Pending entries are kept.')) return;
  const r = await api('DELETE', '/confirmations', {});
  if (r && r.ok) { toast(`Cleared ${r.removed} entr${r.removed === 1 ? 'y' : 'ies'}`, 'success'); loadConfirmations(); }
  else toast((r && r.error) || 'Failed', 'error');
}

function _paintConfirmationsBadge(pending) {
  const badge = document.getElementById('confirmations-badge');
  if (!badge) return;
  if (pending == null) {
    // Viewers can't see confirmations — hide rather than show a confusing badge
    badge.classList.add('d-none');
    return;
  }
  // v3.2.0: same green-at-zero pattern as the alerts badge — present
  // state is always visible; colour shows whether action is needed.
  badge.classList.remove('d-none');
  badge.textContent = pending > 99 ? '99+' : String(pending);
  badge.classList.toggle('nav-badge-ok', pending === 0);
  badge.classList.toggle('nav-badge-alert', pending > 0);
  badge.title = pending === 0 ? 'No pending MCP confirmations' :
                pending === 1 ? '1 pending MCP confirmation' :
                `${pending} pending MCP confirmations`;
}

async function refreshConfirmationsBadge() {
  try {
    const data = await api('GET', '/confirmations');
    const arr = (data && data.confirmations) || [];
    _paintConfirmationsBadge(arr.filter(c => c.status === 'pending').length);
  } catch (_) {
    _paintConfirmationsBadge(null);
  }
}

// ─── v3.2.0 (B2): inbound webhooks (Settings → Integrations) ────────────────

let _lastCreatedInboundWebhookUrl = '';

async function loadIntegrationsTab() {
  await loadInboundWebhooks();
  // Render OIDC redirect-URI hint based on current origin
  const hintEl = document.getElementById('oidc-redirect-hint');
  if (hintEl) {
    hintEl.innerHTML = `<strong>Redirect URI</strong> to register with your IdP: <code>${location.origin}/api/auth/oidc/callback</code>`;
  }
  // Populate the existing OIDC fields from config
  try {
    const cfg = await api('GET', '/config');
    if (cfg) {
      const setIf = (id, key, isCheck) => {
        const el = document.getElementById(id);
        if (!el) return;
        if (isCheck) el.checked = !!cfg[key];
        else el.value = cfg[key] || '';
      };
      setIf('oidc-enabled', 'oidc_enabled', true);
      setIf('oidc-issuer', 'oidc_issuer');
      setIf('oidc-client-id', 'oidc_client_id');
      setIf('oidc-scopes', 'oidc_scopes');
      setIf('oidc-admin-group', 'oidc_admin_group');
      // Don't populate the secret — it's stored hashed-server-side or simply
      // never re-read by the UI. Leave blank means "keep current".
      // v4.2.0 (B1): SAML config (the cert is the IdP's public signing cert —
      // not a secret — so it's safe to round-trip into the textarea).
      setIf('saml-enabled', 'saml_enabled', true);
      setIf('saml-idp-entity-id', 'saml_idp_entity_id');
      setIf('saml-idp-sso-url', 'saml_idp_sso_url');
      setIf('saml-idp-cert', 'saml_idp_x509_cert');
      setIf('saml-attr-username', 'saml_attr_username');
      setIf('saml-attr-groups', 'saml_attr_groups');
      setIf('saml-admin-group', 'saml_admin_group');
      setIf('saml-allow-unsolicited', 'saml_allow_unsolicited', true);
      // v5.4.1 (D5): group→role matrix textarea — one "group=role" per line.
      const ssoMap = document.getElementById('sso-group-roles');
      if (ssoMap) {
        const m = cfg.sso_group_roles || {};
        ssoMap.value = Object.keys(m).map(g => `${g}=${m[g]}`).join('\n');
      }
    }
  } catch (_) { /* non-fatal */ }
  const samlHint = document.getElementById('saml-metadata-hint');
  if (samlHint) {
    samlHint.innerHTML = `<strong>SP metadata / ACS URL</strong> to register with your IdP: <code>${location.origin}/api/auth/saml/acs</code> — full metadata at <code>${location.origin}/api/saml/metadata</code>`;
  }
  try { await loadIntegrations(); } catch (_) { /* non-fatal */ }
}

// ── v4.7.0: homelab software integrations ────────────────────────────────────
let _integrations = [];
let _integrationCatalog = [];
// Map a connector result status to the canonical themed .status-pill variant
// (adapts to every theme incl. Industrial light/dark; carries a status dot).
const _INTEG_PILL = { ok: 'ok', warning: 'warn', critical: 'critical', unknown: 'neutral' };

async function loadIntegrations() {
  const data = await api('GET', '/integrations');
  _integrations = (data && data.integrations) || [];
  _integrationCatalog = (data && data.catalog) || [];
  _showHomelab = !data || data.show_homelab !== false;
  const cb = document.getElementById('show-homelab');
  if (cb) cb.checked = _showHomelab;
  const body = document.getElementById('homelab-integrations-body');
  if (body) body.style.display = _showHomelab ? '' : 'none';
  const iv = document.getElementById('integrations-interval');
  if (iv && data && data.interval) iv.value = data.interval;
  const sel = document.getElementById('integration-add-type');
  if (sel) {
    sel.innerHTML = _integrationCatalog.map(c =>
      `<option value="${escAttr(c.type)}">${escHtml(c.label)} (${escHtml(c.category)})</option>`).join('');
  }
  renderIntegrations();
}

function _integrationFields(type) {
  const c = _integrationCatalog.find(x => x.type === type);
  return (c && c.fields) || [];
}

function renderIntegrations() {
  const wrap = document.getElementById('integrations-list');
  if (!wrap) return;
  if (!_integrations.length) {
    wrap.innerHTML = '<div class="empty-state">No integrations yet — pick a type below and Add.</div>';
    return;
  }
  wrap.innerHTML = _integrations.map((it, idx) => {
    const cat = _integrationCatalog.find(x => x.type === it.type);
    const label = cat ? cat.label : it.type;
    const fields = _integrationFields(it.type).map(f => {
      const set = it[f.key + '_set'];
      const val = f.kind === 'password' ? '' : escAttr(it[f.key] || '');
      const ph = f.kind === 'password' && set ? '•••••• (set — blank keeps it)' : escAttr(f.placeholder || '');
      return `<div class="form-group">
          <label class="form-label">${escHtml(f.label)}${f.optional ? ' <span class="hint">(optional)</span>' : ''}</label>
          <input type="${f.kind === 'password' ? 'password' : 'text'}" class="form-input" autocomplete="off"
                 data-ifield="${escAttr(f.key)}" value="${val}" placeholder="${ph}">
        </div>`;
    }).join('');
    const st = it.last_status || 'unknown';
    const badge = `<span class="status-pill ${_INTEG_PILL[st] || 'neutral'}">${escHtml(st)}</span>`;
    const detail = it.last_detail ? `<span class="hint ml-8">${escHtml(it.last_detail)}</span>` : '';
    const note = cat && cat.notes ? `<p class="hint">${escHtml(cat.notes)}</p>` : '';
    return `<div class="integration-card" data-idx="${idx}">
      <div class="integration-card-head">
        <label class="ff-bold"><input type="checkbox" data-ifield="enabled" ${it.enabled ? 'checked' : ''}> ${escHtml(label)}</label>
        ${badge}${detail}
        <span class="spacer"></span>
        <button class="btn-icon" data-action="testIntegration" data-arg="${idx}" title="Test connection">Test</button>
        <button class="btn-icon c-danger-outline" data-action="removeIntegration" data-arg="${idx}" title="Remove">${_icon('trash',14)}</button>
      </div>
      ${note}
      <div class="settings-row">
        <div class="form-group"><label class="form-label">Name</label>
          <input type="text" class="form-input" data-ifield="label" value="${escAttr(it.label || '')}"></div>
        <div class="form-group"><label class="form-label">URL</label>
          <input type="url" class="form-input mw-260" data-ifield="url" value="${escAttr(it.url || '')}" placeholder="https://service.lan:port"></div>
      </div>
      <div class="settings-row">${fields}</div>
      <div class="settings-row">
        <label class="form-label"><input type="checkbox" data-ifield="verify_tls" ${it.verify_tls !== false ? 'checked' : ''}> Verify TLS (uncheck for self-signed)</label>
        <span id="integration-test-${idx}" class="hint ml-8"></span>
      </div>
    </div>`;
  }).join('');
}

// Sync the DOM inputs back into the _integrations model before save/test.
function _readIntegrationCards() {
  document.querySelectorAll('#integrations-list .integration-card').forEach(card => {
    const idx = parseInt(card.dataset.idx, 10);
    const it = _integrations[idx];
    if (!it) return;
    card.querySelectorAll('[data-ifield]').forEach(el => {
      const k = el.dataset.ifield;
      if (el.type === 'checkbox') it[k] = el.checked;
      else if (el.value !== '' || el.type !== 'password') {
        // a blank password keeps the stored secret (don't overwrite with '')
        if (el.type === 'password' && el.value === '') return;
        it[k] = el.value;
      }
    });
  });
}

function addIntegration() {
  const sel = document.getElementById('integration-add-type');
  const type = sel ? sel.value : (_integrationCatalog[0] && _integrationCatalog[0].type);
  if (!type) return;
  const cat = _integrationCatalog.find(x => x.type === type);
  _readIntegrationCards();
  _integrations.push({ type, label: cat ? cat.label : type, url: '', enabled: true, verify_tls: true });
  renderIntegrations();
}

function removeIntegration(idx) {
  _readIntegrationCards();
  _integrations.splice(idx, 1);
  renderIntegrations();
}

// Live-toggle the homelab section + the dashboard widget (persisted on Save).
function toggleShowHomelab() {
  const cb = document.getElementById('show-homelab');
  _showHomelab = !cb || cb.checked;
  const body = document.getElementById('homelab-integrations-body');
  if (body) body.style.display = _showHomelab ? '' : 'none';
}

async function saveIntegrations() {
  _readIntegrationCards();
  const iv = document.getElementById('integrations-interval');
  const cb = document.getElementById('show-homelab');
  const status = document.getElementById('integrations-save-status');
  if (status) status.textContent = 'Saving…';
  try {
    await api('POST', '/integrations', {
      integrations: _integrations,
      interval: iv ? parseInt(iv.value, 10) || 300 : 300,
      show_homelab: cb ? cb.checked : true,
    });
    if (status) status.textContent = 'Saved ✓';
    toast('Integrations saved', 'success');
    await loadIntegrations();
  } catch (e) {
    if (status) status.textContent = '';
    toast((e && e.message) || 'Save failed', 'error');
  }
}

async function testIntegration(idx) {
  _readIntegrationCards();
  const out = document.getElementById('integration-test-' + idx);
  if (out) { out.textContent = 'Testing…'; out.className = 'hint ml-8'; }
  try {
    const r = await api('POST', '/integrations/test', _integrations[idx]);
    if (out) {
      out.textContent = (r.ok ? '✓ ' : '✗ ') + (r.detail || r.status || '') + (r.version ? ' · v' + r.version : '');
      out.className = 'hint ml-8 ' + (r.ok ? 'c-green' : 'c-amber');
    }
  } catch (e) {
    if (out) { out.textContent = '✗ ' + ((e && e.message) || 'failed'); out.className = 'hint ml-8 c-red'; }
  }
}

// ── v4.7.0: integration rows — ONE compact line per service, shared by the
// dashboard widget and the Integrations page. Name is prominent; the stat chips
// the connector pulls from the service API sit inline; version + age on the
// right. CSP-safe (escHtml/escAttr).
const _INTEG_TILE_PILL = { ok: 'ok', warning: 'warn', critical: 'critical', unknown: 'neutral' };
function _integrationTiles(items, opts) {
  opts = opts || {};
  if (!items || !items.length) return '<div class="empty-state">No integrations configured yet.</div>';
  return items.map(it => {
    const v = _INTEG_TILE_PILL[it.status] || 'neutral';
    const chips = (it.stats || []).map(s =>
      `<span class="integ-stat"><b>${escHtml(String(s.value))}</b> ${escHtml(s.label)}</span>`)
      .join('<span class="integ-sep">·</span>');
    const mid = chips || (it.detail ? `<span class="integ-row-detail">${escHtml(it.detail)}</span>` : '');
    const foot = [];
    if (it.version) foot.push('v' + escHtml(String(it.version)));
    if (it.checked && typeof timeAgo === 'function') foot.push(escHtml(timeAgo(it.checked)));
    const click = opts.link ? ' data-action="goIntegrationsPage" role="button" tabindex="0"' : '';
    return `<div class="integ-row${opts.link ? ' integ-row-link' : ''}"${click} title="${escAttr((it.label || '') + ' (' + (it.type || '') + ') — ' + (it.detail || ''))}">
      <span class="status-pill ${v} integ-row-pill">${escHtml(it.status || 'unknown')}</span>
      <span class="integ-row-name">${escHtml(it.label || it.type || '?')}</span>
      <span class="integ-row-stats">${mid}</span>
      <span class="integ-row-meta">${foot.join(' · ')}</span>
    </div>`;
  }).join('');
}

function goIntegrationsPage() {
  showPage('integrations', document.querySelector('.nav-btn[data-page="integrations"]'));
}

function openIntegrationsSettings() {
  showPage('settings', document.querySelector('.nav-btn[data-page="settings"]'));
  setTimeout(() => { try { switchSettingsTab('integrations'); loadIntegrationsTab(); } catch (_) {} }, 50);
}

// The dedicated Integrations tiles page (Monitoring → Integrations).
async function loadIntegrationsPage() {
  const wrap = document.getElementById('integrations-page-tiles');
  const sum = document.getElementById('integrations-page-summary');
  if (!wrap) return;
  try {
    const data = await api('GET', '/integrations');
    if (data && data.show_homelab === false) {
      wrap.innerHTML = '<div class="empty-state">Homelab software integrations are hidden on this instance (Settings → Integrations → Show Homelab software).</div>';
      if (sum) sum.textContent = '';
      return;
    }
    const insts = (data && data.integrations) || [];
    // Build tile items from the per-instance last_* fields.
    const items = insts.map(i => ({
      id: i.id, label: i.label, type: i.type,
      status: i.enabled ? (i.last_status || 'unknown') : 'unknown',
      detail: i.enabled ? i.last_detail : 'disabled',
      version: i.last_version, checked: i.last_checked, stats: i.last_stats || [],
    }));
    const order = { critical: 0, warning: 1, unknown: 2, ok: 3 };
    items.sort((a, b) => (order[a.status] ?? 9) - (order[b.status] ?? 9) || String(a.label || '').localeCompare(String(b.label || '')));
    wrap.innerHTML = _integrationTiles(items);
    if (sum) {
      const c = { critical: 0, warning: 0, ok: 0 };
      items.forEach(i => { if (i.status in c) c[i.status]++; });
      sum.innerHTML = `${items.length} integration${items.length === 1 ? '' : 's'} · <span class="${c.critical > 0 ? 'c-red fw-600' : ''}">${c.critical}</span> critical, <span class="${c.warning > 0 ? 'c-amber' : ''}">${c.warning}</span> warning, ${c.ok} ok`;
    }
  } catch (e) {
    wrap.innerHTML = '<div class="empty-state">Failed to load integrations.</div>';
  }
}

// ── v4.7.0: fleet GPU page (Monitoring → GPUs) — NVIDIA + AMD, rich cards ─────
// v4.7.0: temperature + utilisation trend sparklines (last ~4h of samples).
// Renders nothing until there are ≥2 points, so a fresh host shows no empty box.

async function loadInboundWebhooks() {
  try {
    const data = await api('GET', '/inbound-webhooks');
    _renderInboundWebhooks((data && data.tokens) || []);
  } catch (e) {
    toast('Failed to load inbound webhooks', 'error');
  }
}

function _renderInboundWebhooks(tokens) {
  const tbody = document.getElementById('inbound-webhooks-tbody');
  if (!tbody) return;
  // v3.2.1: wire sort
  tableCtl.wireSortOnly('inbound-webhooks-thead', 'inbound_webhooks', () => loadInboundWebhooks());
  tokens = tableCtl.sortRows('inbound_webhooks', tokens, (t) => ({
    label:      t.label || '',
    kind:       t.kind || 'alert',
    scope:      t.scope_device_id || t.scope_tag || 'any',
    hit_count:  t.hit_count || 0,
    last_seen:  t.last_seen || 0,
    enabled:    t.enabled ? 1 : 0,
  }));
  if (!tokens.length) {
    tbody.innerHTML = '<tr><td colspan="8" class="empty-state">No inbound tokens yet.</td></tr>';
    return;
  }
  tbody.innerHTML = tokens.map(t => {
    const kind = t.kind || 'alert';
    const kindPill = kind === 'syslog'
      ? '<span class="sev-pill sev-medium">syslog</span>'
      : kind === 'snmp_trap'
      ? '<span class="sev-pill sev-medium">snmp trap</span>'
      : '<span class="sev-pill sev-low">alert</span>';
    const scope = t.scope_device_id ? `device ${_escapeHtml(t.scope_device_id)}` :
                  t.scope_tag ? `tag ${_escapeHtml(t.scope_tag)}` : 'any';
    const lastSeen = t.last_seen ? _formatTs(t.last_seen) : '<span class="c-muted">—</span>';
    const status = t.enabled ?
      '<span class="sev-pill sev-success">enabled</span>' :
      '<span class="sev-pill sev-low">disabled</span>';
    const toggle = t.enabled ?
      `<button class="btn-icon btn-xs" data-action="toggleInboundWebhook" data-arg="${t.id}" data-arg2="0">Disable</button>` :
      `<button class="btn-icon btn-xs" data-action="toggleInboundWebhook" data-arg="${t.id}" data-arg2="1">Enable</button>`;
    return `<tr>
      <td><strong>${_escapeHtml(t.label || '')}</strong></td>
      <td>${kindPill}</td>
      <td class="hint">${scope}</td>
      <td class="ff-mono fs-12">${_escapeHtml(t.token_preview || '')}</td>
      <td>${t.hit_count || 0}</td>
      <td class="hint nowrap">${lastSeen}</td>
      <td>${status}</td>
      <td class="nowrap">${toggle} <button class="btn-icon btn-xs" title="Edit" data-action-btn="_editInboundWebhookBtn" data-store-key="${_storeEvtData(t)}">${_icon('edit',14)}</button> <button class="btn-icon btn-xs c-danger-outline" data-action="revokeInboundWebhook" data-arg="${t.id}" data-arg2="${_escapeHtml(t.label||'')}">Revoke</button></td>
    </tr>`;
  }).join('');
}

// v3.3.0: edit an existing inbound token's label / scope / enabled.
// The token secret itself is immutable (rotate via revoke + create).
async function _editInboundWebhookBtn(btn) {
  const t = _evtData.get(btn.dataset.storeKey);
  if (!t) return;
  const curLabel  = t.label || '';
  const curScopeD = t.scope_device_id || '';
  const curScopeT = t.scope_tag || '';
  const newLabel = await uiPrompt({title: 'Edit inbound webhook',
    message: `Label for "${curLabel}" (blank keeps current):`, value: curLabel});
  if (newLabel === null) return;  // operator cancelled
  const newScopeD = await uiPrompt({title: 'Restrict to device',
    message: `Restrict to device_id? (current: ${curScopeD || '(any)'}). Blank = any device.`,
    value: curScopeD});
  if (newScopeD === null) return;
  const newScopeT = await uiPrompt({title: 'Restrict to tag',
    message: `Restrict to tag? (current: ${curScopeT || '(any)'}). Blank = any tag.`,
    value: curScopeT});
  if (newScopeT === null) return;
  const body = {
    label:           newLabel.trim(),
    scope_device_id: newScopeD.trim(),
    scope_tag:       newScopeT.trim(),
  };
  const r = await api('PATCH', '/inbound-webhooks/' + t.id, body);
  if (r?.ok) { toast('Inbound webhook updated', 'success'); loadInboundWebhooks(); }
  else { toast(r?.error || 'Failed', 'error'); }
}

function openInboundWebhookCreate() {
  document.getElementById('inbound-wh-label').value = '';
  document.getElementById('inbound-wh-kind').value = 'alert';
  // Populate the device dropdown
  const sel = document.getElementById('inbound-wh-device');
  if (sel) {
    const opts = ['<option value="">(any — match by body.device)</option>'];
    (window._devicesCache || devices || []).forEach(d => {
      const id = d.id || d.device_id || '';
      const nm = d.name || id;
      opts.push(`<option value="${_escapeHtml(id)}">${_escapeHtml(nm)}</option>`);
    });
    sel.innerHTML = opts.join('');
  }
  updateInboundWebhookKindHint();
  openModal('inbound-webhook-create-modal');
}

function updateInboundWebhookKindHint() {
  const kind = document.getElementById('inbound-wh-kind').value;
  const hint = document.getElementById('inbound-wh-kind-hint');
  const req = document.getElementById('inbound-wh-device-required');
  const devOpt = document.querySelector('#inbound-wh-device option[value=""]');
  const pinned = (kind === 'syslog' || kind === 'snmp_trap');
  if (kind === 'snmp_trap') {
    if (hint) hint.textContent = 'SNMP trap tokens receive JSON {traps:[{oid,value,agent}]} forwarded by an snmptrapd handler; traps attach to the pinned device and raise snmp_trap_received.';
  } else if (kind === 'syslog') {
    if (hint) hint.textContent = 'Syslog tokens receive RFC 3164/5424 lines (JSON {lines:[...]} or plain text) and append to the device\'s log_watch under unit="syslog".';
  } else {
    if (hint) hint.textContent = 'Alert tokens receive JSON {severity,title,...} and land in the Alerts inbox.';
  }
  if (req) req.classList.toggle('d-none', !pinned);
  if (devOpt) devOpt.textContent = pinned ? '— select device —' : '(any — match by body.device)';
}

async function createInboundWebhook() {
  const label = document.getElementById('inbound-wh-label').value.trim();
  if (!label) { toast('Label required', 'error'); return; }
  const kind = document.getElementById('inbound-wh-kind').value;
  const scope_device_id = document.getElementById('inbound-wh-device').value || null;
  if ((kind === 'syslog' || kind === 'snmp_trap') && !scope_device_id) {
    toast(`${kind === 'snmp_trap' ? 'SNMP trap' : 'Syslog'} tokens must be pinned to a device`, 'error');
    return;
  }
  const r = await api('POST', '/inbound-webhooks', { label, scope_device_id, kind });
  if (r && r.ok && r.token) {
    closeModal('inbound-webhook-create-modal');
    const path = kind === 'syslog' ? '/api/syslog/in/' : kind === 'snmp_trap' ? '/api/snmp/trap/' : '/api/webhook/in/';
    _lastCreatedInboundWebhookUrl = `${location.origin}${path}${r.token}`;
    document.getElementById('inbound-wh-url').textContent = _lastCreatedInboundWebhookUrl;
    document.getElementById('inbound-wh-show-title').textContent =
      kind === 'syslog' ? 'Syslog ingestion token created'
      : kind === 'snmp_trap' ? 'SNMP trap token created' : 'Alert webhook token created';
    const ex = document.getElementById('inbound-wh-example');
    if (kind === 'snmp_trap') {
      ex.textContent =
        '# Forward decoded traps as JSON (e.g. from an snmptrapd handler script)\n' +
        `curl -X POST '${_lastCreatedInboundWebhookUrl}' \\\n` +
        '  -H \'Content-Type: application/json\' \\\n' +
        '  -d \'{"traps":[{"oid":"1.3.6.1.6.3.1.1.5.3","value":"linkDown","agent":"192.0.2.10"}]}\'';
    } else if (kind === 'syslog') {
      ex.textContent =
        '# JSON form\n' +
        `curl -X POST '${_lastCreatedInboundWebhookUrl}' \\\n` +
        '  -H \'Content-Type: application/json\' \\\n' +
        '  -d \'{"lines":["<11>kernel: ERROR disk full","<14>sshd: Accepted root"]}\'\n\n' +
        '# Plain text — one syslog line per row (rsyslog omhttp default)\n' +
        `curl -X POST '${_lastCreatedInboundWebhookUrl}' \\\n` +
        '  -H \'Content-Type: text/plain\' \\\n' +
        '  --data-binary $\'<14>foo bar\\n<11>err line\\n\'';
    } else {
      ex.textContent =
        `curl -X POST '${_lastCreatedInboundWebhookUrl}' \\\n` +
        '  -H \'Content-Type: application/json\' \\\n' +
        '  -d \'{"severity":"high","title":"CPU 95% on web01","device":"web01","source":"grafana"}\'';
    }
    openModal('inbound-webhook-show-modal');
    loadInboundWebhooks();
  } else {
    toast((r && r.error) || 'Failed', 'error');
  }
}

function copyInboundWebhookUrl() {
  if (!_lastCreatedInboundWebhookUrl) return;
  navigator.clipboard.writeText(_lastCreatedInboundWebhookUrl)
    .then(() => toast('Copied', 'success'))
    .catch(() => toast('Copy failed — select and copy manually', 'error'));
}

async function toggleInboundWebhook(id, enabledStr) {
  const enabled = enabledStr === '1';
  const r = await api('PATCH', `/inbound-webhooks/${encodeURIComponent(id)}`, { enabled });
  if (r && r.ok) { toast(`Token ${enabled ? 'enabled' : 'disabled'}`, 'success'); loadInboundWebhooks(); }
  else toast((r && r.error) || 'Failed', 'error');
}

async function revokeInboundWebhook(id, label) {
  if (!await uiConfirm(`Revoke inbound webhook "${label}"? The URL will stop working immediately.`)) return;
  const r = await api('DELETE', `/inbound-webhooks/${encodeURIComponent(id)}`);
  if (r && r.ok) { toast('Token revoked', 'success'); loadInboundWebhooks(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// v3.2.0: Test OIDC discovery — POST /api/auth/oidc/test
async function testOidcConfig() {
  const out = document.getElementById('oidc-test-result');
  if (out) out.innerHTML = '<span class="sev-pill sev-medium">testing</span> Fetching discovery document…';
  // Save first so we test what's actually on disk
  await saveOidcConfig();
  const r = await api('POST', '/auth/oidc/test', {});
  if (!out) return;
  if (!r || r.ok === false) {
    out.innerHTML = `<div class="sev-pill sev-critical">failed</div> ${_escapeHtml((r && r.error) || 'unknown error')}`;
    return;
  }
  const ep = r.endpoints || {};
  const warns = (r.warnings || []).map(w => `<li>${_escapeHtml(w)}</li>`).join('');
  out.innerHTML =
    `<div class="sev-pill sev-success">ok</div> Discovery succeeded.` +
    `<table class="fs-13 mt-8">` +
      `<tr><td class="c-muted-padded">Issuer</td><td><code>${_escapeHtml(r.issuer || '—')}</code></td></tr>` +
      `<tr><td class="c-muted-padded">Authorization</td><td><code>${_escapeHtml(ep.authorization || '—')}</code></td></tr>` +
      `<tr><td class="c-muted-padded">Token</td><td><code>${_escapeHtml(ep.token || '—')}</code></td></tr>` +
      `<tr><td class="c-muted-padded">Userinfo</td><td><code>${_escapeHtml(ep.userinfo || '—')}</code></td></tr>` +
      `<tr><td class="c-muted-padded">JWKS</td><td><code>${_escapeHtml(ep.jwks || '—')}</code></td></tr>` +
      `<tr><td class="c-muted-padded">Register redirect URI</td><td><code>${_escapeHtml(r.redirect_uri_needed || '—')}</code></td></tr>` +
    `</table>` +
    (warns ? `<div class="mt-8"><strong>Warnings:</strong><ul>${warns}</ul></div>` : '');
}

// v5.4.1 (D5): parse the SSO group→role matrix textarea ("group=role" per line)
// into a {group: role} object. Blank/comment lines and malformed rows are skipped.
function _parseGroupRoleMap(text) {
  const out = {};
  (text || '').split('\n').forEach(line => {
    const s = line.trim();
    if (!s || s.startsWith('#')) return;
    const i = s.indexOf('=');
    if (i <= 0) return;
    const g = s.slice(0, i).trim(), r = s.slice(i + 1).trim();
    if (g && r) out[g] = r;
  });
  return out;
}

// OIDC config save is wired here so the Integrations tab is self-contained
async function saveOidcConfig() {
  const payload = {
    oidc_enabled:      document.getElementById('oidc-enabled').checked,
    oidc_issuer:       document.getElementById('oidc-issuer').value.trim(),
    oidc_client_id:    document.getElementById('oidc-client-id').value.trim(),
    oidc_scopes:       document.getElementById('oidc-scopes').value.trim() || 'openid profile email groups',
    oidc_admin_group:  document.getElementById('oidc-admin-group').value.trim(),
  };
  const secret = document.getElementById('oidc-client-secret').value;
  if (secret) payload.oidc_client_secret = secret;
  // v5.4.1 (D5): parse the shared SSO group→role matrix ("group=role" per line).
  const ssoMap = document.getElementById('sso-group-roles');
  if (ssoMap) payload.sso_group_roles = _parseGroupRoleMap(ssoMap.value);
  const r = await api('POST', '/config', payload);
  if (r && r.ok !== false) {
    toast('OIDC config saved', 'success');
    document.getElementById('oidc-client-secret').value = '';
  } else {
    toast((r && r.error) || 'Failed', 'error');
  }
}

// v4.2.0 (B1): persist the SAML SP/IdP config.
async function saveSamlConfig() {
  const val = (id) => (document.getElementById(id).value || '').trim();
  const payload = {
    saml_enabled:           document.getElementById('saml-enabled').checked,
    saml_idp_entity_id:     val('saml-idp-entity-id'),
    saml_idp_sso_url:       val('saml-idp-sso-url'),
    saml_idp_x509_cert:     val('saml-idp-cert'),
    saml_attr_username:     val('saml-attr-username'),
    saml_attr_groups:       val('saml-attr-groups'),
    saml_admin_group:       val('saml-admin-group'),
    saml_allow_unsolicited: document.getElementById('saml-allow-unsolicited').checked,
  };
  // v5.4.1 (D5): persist the shared SSO group→role matrix from here too.
  const ssoMap = document.getElementById('sso-group-roles');
  if (ssoMap) payload.sso_group_roles = _parseGroupRoleMap(ssoMap.value);
  const r = await api('POST', '/config', payload);
  if (r && r.ok !== false) toast('SAML config saved', 'success');
  else toast((r && r.error) || 'Failed', 'error');
}

// v4.1.0: per-sidebar-group "needs attention" count badges.
async function refreshNavCounts() {
  try {
    const c = await api('GET', '/nav-counts');
    if (!c) return;
    // v4.2.0 sweep (perf): /nav-counts now bundles the alerts summary and the
    // pending-confirmations count, so the 60s poll is one request, not three.
    if (c.alerts) _paintAlertsBadge(c.alerts.open || 0);
    _paintConfirmationsBadge(
      typeof c.confirmations_pending === 'number' ? c.confirmations_pending : null);
    _paintVitals(c);
    // v5.0.0 (T6): Status Board nav badge = offline-host count (red when > 0).
    { const bb = document.getElementById('board-badge');
      if (bb) {
        const off = typeof c.fleet === 'number' ? c.fleet : 0;
        if (off > 0) { bb.classList.remove('d-none'); bb.classList.add('nav-badge-alert'); bb.textContent = off > 99 ? '99+' : String(off); bb.title = `${off} device(s) offline`; }
        else bb.classList.add('d-none');
      } }
    // v5.5.0: keep the sidebar Tickets badge live on the 60s poll (it used to
    // only update on a full dashboard load, so the count lingered after a
    // ticket was resolved until the user manually refreshed the page).
    if (typeof c.tickets_open === 'number') {
      const tb = document.getElementById('tickets-badge');
      if (tb) {
        const n = c.tickets_open;   // server already returns 0 when tickets are off
        tb.classList.toggle('d-none', n === 0);
        tb.textContent = n > 99 ? '99+' : String(n);
        tb.title = n === 1 ? '1 open ticket' : `${n} open tickets`;
      }
    }
    // v5.0.0 (#U4): live pending-command count on the Command Queue nav item.
    { const b = document.getElementById('cmdqueue-badge');
      if (b) {
        const n = typeof c.commands_pending === 'number' ? c.commands_pending : 0;
        if (n > 0) { b.classList.remove('d-none'); b.textContent = n > 99 ? '99+' : String(n); b.title = `${n} command(s) waiting for delivery`; }
        else b.classList.add('d-none');
      } }
    [['fleet', c.fleet], ['monitoring', c.monitoring], ['security', c.security]]
      .forEach(([group, n]) => {
        const toggle = document.querySelector(
          '.sidebar-group[data-group="' + group + '"] .sidebar-group-toggle');
        if (!toggle) return;
        let b = toggle.querySelector('.nav-group-badge');
        if (!n) { if (b) b.remove(); return; }
        if (!b) {
          b = document.createElement('span');
          b.className = 'nav-group-badge';
          const chev = toggle.querySelector('.chevron');
          toggle.insertBefore(b, chev || null);
        }
        b.textContent = n > 99 ? '99+' : String(n);
      });
    _navTintState = { security: c.security, fleet: c.fleet, monitoring: c.monitoring };
    _applyNavTints();
  } catch (_) { /* non-fatal */ }
}

// v4.1.0: point at WHERE a group's count lives — tint the responsible child
// nav item's icon (red = critical, amber = warning). querySelectorAll so the
// pinned *favorite clones* tint too, not just the in-group original. Re-run
// from _renderFavorites since clones are rebuilt on every star toggle.
var _navTintState = { security: 0, fleet: 0, monitoring: 0 };
function _applyNavTints() {
  const c = _navTintState || {};
  const tint = (sel, level) => {
    document.querySelectorAll(sel).forEach(el => {
      el.classList.toggle('nav-alert', level === 'alert');
      el.classList.toggle('nav-warn', level === 'warn');
    });
  };
  tint('.nav-btn[data-page="cve"]', c.security ? 'alert' : '');
  tint('.nav-btn[data-page="devices"]', c.fleet ? 'warn' : '');
  tint('.nav-btn[data-arg="section-targets"]', c.monitoring ? 'alert' : '');
}

// Refresh alert + confirmation badges on load and every 60s after
function _refreshTopBadges() {
  // v5.0.0: skip when unauthenticated — the badge poll is armed on
  // DOMContentLoaded (and re-fires every 60s), so without this guard it hits
  // /api/nav-counts on the login screen (a 401 in the console) and keeps
  // polling after logout. The counts are meaningless without a session anyway.
  if (!getToken()) return;
  // One bundled request — /nav-counts carries all three badge groups now.
  // refreshAlertsBadge()/refreshConfirmationsBadge() still exist for the
  // targeted refreshes after ack/approve actions.
  refreshNavCounts();
}
// v3.13.0: guard against a stacked interval if app.js is ever evaluated
// twice (HMR / duplicate <script> / bfcache) — keep a single poller.
function _armTopBadges() {
  _refreshTopBadges();
  if (!window._topBadgeTimer) window._topBadgeTimer = setInterval(_refreshTopBadges, 60000);
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', _armTopBadges);
} else {
  _armTopBadges();
}

// ── moved to static/js/app-calendar.js (v3.4.0 split) ─────────────────────────────
// ── moved to static/js/app-cmdb.js (v3.4.0 split) ─────────────────────────────
// ── v1.10.0: Update logs viewer ──────────────────────────────────────────────
// Independent of the CMDB system — this hangs off the device dropdown menu
// and shows the rolling buffer of package-upgrade output captured by the
// agent. Each run is collapsed by default; the most recent is auto-expanded.
let _updateLogsCurrent = null;     // {id, name}

async function openUpdateLogs(deviceId, name) {
  _updateLogsCurrent = {id: deviceId, name: name};
  document.getElementById('update-logs-title').textContent = `Update history — ${name}`;
  document.getElementById('update-logs-body').innerHTML =
    '<div class="empty-state">Loading…</div>';
  openModal('update-logs-modal');
  await reloadUpdateLogs();
}

async function reloadUpdateLogs() {
  if (!_updateLogsCurrent) return;
  const r = await api('GET', `/devices/${encodeURIComponent(_updateLogsCurrent.id)}/update-logs`);
  const body = document.getElementById('update-logs-body');
  if (!r) return;   // api() handled 401
  document.getElementById('update-logs-capacity').textContent = r.capacity || 10;
  const logs = (r.logs || []).slice().reverse();   // newest first
  if (!logs.length) {
    body.innerHTML = '<div class="empty-state">No update runs captured yet. Run "Upgrade packages" on this device — the output will land here on the next heartbeat (~60s).</div>';
    return;
  }
  // v2.8.1: deduplicate — suppress consecutive runs with identical output
  // (agents often send the same "0 upgraded" result every scan cycle)
  const dedupedLogs = [];
  let lastOutput = null;
  for (const entry of logs) {
    const out = (entry.output || '').trim();
    if (out !== lastOutput || entry.exit_code !== 0) {
      dedupedLogs.push(entry);
      lastOutput = out;
    }
  }
  body.innerHTML = dedupedLogs.map((entry, idx) => {
    const ok = entry.exit_code === 0;
    const status = ok
      ? '<span class="c-green">● success</span>'
      : `<span class="c-red">● failed (rc=${entry.exit_code})</span>`;
    const when = entry.finished_at
      ? new Date(entry.finished_at * 1000).toLocaleString()
      : '—';
    const duration = (entry.finished_at && entry.started_at)
      ? `${Math.max(0, entry.finished_at - entry.started_at)}s`
      : '?';
    const pm = entry.package_manager || 'unknown';
    const out = entry.output || '(no output captured)';
    const open = idx === 0 ? 'open' : '';
    return `<details ${open} class="isl-447">
      <summary class="isl-448">
        <span class="fw-500">${escHtml(when)}</span>
        <span class="hint">${escHtml(pm)} · ${escHtml(duration)}</span>
        <span class="isl-12">${status}</span>
      </summary>
      <pre class="isl-449">${escHtml(out)}</pre>
    </details>`;
  }).join('');
}


// ══════════════════════════════════════════════════════════════════════════════
// v1.11.0: Containers / Network map / TLS monitor / Agentless devices
// ══════════════════════════════════════════════════════════════════════════════

// ── moved to static/js/app-containers.js (v3.4.0 split) ─────────────────────────────
// ── moved to static/js/app-network.js (v3.4.0 split) ─────────────────────────────
// ─── v2.1.0: Script library + multi-select batch exec + docker-compose ────
//
// Three features that share UI plumbing:
//
//   * Scripts page (CRUD over /api/scripts).
//   * "Run script" button on the existing batch action bar — fans out to
//     /api/exec/batch and shows live job status via /api/exec/batch/<id>.
//   * Docker-compose dropdown on device cards: up/down/restart/pull/logs,
//     pointing only at projects the agent itself reported in its heartbeat.
//
// All three rendering paths use escHtml() for text and escAttr() for
// JS-in-onclick — see the comment on escAttr above. Mixing them up is
// the exact bug that triggered the 2.0.0 auto-refresh crash.

let _scriptsCache = [];

async function loadScripts() {
  const tbody = document.getElementById('scripts-tbody');
  if (!tbody) return;
  tbody.innerHTML = '<tr class="skeleton-row"><td colspan="6"><div class="skeleton skeleton-line long"></div></td></tr><tr class="skeleton-row"><td colspan="6"><div class="skeleton skeleton-line med"></div></td></tr><tr class="skeleton-row"><td colspan="6"><div class="skeleton skeleton-line long"></div></td></tr><tr class="skeleton-row"><td colspan="6"><div class="skeleton skeleton-line med"></div></td></tr><tr class="skeleton-row"><td colspan="6"><div class="skeleton skeleton-line long"></div></td></tr>';
  const data = await api('GET', '/scripts');
  _scriptsCache = Array.isArray(data) ? data : [];
  renderScriptsList();
}

function renderScriptsList() {
  const tbody = document.getElementById('scripts-tbody');
  if (!tbody) return;
  const term = (document.getElementById('scripts-filter')?.value || '').toLowerCase();
  let rows = _scriptsCache;
  if (term) {
    rows = rows.filter(s => (s.name||'').toLowerCase().includes(term) ||
                            (s.description||'').toLowerCase().includes(term));
  }
  // v3.2.1: sortable
  tableCtl.wireSortOnly('scripts-thead', 'scripts', renderScriptsList);
  rows = tableCtl.sortRows('scripts', rows, (s) => ({
    name:        (s.name || '').toLowerCase(),
    description: (s.description || '').toLowerCase(),
    size:        s.body_len || 0,
    updated:     s.updated || 0,
    flags:       s.dangerous ? 1 : 0,
  }));
  if (!rows.length) {
    tbody.innerHTML = `<tr><td colspan="6" class="empty-state">${_scriptsCache.length ? 'No matches' : 'No scripts yet. Click <b>New script</b> to create one.'}</td></tr>`;
    return;
  }
  tbody.innerHTML = rows.map(s => {
    const size = s.body_len < 1024 ? `${s.body_len} B` : `${(s.body_len/1024).toFixed(1)} KB`;
    const updated = s.updated ? timeAgo(s.updated) : '—';
    const dangerBadge = s.dangerous
      ? '<span class="patch-badge warn" title="Dry run flagged dangerous patterns">DANGER</span>'
      : '';
    return `<tr>
      <td class="fw-500">${escHtml(s.name||'—')}</td>
      <td class="hint">${escHtml(s.description||'')}</td>
      <td class="isl-328">${escHtml(size)}</td>
      <td class="hint">${escHtml(updated)}</td>
      <td>${dangerBadge}</td>
      <td class="nowrap">
        <button class="btn-icon isl-352" title="Edit" data-action="openScriptEdit" data-arg="${escAttr(s.id)}" >${_icon('edit',14)}</button>
        <button class="btn-icon isl-352" data-action="dryRunScript" data-arg="${escAttr(s.id)}" >Dry run</button>
        <button class="btn-icon isl-502 c-danger-outline" title="Delete" data-action="deleteScript" data-arg="${escAttr(s.id)}" data-arg2="${escAttr(s.name||'')}">${_icon('trash',14)}</button>
      </td>
    </tr>`;
  }).join('');
}

function openScriptAdd() {
  document.getElementById('script-edit-id').value = '';
  document.getElementById('script-edit-title').textContent = 'New script';
  document.getElementById('script-edit-name').value = '';
  document.getElementById('script-edit-desc').value = '';
  document.getElementById('script-edit-body').value = '#!/usr/bin/env bash\nset -euo pipefail\n\n';
  document.getElementById('script-edit-lint').style.display = 'none';
  openModal('script-edit-modal');
  setTimeout(() => document.getElementById('script-edit-name').focus(), 50);
}

async function openScriptEdit(id) {
  const data = await api('GET', '/scripts/' + encodeURIComponent(id));
  if (!data || data.error) { toast(data?.error || 'Failed', 'error'); return; }
  document.getElementById('script-edit-id').value = data.id;
  document.getElementById('script-edit-title').textContent = `Edit script — ${data.name||''}`;
  document.getElementById('script-edit-name').value = data.name || '';
  document.getElementById('script-edit-desc').value = data.description || '';
  document.getElementById('script-edit-body').value = data.body || '';
  _renderLintIntoBox('script-edit-lint', data.last_lint || null);
  openModal('script-edit-modal');
}

function _renderLintIntoBox(boxId, lint) {
  const el = document.getElementById(boxId);
  if (!el) return;
  if (!lint) { el.style.display = 'none'; return; }
  let bg = 'rgba(34,197,94,0.12)';
  let fg = 'var(--green)';
  let head = '✓ Syntax OK';
  if (lint.syntax_error && lint.syntax_error !== '__skipped__') {
    bg = 'rgba(239,68,68,0.12)'; fg = 'var(--red)';
    head = '✗ ' + lint.syntax_error;
  } else if (lint.syntax_error === '__skipped__') {
    bg = 'rgba(245,158,11,0.12)'; fg = 'var(--amber)';
    head = 'bash -n not available server-side — syntax check skipped';
  }
  let body = head;
  if (lint.dangerous && lint.dangerous.length) {
    body += '\n\nDangerous patterns detected:';
    lint.dangerous.forEach(d => { body += '\n  • ' + d; });
  }
  el.style.background = bg;
  el.style.color = fg;
  el.textContent = body;
  el.style.display = 'block';
}

async function runScriptDryRunFromEditor() {
  const id = document.getElementById('script-edit-id').value;
  if (!id) {
    // Not saved yet — save first, then dry-run. Otherwise we have no
    // server-side body to lint and the operator would just see an empty
    // result. This also gives them an "id" they can later edit.
    await saveScriptFromEditor(/*reopen=*/true);
    return;
  }
  const data = await api('POST', '/scripts/' + encodeURIComponent(id) + '/dry-run');
  if (!data || data.error) { toast(data?.error || 'Dry run failed', 'error'); return; }
  _renderLintIntoBox('script-edit-lint', data.lint);
  toast('Dry run complete', 'info');
  // Refresh list cache (last_lint may have changed).
  loadScripts();
}

async function saveScriptFromEditor(reopenAfter) {
  const id   = document.getElementById('script-edit-id').value;
  const name = document.getElementById('script-edit-name').value.trim();
  const desc = document.getElementById('script-edit-desc').value;
  const body = document.getElementById('script-edit-body').value;
  if (!name) { toast('Name required', 'error'); return; }
  if (!body.trim()) { toast('Body required', 'error'); return; }
  let resp;
  if (id) {
    resp = await api('PUT', '/scripts/' + encodeURIComponent(id), {name, description: desc, body});
  } else {
    resp = await api('POST', '/scripts', {name, description: desc, body});
  }
  if (!resp || resp.error) { toast(resp?.error || 'Save failed', 'error'); return; }
  toast(id ? 'Script updated' : 'Script created', 'success');
  if (resp.lint) _renderLintIntoBox('script-edit-lint', resp.lint);
  // If this was a create, the server returned the new record — keep the
  // modal open in edit mode so the operator can immediately dry-run.
  if (!id && resp.script?.id) {
    document.getElementById('script-edit-id').value = resp.script.id;
    document.getElementById('script-edit-title').textContent = `Edit script — ${resp.script.name||''}`;
  }
  loadScripts();
  if (!reopenAfter && id) closeModal('script-edit-modal');
}

async function dryRunScript(id) {
  const data = await api('POST', '/scripts/' + encodeURIComponent(id) + '/dry-run');
  if (!data || data.error) { toast(data?.error || 'Dry run failed', 'error'); return; }
  const l = data.lint || {};
  let summary;
  if (l.syntax_error && l.syntax_error !== '__skipped__') {
    summary = '✗ Syntax error: ' + l.syntax_error.slice(0, 240);
  } else {
    summary = '✓ Syntax OK';
  }
  if (l.dangerous && l.dangerous.length) {
    summary += ` — ${l.dangerous.length} dangerous pattern${l.dangerous.length>1?'s':''}: ${l.dangerous.join(', ')}`;
  }
  toast(summary, l.syntax_error && l.syntax_error !== '__skipped__' ? 'error'
                : (l.dangerous && l.dangerous.length ? 'info' : 'success'));
  loadScripts();
}

async function deleteScript(id, name) {
  if (!await uiConfirm(`Delete script ${name || id}?`)) return;
  const data = await api('DELETE', '/scripts/' + encodeURIComponent(id));
  if (data?.ok) { toast('Script deleted', 'info'); loadScripts(); }
  else toast(data?.error || 'Failed', 'error');
}

// ── Run-script modal: single device OR batch (current selection) ──────────
async function openScriptRunForDevice(deviceId, deviceName) {
  document.getElementById('script-run-mode').value = 'single';
  document.getElementById('script-run-device-id').value = deviceId;
  document.getElementById('script-run-target').textContent = `Queue a saved script on ${deviceName}.`;
  document.getElementById('script-run-confirm-wrap').style.display = 'none';
  document.getElementById('script-run-confirm-dangerous').checked = false;
  document.getElementById('script-run-lint').style.display = 'none';
  await _populateScriptRunPicker();
  openModal('script-run-modal');
}
async function openScriptRunForBatch() {
  if (!selectedDevices.size) { toast('Select devices first', 'error'); return; }
  document.getElementById('script-run-mode').value = 'batch';
  document.getElementById('script-run-device-id').value = '';
  document.getElementById('script-run-target').textContent =
    `Queue a saved script on ${selectedDevices.size} selected device${selectedDevices.size===1?'':'s'}.`;
  document.getElementById('script-run-confirm-wrap').style.display = 'none';
  document.getElementById('script-run-confirm-dangerous').checked = false;
  document.getElementById('script-run-lint').style.display = 'none';
  await _populateScriptRunPicker();
  openModal('script-run-modal');
}
async function _populateScriptRunPicker() {
  const sel = document.getElementById('script-run-pick');
  sel.innerHTML = '<option value="">— Choose a saved script —</option>';
  const data = await api('GET', '/scripts');
  (Array.isArray(data) ? data : []).forEach(s => {
    const opt = document.createElement('option');
    opt.value = s.id;
    opt.textContent = s.name + (s.dangerous ? '  DANGER' : '');
    opt.dataset.dangerous = s.dangerous ? '1' : '';
    sel.appendChild(opt);
  });
}
function onScriptRunPick() {
  const sel = document.getElementById('script-run-pick');
  const opt = sel.options[sel.selectedIndex];
  const dangerous = opt?.dataset?.dangerous === '1';
  document.getElementById('script-run-confirm-wrap').style.display = dangerous ? 'block' : 'none';
  document.getElementById('script-run-confirm-dangerous').checked = false;
  document.getElementById('script-run-lint').style.display = 'none';
}
async function confirmScriptRun() {
  const sid = document.getElementById('script-run-pick').value;
  if (!sid) { toast('Pick a script first', 'error'); return; }
  const mode = document.getElementById('script-run-mode').value;
  const confirmDangerous = document.getElementById('script-run-confirm-dangerous').checked;
  let payload = {script_id: sid, confirm_dangerous: confirmDangerous};
  if (mode === 'single') {
    payload.device_ids = [document.getElementById('script-run-device-id').value];
  } else {
    payload.device_ids = [...selectedDevices];
  }
  const resp = await api('POST', '/exec/batch', payload);
  if (!resp || resp.error) {
    // Surface syntax / dangerous-pattern errors so the operator knows
    // what to fix rather than just "request failed".
    if (resp?.dangerous?.length) {
      _renderLintIntoBox('script-run-lint', {dangerous: resp.dangerous, syntax_error: null});
      toast('Script flagged as dangerous — tick the box to confirm', 'error');
      document.getElementById('script-run-confirm-wrap').style.display = 'block';
      return;
    }
    if (resp?.syntax_error) {
      _renderLintIntoBox('script-run-lint', {syntax_error: resp.syntax_error, dangerous: []});
      toast('Fix the syntax error first', 'error');
      return;
    }
    toast(resp?.error || 'Failed to queue', 'error');
    return;
  }
  closeModal('script-run-modal');
  if (mode === 'batch') clearSelection();
  toast(`Queued on ${resp.queued}/${resp.total} device${resp.total===1?'':'s'}`, 'success');
  if (resp.job_id) openBatchJobModal(resp.job_id);
}

// ── Batch job status modal — polls /api/exec/batch/<id> ───────────────────
let _batchJobTimer = null;
function openBatchJobModal(jobId) {
  document.getElementById('batch-job-id').value = jobId;
  document.getElementById('batch-job-body').innerHTML =
    '<div class="empty-state">Loading…</div>';
  document.getElementById('batch-job-title').textContent = 'Batch script run';
  document.getElementById('batch-job-sub').textContent = 'Polling for results…';
  openModal('batch-job-modal');
  refreshBatchJob();
  clearInterval(_batchJobTimer);
  _batchJobTimer = setInterval(refreshBatchJob, 10000);
}
function closeBatchJobModal() {
  clearInterval(_batchJobTimer);
  _batchJobTimer = null;
  closeModal('batch-job-modal');
}
async function refreshBatchJob() {
  const jobId = document.getElementById('batch-job-id').value;
  if (!jobId) return;
  const data = await api('GET', '/exec/batch/' + encodeURIComponent(jobId));
  if (!data || data.error) {
    document.getElementById('batch-job-body').innerHTML =
      `<div class="c-red-p20">${escHtml(data?.error||'Failed to load job')}</div>`;
    clearInterval(_batchJobTimer);
    return;
  }
  document.getElementById('batch-job-title').textContent =
    `Batch run: ${data.script_name || data.script_id}`;
  const entries = Object.entries(data.per_device || {});
  const done = entries.filter(([,e]) => e.status === 'done').length;
  const queued = entries.filter(([,e]) => e.queued).length;
  document.getElementById('batch-job-sub').textContent =
    `${done}/${queued} returned output — refreshes every 10s (close to stop)`;
  let body = '';
  for (const [devId, e] of entries) {
    const name = escHtml(e.name || devId);
    let pill = '<span class="patch-badge ok fs-11">pending</span>';
    let outBox = '';
    if (!e.queued) {
      pill = `<span class="patch-badge warn fs-11">${escHtml(e.reason||'skipped')}</span>`;
    } else if (e.status === 'done') {
      const ok = e.rc === 0;
      pill = `<span class="patch-badge ${ok ? 'ok' : 'warn'} fs-11">rc=${escHtml(String(e.rc))}</span>`;
      const finished = e.finished_at ? new Date(e.finished_at*1000).toLocaleTimeString() : '';
      outBox = `<pre class="isl-503">${escHtml(e.output||'(no output)')}</pre><div class="isl-504">finished ${escHtml(finished)}</div>`;
    }
    body += `<div class="isl-505">
      <div class="isl-506"><div class="fw-600">${name}</div>${pill}</div>
      ${outBox}
    </div>`;
  }
  if (!entries.length) body = '<div class="isl-507">No targets in this batch.</div>';
  document.getElementById('batch-job-body').innerHTML = body;
  // Stop polling once everyone has either returned output or was skipped.
  if (queued === 0 || done >= queued) {
    clearInterval(_batchJobTimer);
    _batchJobTimer = null;
    document.getElementById('batch-job-sub').textContent =
      `${done}/${queued} returned output — polling stopped (Refresh to re-check)`;
  }
}

// ── Docker-compose dropdown on device cards ───────────────────────────────
async function openComposeModal(deviceId, deviceName) {
  document.getElementById('compose-device-id').value = deviceId;
  document.getElementById('compose-title').textContent = `docker compose — ${deviceName}`;
  document.getElementById('compose-result').textContent =
    'Queue an action — output arrives on the next heartbeat (~60s).';
  const sel = document.getElementById('compose-project-pick');
  sel.innerHTML = '<option value="">Loading…</option>';
  openModal('compose-modal');
  const data = await api('GET', '/devices/' + encodeURIComponent(deviceId) + '/compose');
  if (!data || data.error) {
    sel.innerHTML = `<option value="">${escHtml(data?.error||'Failed to load')}</option>`;
    return;
  }
  const projects = data.projects || [];
  if (!projects.length) {
    sel.innerHTML = `<option value="">${data.docker_seen ? 'No projects found under /opt /home /docker /srv' : 'Device has not reported yet'}</option>`;
    return;
  }
  sel.innerHTML = projects.map(p =>
    `<option value="${escHtml(p.dir)}">${escHtml(p.name)} — ${escHtml(p.dir)}</option>`
  ).join('');
}
async function runCompose(action) {
  const deviceId = document.getElementById('compose-device-id').value;
  const dir = document.getElementById('compose-project-pick').value;
  if (!dir) { toast('Pick a project first', 'error'); return; }
  // Down is the most disruptive — confirm explicitly.
  if (action === 'down' && !await uiConfirm(`Run "docker compose down" in ${dir}?\nThis stops and removes the project's containers.`)) return;
  const resp = await api('POST', '/devices/' + encodeURIComponent(deviceId) + '/compose/action',
                         {action, dir});
  if (!resp || resp.error) { toast(resp?.error || 'Failed', 'error'); return; }
  toast(`compose ${action} queued — output arrives on next heartbeat`, 'success');
  document.getElementById('compose-result').textContent =
    `Queued: ${resp.queued}\nWaiting for the agent's next heartbeat (~60s)…\nResults appear on the device's System info → Command output panel.`;
}


document.addEventListener('DOMContentLoaded', () => {
  // v4.6.0: apply the theme + New/Old UI skin up front so the LOGIN / front
  // page is themed too (not just the post-login app, which re-applies in showApp).
  try { applyTheme(); } catch (_) {}
  try { applyUIVersion(); } catch (_) {}
  loadPublicInfo();
  // The login fields are now inside #login-form so Enter triggers the
  // form's submit naturally — no per-field keydown listeners required.
  // Keep the username → password focus-on-Enter so tab-less keyboards
  // (and operators who hit Enter after username) still flow through.
  document.getElementById('login-user').addEventListener('keydown', e => {
    if (e.key === 'Enter') {
      e.preventDefault();
      document.getElementById('login-pass').focus();
    }
  });
  // v1.11.5: best-effort flush on tab close. Browsers limit what fetch()
  // can do in 'beforeunload', but a fire-and-forget request often makes
  // it out before the page is gone. The 600ms debounce already covers
  // every other case; this is just for "user closed the tab mid-typing".
  window.addEventListener('beforeunload', () => {
    if (_uiPrefsFlushTimer && _uiPrefsLoaded) {
      try { flushUiPrefs(); } catch(e) {}
    }
  });
  checkAuth();
});

// ─── v2.1.3: AI assistant ───────────────────────────────────────────────────
//
// Two surfaces:
//   1. Settings → AI assistant tab (loadAISettings / saveAISettings /
//      testAIConnection / onAIProviderChange)
//   2. Inline AIbuttons on command output, journal, scripts, CVE rows,
