function _fwRuleRow(devId, backend, r, editable) {
  const del = (editable && r.ref)
    ? `<button class="btn-icon cell-sm c-danger-outline" data-action="firewallRuleDelete" data-arg="${escAttr(devId)}" data-arg2="${escAttr(backend)}" data-arg3="${escAttr(r.ref)}" data-pass-btn="1" title="Delete this rule">${_icon('trash',14)}</button>`
    : '';
  return `<div class="fw-rule-row"><code>${escHtml(r.text)}</code>${del}</div>`;
}

// Render a backend's rules grouped by table/chain (like `nft list ruleset` /
// `iptables -S` per chain) instead of a flat, counter-laden dump.
function _fwRenderRules(devId, backend, rl, editable) {
  if (!rl.length) return '<div class="hint mt-4">No rules listed (or not readable without root).</div>';
  const hasChains = rl.some(r => r.chain);
  let html = '<div class="scroll-cap mt-8 fw-rules">';
  if (hasChains) {
    const order = [], groups = new Map();
    for (const r of rl) {
      const key = (r.table || '') + '␟' + (r.chain || '');
      if (!groups.has(key)) { groups.set(key, []); order.push(key); }
      groups.get(key).push(r);
    }
    for (const key of order) {
      const parts = key.split('␟'), tbl = parts[0], chain = parts[1];
      html += `<div class="fw-chain-hdr">${tbl ? escHtml(tbl) + ' · ' : ''}chain ${escHtml(chain || '—')}</div>`;
      html += groups.get(key).map(r => _fwRuleRow(devId, backend, r, editable)).join('');
    }
  } else {
    html += rl.map(r => _fwRuleRow(devId, backend, r, editable)).join('');
  }
  return html + '</div>';
}




async function loadFail2ban() {
  const tbody = document.getElementById('fail2ban-tbody');
  if (!tbody) return;
  tableCtl.wireSortOnly('fail2ban-thead', 'fail2ban', () => _renderFail2ban());
  tbody.innerHTML = _skeletonRows(5);
  try {
    const data = await api('GET', '/fail2ban');
    _fail2banResp = data;
    const sm = document.getElementById('fail2ban-summary');
    if (sm) {
      const tot = (data.devices || []).reduce((a, d) => a + (d.banned_total || 0), 0);
      sm.textContent = `${data.count} host(s) · ${tot} banned IP(s)`;
    }
    _renderFail2ban();
  } catch (e) {
    tbody.innerHTML = `<tr><td colspan="5" class="hint">Failed to load: ${escHtml(String(e))}</td></tr>`;
  }
}

function _renderFail2ban() {
  const tbody = document.getElementById('fail2ban-tbody');
  if (!tbody || !_fail2banResp) return;
  let rows = (_fail2banResp.devices || []).slice();
  rows = tableCtl.sortRows('fail2ban', rows, (r) => ({
    device:    (r.device || '').toLowerCase(),
    jails:     (r.jails || []).length,
    banned:    r.banned_total || 0,
    available: r.available ? 1 : 0,
  }));
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="hint">No fail2ban data reported yet.</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(r => {
    const mon = r.monitored === false ? ' <span class="pill" data-color="var(--muted)">unmonitored</span>' : '';
    if (!r.available) {
      return `<tr data-f2brow="${escAttr(r.device_id)}"><td class="fw-500">${escHtml(r.device)}${mon}</td><td colspan="2" class="hint">fail2ban not installed / unreachable</td><td><span class="pill" data-color="var(--muted)">n/a</span></td><td></td></tr>`;
    }
    const jailNames = (r.jails || []).map(j => escHtml(j.name)).join(', ') || '<span class="hint">none</span>';
    return `<tr data-f2brow="${escAttr(r.device_id)}">
      <td class="fw-500">${escHtml(r.device)}${mon}</td>
      <td>${jailNames}</td>
      <td class="hint">${r.banned_total || 0}</td>
      <td><span class="pill" data-color="var(--green)">running</span></td>
      <td><button class="btn-icon cell-sm" data-action="fail2banDetail" data-arg="${escAttr(r.device_id)}" data-arg2="${escAttr(r.device)}">Manage</button></td>
    </tr>`;
  }).join('');
}

async function fail2banDetail(devId, devName) {
  const panel = document.getElementById('fail2ban-detail');
  if (!panel) return;
  panel.innerHTML = '<div class="hint">Loading jails…</div>';
  let data;
  try { data = await api('GET', '/fail2ban?device=' + encodeURIComponent(devId)); }
  catch (e) { panel.innerHTML = `<div class="hint">Failed: ${escHtml(String(e))}</div>`; return; }
  const dev = (data.devices || [])[0];
  if (!dev || !dev.available) { panel.innerHTML = '<div class="hint">fail2ban not available on this host.</div>'; return; }
  let html = `<div class="dash-card"><div class="fw-detail-hdr"><div class="section-title">fail2ban — ${escHtml(devName || dev.device)}</div><div class="fw-detail-actions"><button class="btn-icon cell-sm" data-action="fail2banDetailClose" title="Close" aria-label="Close">${_FW_X_SVG}</button></div></div>`;
  if (!(dev.jails || []).length) html += '<div class="hint mt-8">No jails configured.</div>';
  for (const j of (dev.jails || [])) {
    const did = escAttr(dev.device_id), jn = escAttr(j.name);
    html += `<div class="fw-jail-hdr"><strong>${escHtml(j.name)}</strong> <span class="hint">${j.banned_count || 0} banned · ${j.total_failed || 0} failed</span>
      <button class="btn-icon cell-sm" data-action="fail2banBan" data-arg="${did}" data-arg2="${jn}" title="Ban an IP in this jail">Ban IP</button>
      <button class="btn-icon cell-sm" data-action="fail2banJail" data-arg="${did}" data-arg2="${jn}" data-arg3="enable" title="Start this jail">Start</button>
      <button class="btn-icon cell-sm c-danger-outline" data-action="fail2banJail" data-arg="${did}" data-arg2="${jn}" data-arg3="disable" title="Stop this jail">Stop</button></div>`;
    const banned = j.banned || [];
    if (banned.length) {
      html += '<div class="scroll-cap mt-8 fw-rules">' + banned.map(ip =>
        `<div class="fw-ban-row"><code>${escHtml(ip)}</code><button class="btn-icon cell-sm" data-action="fail2banUnban" data-arg="${did}" data-arg2="${jn}" data-arg3="${escAttr(ip)}" data-pass-btn="1">Unban</button></div>`).join('') + '</div>';
    } else {
      html += '<div class="hint mt-4">No banned IPs.</div>';
    }
  }
  html += '</div>';
  panel.innerHTML = html;
  _fwSelectRow('fail2ban-tbody', 'f2brow', dev.device_id);
  panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

async function fail2banBan(devId, jail) {
  const ip = await uiPrompt({ title: `Ban IP in ${jail}`, message: 'Enter an IPv4 or IPv6 address to ban.', placeholder: '203.0.113.10', confirmText: 'Ban' });
  if (!ip) return;
  try {
    await api('POST', `/devices/${encodeURIComponent(devId)}/fail2ban-action`, { action: 'ban', jail, ip });
    toast('Ban queued', 'success');
    _fwQueuedNote('fail2ban-detail');
  } catch (e) { toast('Failed: ' + String(e), 'error'); }
}

async function fail2banUnban(devId, jail, ip, btn) {
  try {
    await api('POST', `/devices/${encodeURIComponent(devId)}/fail2ban-action`, { action: 'unban', jail, ip: String(ip) });
    toast('Unban queued', 'success');
    _fwMarkPending(btn); _fwQueuedNote('fail2ban-detail');
  } catch (e) { toast('Failed: ' + String(e), 'error'); }
}

async function fail2banJail(devId, jail, action) {
  const stop = action === 'disable';
  const ok = await uiConfirm({ title: `${stop ? 'Stop' : 'Start'} jail ${jail}`, message: `${stop ? 'Stop' : 'Start'} the "${jail}" jail on this host?`, confirmText: stop ? 'Stop' : 'Start', danger: stop });
  if (!ok) return;
  try {
    await api('POST', `/devices/${encodeURIComponent(devId)}/fail2ban-action`, { action, jail });
    toast('Queued', 'success');
    _fwQueuedNote('fail2ban-detail');
  } catch (e) { toast('Failed: ' + String(e), 'error'); }
}

// ── Firewall/fail2ban detail-panel UX helpers (v4.10.0 polish) ───────────────
const _FW_X_SVG = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="13" height="13" stroke-linecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>';

function _fwSelectRow(tbodyId, key, devId) {
  const tb = document.getElementById(tbodyId);
  if (!tb) return;
  tb.querySelectorAll('tr').forEach(r => r.classList.toggle('row-selected', r.dataset[key] === devId));
}
function _fwClearSel(tbodyId) {
  const tb = document.getElementById(tbodyId);
  if (tb) tb.querySelectorAll('tr.row-selected').forEach(r => r.classList.remove('row-selected'));
}
function _fwMarkPending(btn) {
  if (!btn) return;
  const row = btn.closest('.fw-rule-row, .fw-ban-row');
  if (row) row.classList.add('fw-pending');
  btn.disabled = true;
  btn.textContent = 'queued';
}
function _fwQueuedNote(panelId) {
  const card = document.querySelector('#' + panelId + ' .dash-card');
  if (!card) return;
  let note = card.querySelector('.fw-queued-note');
  if (!note) {
    note = document.createElement('div');
    note.className = 'fw-queued-note';
    const hdr = card.querySelector('.fw-detail-hdr');
    if (hdr && hdr.nextSibling) card.insertBefore(note, hdr.nextSibling); else card.appendChild(note);
  }
  const n = (parseInt(note.dataset.n || '0', 10) || 0) + 1;
  note.dataset.n = n;
  note.textContent = `Queued: ${n} change${n > 1 ? 's' : ''} — apply on the host's next check-in.`;
}
function fail2banDetailClose() {
  const p = document.getElementById('fail2ban-detail'); if (p) p.innerHTML = '';
  _fwClearSel('fail2ban-tbody');
}

async function loadExposure() {
  const tbody = document.getElementById('exposure-tbody');
  const summary = document.getElementById('exposure-summary');
  if (!tbody) return;
  tableCtl.wireSortOnly('exposure-thead', 'exposure', () => _renderExposure());
  tbody.innerHTML = _skeletonRows(6);
  try {
    const data = await api('GET', '/exposure' + (_exposureScope ? `?scope=${_exposureScope}` : ''));
    _exposureResp = data;
    if (summary) {
      const c = data.counts || {};
      summary.textContent = `${data.count} sockets · world ${c.world||0} · lan ${c.lan||0} · local ${c.local||0}`;
    }
    _renderExposure();
  } catch (e) {
    tbody.innerHTML = `<tr><td colspan="6" class="isl-533">Failed to load: ${escHtml(String(e))}</td></tr>`;
  }
  loadSecrets();   // v3.14.0 #35: the secrets card lives on the same page
}

// ─── v3.14.0 #35: exposed-secrets fleet card (redacted findings) ────────────
let _secretsResp = null;
async function loadSecrets() {
  const tbody = document.getElementById('secrets-tbody');
  if (!tbody) return;
  tableCtl.wireSortOnly('secrets-thead', 'secrets', () => _renderSecrets());
  const fb = document.getElementById('secrets-filter');
  // Debounce: _renderSecrets() flattens + sorts + rebuilds the whole tbody
  // (hundreds of findings on a big fleet); the prior listener fired that on
  // EVERY keystroke (the data-input-debounce attr was dead — no data-input).
  if (fb && !fb.dataset.wired) {
    fb.dataset.wired = '1';
    let _sft;
    fb.addEventListener('input', () => {
      clearTimeout(_sft);
      _sft = setTimeout(() => _renderSecrets(), 180);
    });
  }
  tbody.innerHTML = _skeletonRows(6);
  try {
    _secretsResp = await api('GET', '/fleet/secrets');
    _renderSecrets();
  } catch (e) {
    tbody.innerHTML = `<tr><td colspan="6" class="isl-533">Failed to load: ${escHtml(String(e))}</td></tr>`;
  }
}
function _renderSecrets() {
  const tbody = document.getElementById('secrets-tbody');
  const summary = document.getElementById('secrets-summary');
  if (!tbody || !_secretsResp) return;
  let rows = [];
  for (const d of (_secretsResp.devices || [])) {
    // v4.1.0 (#55): carry host id + host-mute state onto each finding row.
    for (const f of (d.findings || [])) rows.push({ device: d.name, device_id: d.device_id, host_muted: !!d.host_muted, ...f });
  }
  const total = rows.length;
  // filter (627-finding fleets need it)
  const q = (document.getElementById('secrets-filter')?.value || '').toLowerCase().trim();
  if (q) rows = rows.filter(r => `${r.device || ''} ${r.rule || ''} ${r.path || ''} ${r.preview || ''}`.toLowerCase().includes(q));
  if (summary) {
    summary.textContent = !_secretsResp.enabled
      ? 'Scanning is off — enable it in Settings → Security.'
      : `${_secretsResp.total_active || 0} active finding(s) across ${(_secretsResp.devices || []).length} host(s).`
        + (q ? ` — showing ${rows.length} of ${total}.` : '');
  }
  rows = tableCtl.sortRows('secrets', rows, (r) => ({
    device: (r.device || '').toLowerCase(), rule: r.rule || '',
    path: (r.path || '').toLowerCase(), preview: r.preview || '', line: r.line || 0,
  }));
  if (rows.length === 0) {
    tbody.innerHTML = `<tr><td colspan="6" class="hint">${_secretsResp.enabled ? 'No secrets found in the scanned paths.' : 'Secrets scanning is disabled.'}</td></tr>`;
    return;
  }
  tbody.innerHTML = rows.map((r) => `
    <tr>
      <td>${escHtml(r.device || '—')}${r.host_muted ? ' <span class="hint">host muted</span>' : ''}</td>
      <td><span class="cmd-badge">${escHtml(r.rule || '?')}</span>${r.muted ? ' <span class="hint">muted</span>' : ''}</td>
      <td class="fs-12"><div class="cell-trunc" title="${escAttr(r.path || '')}"><code>${escHtml(r.path || '—')}</code></div></td>
      <td class="fs-12"><div class="cell-trunc" title="${escAttr(r.preview || '')}"><code>${escHtml(r.preview || '—')}</code></div></td>
      <td class="ta-center">${r.line || '—'}</td>
      <td class="nowrap">${r.host_muted
        ? `<button class="btn-icon cell-sm" data-action="unmuteSecretHost" data-arg="${escAttr(r.device_id || '')}">Unmute host</button>`
        : `${r.muted
            ? `<button class="btn-icon cell-sm" data-action="unmuteSecret" data-arg="${escAttr(r.fingerprint || '')}">Unmute</button>`
            : `<button class="btn-icon cell-sm" data-action="muteSecret" data-arg="${escAttr(r.fingerprint || '')}">Mute</button>`}
           <button class="btn-icon cell-sm" data-action="muteSecretHost" data-arg="${escAttr(r.device_id || '')}" title="Mute every finding on this host">Mute host</button>`}</td>
    </tr>`).join('');
}
async function muteSecret(fp) {
  const r = await api('POST', '/secrets/mute', { fingerprint: fp });
  if (r?.ok) { toast('Finding muted', 'info'); loadSecrets(); } else toast(r?.error || 'Failed', 'error');
}
async function unmuteSecret(fp) {
  const r = await api('POST', '/secrets/mute', { fingerprint: fp, unmute: true });
  if (r?.ok) { toast('Finding unmuted', 'info'); loadSecrets(); } else toast(r?.error || 'Failed', 'error');
}
// v4.1.0 (#55): mute / unmute every secret finding on a whole host.
async function muteSecretHost(devId) {
  if (!devId) return;
  if (!await uiConfirm('Mute every secret finding on this host? It stops alerting and counting until you unmute.')) return;
  const r = await api('POST', '/secrets/host-mute', { device_id: devId });
  if (r?.ok) { toast('Host muted', 'info'); loadSecrets(); } else toast(r?.error || 'Failed', 'error');
}
async function unmuteSecretHost(devId) {
  if (!devId) return;
  const r = await api('POST', '/secrets/host-mute', { device_id: devId, unmute: true });
  if (r?.ok) { toast('Host unmuted', 'info'); loadSecrets(); } else toast(r?.error || 'Failed', 'error');
}
function _renderExposure() {
  const tbody = document.getElementById('exposure-tbody');
  if (!tbody || !_exposureResp) return;
  let rows = (_exposureResp.ports || []).slice();
  rows = tableCtl.sortRows('exposure', rows, (r) => ({
    device: (r.device || '').toLowerCase(),
    proto:  r.proto || '',
    port:   r.port || 0,
    process: (r.process || '').toLowerCase(),
    addr:   r.addr || '',
    scope:  r.scope || '',
  }));
  // v3.12.0: discovery banner — visibility leads back to the (opt-in) alerting.
  const banner = document.getElementById('exposure-banner');
  if (banner) {
    const world = (_exposureResp.counts || {}).world || 0;
    if (!_exposureResp.audit_enabled && world > 0) {
      banner.hidden = false;
      banner.innerHTML = `<span class="exposure-banner-text"><strong>${world}</strong> world-reachable service${world === 1 ? '' : 's'} detected. Alerting is off — turn on the Listening-port &amp; firewall audit to be notified when a new one appears.</span>`
        + `<button class="btn-icon" data-action-btn="_showPageBtn" data-page="settings"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>Open Settings</button>`;
    } else { banner.hidden = true; banner.innerHTML = ''; }
  }
  if (rows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="6" class="isl-534">No listening sockets reported yet. Agents must be on v3.11.0+.</td></tr>';
    return;
  }
  const badge = (s) => {
    const color = s === 'world' ? 'var(--red)' : s === 'lan' ? 'var(--amber)' : 'var(--muted)';
    return `<span class="pill" data-color="${color}">${escHtml(s || '—')}</span>`;
  };
  // Which hosts are entirely muted (a device_id-only rule)? Drives the
  // host-level Mute/Unmute toggle and avoids redundant per-process buttons.
  const hostMuted = new Set((_exposureResp.mutes || [])
    .filter(m => m && m.device_id && !m.process && !m.proto && m.port == null)
    .map(m => m.device_id));
  tbody.innerHTML = rows.map(r => {
    const proc = r.process || '';
    const isHostMuted = hostMuted.has(r.device_id);
    const procBtn = r.muted
      ? `<button class="btn-icon cell-sm" data-action="unmuteExposureProcess" data-arg="${escAttr(proc)}" title="Stop muting alerts for ${escAttr(proc)}">Unmute</button>`
      : (proc ? `<button class="btn-icon cell-sm" data-action="muteExposureProcess" data-arg="${escAttr(proc)}" title="Mute new-port / world-exposed alerts for ${escAttr(proc)}">Mute</button>` : '');
    const hostBtn = isHostMuted
      ? `<button class="btn-icon cell-sm" data-action="unmuteExposureHost" data-arg="${escAttr(r.device_id)}" data-arg2="${escAttr(r.device)}" title="Stop muting all exposure from ${escAttr(r.device)}">Unmute host</button>`
      : `<button class="btn-icon cell-sm" data-action="muteExposureHost" data-arg="${escAttr(r.device_id)}" data-arg2="${escAttr(r.device)}" title="Mute ALL exposure alerts from ${escAttr(r.device)}">Mute host</button>`;
    return `<tr${(r.muted || isHostMuted) ? ' class="muted-row"' : ''}>
    <td class="fw-500">${escHtml(r.device)}</td>
    <td class="hint">${escHtml(r.proto)}/${r.port}</td>
    <td>${escHtml(proc || '—')}${(r.muted || isHostMuted) ? ' <span class="pill" data-color="var(--muted)">muted</span>' : ''}</td>
    <td class="hint">${escHtml(r.addr || '—')}</td>
    <td>${badge(r.scope)}</td>
    <td class="exposure-actions">${r.scope === 'world' ? `<button class="btn-icon cell-sm" data-action="aiExposureAdvice" data-arg="${escAttr(r.device)}" data-arg2="${escAttr(r.proto + '/' + r.port)}" data-arg3="${escAttr(proc)}" title="AI: should this be exposed? how to lock it down">${_icon('sparkles', 12)}</button> ` : ''}${isHostMuted ? hostBtn : procBtn + ' ' + hostBtn}</td>
  </tr>`;
  }).join('');
}

// v3.12.0: surgical exposure mutes (by process) from the Exposure table.
async function muteExposureProcess(process) {
  if (!process) return;
  if (!await uiConfirm(`Mute new-port and world-exposed alerts for "${process}" across the fleet?\n\nAny matching open alerts will be resolved. The Exposure page still lists these sockets.`)) return;
  const r = await api('POST', '/exposure/mute', { action: 'add', process });
  if (r && r.ok) {
    toast(`Muted ${process}` + (r.resolved ? ` · resolved ${r.resolved} alert(s)` : ''), 'success');
    loadExposure();
  } else { toast('Mute failed', 'error'); }
}
// v3.12.0: mute ALL exposure from one host (device-scoped rule).
async function muteExposureHost(deviceId, deviceName) {
  if (!deviceId) return;
  const nm = deviceName || deviceId;
  if (!await uiConfirm(`Mute new-port and world-exposed alerts for EVERY service on "${nm}"?\n\nUseful for an appliance or jump host you've accepted. Any matching open alerts are resolved; the sockets still appear here.`)) return;
  const r = await api('POST', '/exposure/mute', { action: 'add', device_id: deviceId });
  if (r && r.ok) {
    toast(`Muted all exposure from ${nm}` + (r.resolved ? ` · resolved ${r.resolved} alert(s)` : ''), 'success');
    loadExposure();
  } else { toast('Mute failed', 'error'); }
}
async function unmuteExposureHost(deviceId, deviceName) {
  const r = await api('POST', '/exposure/mute', { action: 'remove', device_id: deviceId });
  if (r && r.ok) { toast(`Unmuted ${deviceName || deviceId}`, 'success'); loadExposure(); }
  else { toast('Unmute failed', 'error'); }
}
async function unmuteExposureProcess(process) {
  const r = await api('POST', '/exposure/mute', { action: 'remove', process });
  if (r && r.ok) { toast(`Unmuted ${process}`, 'success'); loadExposure(); }
  else { toast('Unmute failed', 'error'); }
}

// v3.12.0: managed mute list in Settings → Security.
function _renderExposureMutes(mutes) {
  const el = document.getElementById('exposure-mute-list');
  if (!el) return;
  mutes = mutes || [];
  if (!mutes.length) {
    el.textContent = 'No mutes — the audit alerts on every host.';
    return;
  }
  el.innerHTML = mutes.map(m => {
    const parts = [];
    // v3.14.0 fix: a host-scoped mute ({device_id}) used to render as "(empty)"
    // because only process/proto/port were shown — now show the device too, and
    // pass it to Remove so device mutes can actually be cleared.
    if (m.device_id) {
      const dev = (window._devicesCache || []).find(d => d.id === m.device_id);
      parts.push('device=' + escHtml(dev ? dev.name : m.device_id));
    }
    if (m.process) parts.push('process=' + escHtml(m.process));
    if (m.proto) parts.push('proto=' + escHtml(m.proto));
    if (m.port !== undefined && m.port !== null) parts.push('port=' + escHtml(String(m.port)));
    const label = parts.join(' · ') || '(empty)';
    return `<div class="sb-controls"><span>${label}</span><button class="btn-icon cell-sm" data-action="removeExposureMute" data-arg="${escAttr(m.process || '')}" data-arg2="${escAttr(m.proto || '')}" data-arg3="${escAttr(m.port !== undefined && m.port !== null ? String(m.port) : '')}" data-arg4="${escAttr(m.device_id || '')}" title="Remove">${_icon('trash',14)}</button></div>`;
  }).join('');
}
async function addExposureMute() {
  const process = (document.getElementById('mute-process')?.value || '').trim();
  const proto = (document.getElementById('mute-proto')?.value || '').trim();
  const port = (document.getElementById('mute-port')?.value || '').trim();
  if (!process && !proto && !port) { toast('Enter a process and/or proto/port', 'error'); return; }
  const body = { action: 'add' };
  if (process) body.process = process;
  if (proto) body.proto = proto;
  if (port) body.port = port;
  const r = await api('POST', '/exposure/mute', body);
  if (r && r.ok) {
    toast('Mute added' + (r.resolved ? ` · resolved ${r.resolved} alert(s)` : ''), 'success');
    ['mute-process', 'mute-proto', 'mute-port'].forEach(id => { const e = document.getElementById(id); if (e) e.value = ''; });
    _renderExposureMutes(r.mutes);
  } else { toast('Add mute failed', 'error'); }
}
async function removeExposureMute(process, proto, port, deviceId) {
  const body = { action: 'remove' };
  if (deviceId) body.device_id = deviceId;
  if (process) body.process = process;
  if (proto) body.proto = proto;
  if (port !== '' && port !== undefined && port !== null) body.port = port;
  const r = await api('POST', '/exposure/mute', body);
  if (r && r.ok) { toast('Mute removed', 'success'); _renderExposureMutes(r.mutes); }
  else { toast('Remove mute failed', 'error'); }
}
document.addEventListener('change', e => {
  if (e.target && e.target.id === 'exposure-scope') {
    _exposureScope = e.target.value || '';
    loadExposure();
  }
});

// ─── v3.11.0: Storage / RAID health ──────────────────────────────────────────
let _storageResp = null;
async function loadStorage() {
  const tbody = document.getElementById('storage-tbody');
  const summary = document.getElementById('storage-summary');
  if (!tbody) return;
  tableCtl.wireSortOnly('storage-thead', 'storage', () => _renderStorage());
  tbody.innerHTML = _skeletonRows(6);
  try {
    const data = await api('GET', '/storage');
    _storageResp = data;
    if (summary) summary.textContent = `${data.count} pools · ${data.degraded} degraded`;
    _renderStorage();
  } catch (e) {
    tbody.innerHTML = `<tr><td colspan="6" class="isl-533">Failed to load: ${escHtml(String(e))}</td></tr>`;
  }
}
// Cap a full-fleet roll-up table so an extremely large fleet can't flood the
// page with thousands of <tr>s (same principle as the home roster cap). Rows
// arrive already sorted, so the first N reflect the active sort; the caller
// appends `.note` as a trailing row telling the user how many were hidden.
const FLEET_ROWS_CAP = 200;
function _capFleetRows(rows, colspan, noun) {
  if (rows.length <= FLEET_ROWS_CAP) return { rows, note: '' };
  const more = rows.length - FLEET_ROWS_CAP;
  return {
    rows: rows.slice(0, FLEET_ROWS_CAP),
    note: `<tr><td colspan="${colspan}" class="hint ta-center">Showing the first ${FLEET_ROWS_CAP} of ${rows.length} ${noun} (+${more} more) — sort a column to bring what you need to the top.</td></tr>`,
  };
}

function _renderStorage() {
  const tbody = document.getElementById('storage-tbody');
  if (!tbody || !_storageResp) return;
  let rows = (_storageResp.pools || []).slice();
  rows = tableCtl.sortRows('storage', rows, (r) => ({
    device:   (r.device || '').toLowerCase(),
    pool:     (r.pool || '').toLowerCase(),
    kind:     r.kind || '',
    state:    r.state || '',
    capacity: r.capacity || 0,
    scrub:    r.scrub || '',
  }));
  if (rows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" class="isl-534">No ZFS / mdadm / btrfs pools reported. Agents must be on v3.11.0+.</td></tr>';
    return;
  }
  const { rows: shown, note } = _capFleetRows(rows, 7, 'pools');
  tbody.innerHTML = shown.map(r => {
    const color = r.degraded ? 'var(--red)' : 'var(--green)';
    const cap = (r.capacity || r.capacity === 0) && r.capacity !== null ? `${r.capacity}%` : '—';
    // ZFS/Btrfs pools get a one-click maintenance modal (scrub, trim/balance,
    // snapshots, …). mdraid and unmounted btrfs have no actionable target.
    const canAct = (r.kind === 'zfs' || r.kind === 'btrfs') && r.target;
    const maintBtn = canAct
      ? `<button class="btn-icon cell-sm" data-action="openStorageMaint" data-arg="${escAttr(r.device_id)}" data-arg2="${escAttr(r.kind + '|' + r.target + '|' + (r.pool || ''))}" title="${r.online ? 'Run a maintenance command on this pool' : 'Host offline — the command queues until it reconnects'}">Maintain…</button>`
      : '<span class="hint">—</span>';
    return `<tr>
      <td class="fw-500">${escHtml(r.device)}</td>
      <td>${escHtml(r.pool || '—')}</td>
      <td class="hint">${escHtml(r.kind || '—')}</td>
      <td class="${r.degraded ? 'fw-600' : ''}" data-color="${color}">${escHtml(r.state || '—')}</td>
      <td>${cap}</td>
      <td class="hint">${escHtml(r.scrub || '—')}</td>
      <td class="nowrap">${maintBtn}</td>
    </tr>`;
  }).join('') + note;
}

// ─── v5.0.0: one-click ZFS/Btrfs pool maintenance ───────────────────────────
let _storageMaintCtx = null;   // {deviceId, kind, target, pool}
const _STORAGE_MAINT_ACTIONS = {
  zfs: [
    { a: 'scrub',     l: 'Scrub',          mut: 1 },
    { a: 'trim',      l: 'Trim SSDs',      mut: 1 },
    { a: 'clear',     l: 'Clear errors',   mut: 1 },
    { a: 'status',    l: 'Status',         mut: 0 },
    { a: 'snapshots', l: 'List snapshots', mut: 0 },
  ],
  btrfs: [
    { a: 'scrub',     l: 'Scrub',          mut: 1 },
    { a: 'balance',   l: 'Balance (50%)',  mut: 1 },
    { a: 'usage',     l: 'Usage',          mut: 0 },
    { a: 'devstats',  l: 'Device stats',   mut: 0 },
    { a: 'snapshots', l: 'List snapshots', mut: 0 },
  ],
};
let _storagePollTimer = null;
function openStorageMaint(deviceId, packed) {
  const [kind, target, pool] = String(packed || '').split('|');
  if (!_STORAGE_MAINT_ACTIONS[kind] || !target) { toast('No maintenance actions for this pool', 'error'); return; }
  _storageMaintCtx = { deviceId, kind, target, pool: pool || target };
  if (_storagePollTimer) { clearInterval(_storagePollTimer); _storagePollTimer = null; }
  document.getElementById('storage-maint-title').textContent = `${kind.toUpperCase()} maintenance — ${pool || target}`;
  document.getElementById('storage-maint-sub').textContent = `Target: ${target}. Read actions show their output below; scrubs/balances run in the background.`;
  const snapInput = document.getElementById('storage-maint-snap');
  if (snapInput) snapInput.value = '';
  const out = document.getElementById('storage-maint-output');
  if (out) { out.classList.add('d-none'); out.textContent = ''; }
  document.getElementById('storage-maint-actions').innerHTML = _STORAGE_MAINT_ACTIONS[kind].map(x =>
    `<button class="btn-secondary cell-sm" data-action="storageRunAction" data-arg="${escAttr(x.a)}">${escHtml(x.l)}</button>`
  ).join('');
  openModal('storage-maint-modal');
}
async function storageRunAction(action) {
  const c = _storageMaintCtx;
  if (!c) return;
  const def = (_STORAGE_MAINT_ACTIONS[c.kind] || []).find(x => x.a === action);
  const isRead = !(def && def.mut);   // status / usage / device-stats / list-snapshots
  if (!isRead) {
    if (!await uiConfirm(`Run "${def.l}" on ${c.kind} ${c.pool}?\n\nThe command queues on ${c.pool} and runs on the host. Scrubs/balances are IO-intensive and run in the background.`)) return;
  }
  const out = document.getElementById('storage-maint-output');
  if (isRead && out) {
    out.classList.remove('d-none');
    out.textContent = `Running ${def ? def.l.toLowerCase() : action} on ${c.pool}…\nWaiting for the host's next check-in (up to ~90s).`;
  }
  // Baseline against the server's OWN timestamps (not the browser clock) so we
  // only surface the NEW result, not a stale older run of the same command.
  let baseTs = 0;
  if (isRead) {
    const cur = await api('GET', `/devices/${encodeURIComponent(c.deviceId)}/output`).catch(() => null);
    baseTs = Math.max(0, ...(((cur && cur.outputs) || [])
      .filter(e => String(e.cmd || '').includes(c.target)).map(e => e.ts || 0)));
  }
  const r = await api('POST', `/devices/${encodeURIComponent(c.deviceId)}/storage-action`,
                      { kind: c.kind, action, target: c.target });
  if (!r || r.error) {
    toast('Failed: ' + ((r && r.error) || 'unknown'), 'error');
    if (isRead && out) out.textContent = 'Failed: ' + ((r && r.error) || 'unknown');
    return;
  }
  if (!isRead) { toast(`Queued: ${action} on ${c.pool}. Runs on the host; pool status updates on the next check-in.`, 'success'); return; }
  _pollStorageOutput(c.deviceId, c.target, baseTs, action);
}
// Poll the host's command output for the result of a just-queued read action and
// show it in the modal. Reuses the standard /output buffer (capped 100/host).
function _pollStorageOutput(deviceId, target, baseTs, action) {
  if (_storagePollTimer) { clearInterval(_storagePollTimer); }
  const out = document.getElementById('storage-maint-output');
  const deadline = Date.now() + 95000;
  let dots = 0;
  _storagePollTimer = setInterval(async () => {
    // Stop if the modal was closed or context changed.
    if (!_storageMaintCtx || _storageMaintCtx.deviceId !== deviceId
        || !document.getElementById('storage-maint-modal')?.classList.contains('active')) {
      clearInterval(_storagePollTimer); _storagePollTimer = null; return;
    }
    const data = await api('GET', `/devices/${encodeURIComponent(deviceId)}/output`).catch(() => null);
    const list = (data && data.outputs) || [];
    // Newest matching entry for this pool/mount that landed after we queued.
    const hit = list.filter(e => e && (e.ts || 0) > baseTs && String(e.cmd || '').includes(target)).pop();
    if (hit) {
      clearInterval(_storagePollTimer); _storagePollTimer = null;
      if (action === 'snapshots') { _renderSnapshotList(out, target, hit); return; }
      const rcline = (typeof hit.rc === 'number' && hit.rc !== 0) ? `\n\n(exit code ${hit.rc})` : '';
      if (out) out.textContent = `$ ${hit.cmd}\n\n${hit.output || '(no output)'}${rcline}`;
      return;
    }
    if (Date.now() > deadline) {
      clearInterval(_storagePollTimer); _storagePollTimer = null;
      if (out) out.textContent = 'No output yet — the host may be offline or checking in slowly. It will appear in the host’s command output when it reports back.';
      return;
    }
    if (out) { dots = (dots + 1) % 4; out.textContent = out.textContent.replace(/\.*$/, '') + '.'.repeat(dots); }
  }, 3000);
}
async function storageDeleteSnapshot() {
  const c = _storageMaintCtx;
  if (!c) return;
  const snap = (document.getElementById('storage-maint-snap')?.value || '').trim();
  if (!snap) { toast('Enter the exact snapshot name to delete', 'error'); return; }
  if (!await uiConfirm(`Permanently DELETE snapshot:\n\n${snap}\n\nThis cannot be undone.`)) return;
  const r = await api('POST', `/devices/${encodeURIComponent(c.deviceId)}/storage-action`,
                      { kind: c.kind, action: c.kind === 'zfs' ? 'destroy' : 'delete', target: c.target, snapshot: snap });
  if (!r || r.error) { toast('Failed: ' + ((r && r.error) || 'unknown'), 'error'); return; }
  toast('Snapshot deletion queued.', 'success');
  const snapInput = document.getElementById('storage-maint-snap');
  if (snapInput) snapInput.value = '';
}

// Parse a snapshot listing into individual deletable names so you can remove
// snapshots from the list without copy-pasting paths.
//  - zfs `zfs list -t snapshot`: first column is the name (contains '@').
//  - btrfs `subvolume list -s`: each line ends in `path <subvol>`; the deletable
//    path is that joined onto the filesystem mountpoint (the target).
function _parseSnapshotNames(kind, target, text) {
  const lines = String(text || '').split('\n');
  if (kind === 'zfs') {
    return lines.map(l => l.trim().split(/\s+/)[0]).filter(t => t && t.includes('@'));
  }
  const base = (target === '/' ? '' : target.replace(/\/+$/, ''));
  const out = [];
  for (const l of lines) {
    const m = l.match(/\bpath\s+(.+?)\s*$/);
    if (!m) continue;
    const rel = m[1].trim();
    out.push(rel.startsWith('/') ? rel : `${base}/${rel}`);
  }
  return out;
}
function _renderSnapshotList(out, target, hit) {
  const c = _storageMaintCtx;
  if (!out || !c) return;
  const names = _parseSnapshotNames(c.kind, target, hit.output);
  if (!names.length) {
    out.textContent = `$ ${hit.cmd}\n\n${hit.output || '(no snapshots)'}`;
    return;
  }
  const rows = names.map(n =>
    `<div class="row-8-center mb-4"><code class="fl-1 ellipsis">${escHtml(n)}</code><button class="btn-icon cell-sm c-red c-danger-outline" data-action="storageDeleteNamedSnapshot" data-arg="${escAttr(n)}" title="Delete this snapshot">${_icon('trash',14)}</button></div>`
  ).join('');
  // If the host truncated the output (very long list), say so + point at the
  // right tool for bulk cleanup rather than implying the list is complete.
  const truncated = /truncated/i.test(hit.output || '');
  let note = '';
  if (truncated) {
    note = `<div class="c-amber mb-8 fs-12"><strong>The list was truncated</strong> — you have more snapshots than shown. For bulk cleanup use the host's snapshot manager (snapper: <code>snapper delete &lt;N&gt;</code> or a timeline-cleanup policy; or <code>zfs destroy</code> with a range), rather than deleting hundreds one by one.</div>`;
  } else if (/\.snapshots\/\d+\/snapshot/.test(hit.output || '')) {
    note = `<div class="hint mb-8 fs-12">These look like <strong>snapper</strong>-managed snapshots — deleting the subvolume reclaims space but leaves snapper's metadata; <code>snapper delete &lt;N&gt;</code> keeps it consistent.</div>`;
  }
  out.innerHTML = `<div class="row-8-center mb-8"><strong>${names.length} snapshot${names.length === 1 ? '' : 's'}</strong> on ${escHtml(c.pool)} — click Delete to remove one (destructive).</div>${note}${rows}`;
}
async function storageDeleteNamedSnapshot(snap) {
  const c = _storageMaintCtx;
  if (!c || !snap) return;
  if (!await uiConfirm(`Permanently DELETE snapshot:\n\n${snap}\n\nThis cannot be undone.`)) return;
  const r = await api('POST', `/devices/${encodeURIComponent(c.deviceId)}/storage-action`,
                      { kind: c.kind, action: c.kind === 'zfs' ? 'destroy' : 'delete', target: c.target, snapshot: snap });
  if (!r || r.error) { toast('Failed: ' + ((r && r.error) || 'unknown'), 'error'); return; }
  toast('Snapshot deletion queued: ' + snap, 'success');
}

