// Perform a guest action then refresh whichever view is showing.

// v3.4.0: LXC delete — type-to-confirm, auto-stop, no purge.
let _lxcDelPending = null;

function lxcDeleteOpen(vmid, name) {
  // Confirm against the hostname when it has one, else the VMID.
  const nm = (name && String(name).trim()) ? String(name).trim() : '';
  const target = nm || String(vmid);
  _lxcDelPending = { vmid, name: nm, target };
  document.getElementById('lxc-del-name').textContent = nm || `(unnamed) ${vmid}`;
  document.getElementById('lxc-del-vmid').textContent = vmid;
  document.getElementById('lxc-del-confirm-target').textContent = target;
  const inp = document.getElementById('lxc-del-confirm');
  inp.value = ''; inp.placeholder = target;
  document.getElementById('lxc-del-result').innerHTML = '';
  document.getElementById('lxc-del-submit').disabled = true;
  openModal('lxc-delete-modal');
  setTimeout(() => inp.focus(), 50);
}

function lxcDelCheck() {
  if (!_lxcDelPending) return;
  const val = (document.getElementById('lxc-del-confirm').value || '').trim();
  document.getElementById('lxc-del-submit').disabled = (val !== _lxcDelPending.target);
}

async function confirmLxcDelete() {
  if (!_lxcDelPending) return;
  const { vmid, name, target } = _lxcDelPending;
  // Defence-in-depth: re-check the typed value before firing.
  if ((document.getElementById('lxc-del-confirm').value || '').trim() !== target) return;
  const result = document.getElementById('lxc-del-result');
  const submit = document.getElementById('lxc-del-submit');
  submit.disabled = true;
  result.innerHTML = `<span class="diag-pending">${_icon('clock',13)} Stopping (if running) and deleting ${vmid}…</span>`;
  const r = await api('DELETE', `/proxmox/lxc/${vmid}`);
  if (r && r.ok) {
    toast(`Container ${vmid}${name ? ' (' + name + ')' : ''} deleted`, 'success');
    closeModal('lxc-delete-modal');
    _lxcDelPending = null;
    setTimeout(() => loadProxmoxLXC(true), 1500);
  } else {
    result.innerHTML = `<span class="c-red">${escHtml((r && r.error) || 'Delete failed')}</span>`;
    submit.disabled = false;
  }
}

// ─── v2.3.0: Proxmox settings save / test ───────────────────────────────

// Collect the Proxmox form fields into a config payload. The token
// secret is only included when the operator typed something — a blank
// field means "keep the saved secret" (same convention as SMTP).



// ═══════════════════════════════════════════════════════════════════════
// v2.4.0 — Proxmox snapshots
//
// A modal listing a guest's snapshots with create / rollback / delete.
// rollback and delete are destructive: rollback requires typing the
// guest name to confirm; delete uses a plain confirm dialog.
// ═══════════════════════════════════════════════════════════════════════

let _snapCtx = null;   // {kind, vmid, name} of the guest whose modal is open

async function openSnapshots(kind, vmid, guestName) {
  _snapCtx = { kind, vmid, name: guestName };
  let modal = document.getElementById('snapshot-modal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'snapshot-modal';
    modal.className = 'modal-overlay';
    modal.innerHTML = `
      <div class="modal isl-581">
        <div class="isl-582">
          <div id="snapshot-modal-title" class="fw-600">Snapshots</div>
          <button class="btn-icon" data-action="closeModal" data-arg="snapshot-modal" >✕</button>
        </div>
        <div class="isl-583">
          <div class="form-group form-group">
            <label class="form-label fs-11">New snapshot name</label>
            <input type="text" id="snapshot-new-name" class="form-input" placeholder="e.g. before_upgrade">
          </div>
          <div class="form-group isl-584">
            <label class="form-label fs-11">Description (optional)</label>
            <input type="text" id="snapshot-new-desc" class="form-input" placeholder="why">
          </div>
          <button class="btn-primary isl-40" data-action="snapshotCreate" >Create</button>
        </div>
        <div id="snapshot-list" class="scroll-cap"></div>
      </div>`;
    document.body.appendChild(modal);
  }
  document.getElementById('snapshot-modal-title').textContent =
    `Snapshots — ${guestName} (${kind.toUpperCase()} ${vmid})`;
  document.getElementById('snapshot-new-name').value = '';
  document.getElementById('snapshot-new-desc').value = '';
  openModal('snapshot-modal');
  loadSnapshots();
}

async function loadSnapshots() {
  if (!_snapCtx) return;
  const list = document.getElementById('snapshot-list');
  list.innerHTML = '<div class="isl-585">Loading…</div>';
  let data;
  try {
    data = await api('GET', `/proxmox/snapshots?type=${_snapCtx.kind}&vmid=${_snapCtx.vmid}`);
  } catch (e) {
    list.innerHTML = `<div class="isl-586">${escHtml(e.message || String(e))}</div>`;
    return;
  }
  const snaps = (data && data.snapshots) || [];
  if (!snaps.length) {
    list.innerHTML = '<div class="isl-585">No snapshots.</div>';
    return;
  }
  list.innerHTML = `<div class="scrollable-table-wrap audit-scroll"><table class="isl-540"><thead>
    <tr class="isl-468">
      <th class="cell-pad">Name</th><th class="cell-pad">Taken</th>
      <th class="cell-pad">Description</th><th></th></tr></thead><tbody>` +
    snaps.map(s => {
      const taken = s.snaptime ? new Date(s.snaptime * 1000).toLocaleString() : '—';
      return `<tr class="border-bottom">
        <td class="isl-587">${escHtml(s.name)}${s.vmstate ? ' <span class="isl-588">+RAM</span>' : ''}</td>
        <td class="isl-545">${taken}</td>
        <td class="isl-545">${escHtml(s.description || '—')}</td>
        <td class="isl-589">
          <button class="btn-icon isl-590" data-action="snapshotRollback" data-arg="${escAttr(s.name)}" >Rollback</button>
          <button class="btn-icon isl-591 c-danger-outline" title="Delete" data-action="snapshotDelete" data-arg="${escAttr(s.name)}" >${_icon('trash',14)}</button>
        </td></tr>`;
    }).join('') + '</tbody></table></div>';
}

async function snapshotCreate() {
  if (!_snapCtx) return;
  const name = document.getElementById('snapshot-new-name').value.trim();
  const desc = document.getElementById('snapshot-new-desc').value.trim();
  if (!name) { toast('Enter a snapshot name', 'error'); return; }
  try {
    await api('POST', '/proxmox/snapshot', {
      type: _snapCtx.kind, vmid: _snapCtx.vmid, action: 'create',
      name: name, description: desc,
    });
    toast('Snapshot creation started', 'success');
    document.getElementById('snapshot-new-name').value = '';
    document.getElementById('snapshot-new-desc').value = '';
    setTimeout(loadSnapshots, 1500);
  } catch (e) {
    toast('Failed: ' + (e.message || String(e)), 'error');
  }
}

async function snapshotRollback(name) {
  if (!_snapCtx) return;
  // Destructive — discards all state since the snapshot. Require the
  // operator to type the guest name to confirm (not just an OK click).
  const typed = await uiPrompt({title: 'Roll back snapshot',
    message: `ROLLBACK is destructive — it discards ALL changes made to "${_snapCtx.name}" since snapshot "${name}" was taken. To confirm, type the guest name exactly:`,
    placeholder: _snapCtx.name, confirmText: 'Roll back', danger: true});
  if (typed === null) return;
  if (typed.trim() !== _snapCtx.name) {
    toast('Name did not match — rollback cancelled', 'error');
    return;
  }
  try {
    await api('POST', '/proxmox/snapshot', {
      type: _snapCtx.kind, vmid: _snapCtx.vmid, action: 'rollback', name: name,
    });
    toast('Rollback started', 'success');
    setTimeout(loadSnapshots, 1500);
  } catch (e) {
    toast('Failed: ' + (e.message || String(e)), 'error');
  }
}

async function snapshotDelete(name) {
  if (!_snapCtx) return;
  if (!await uiConfirm(`Delete snapshot "${name}"?\n\nThis is irreversible, but it ` +
               `does not affect the running guest.`)) return;
  try {
    await api('POST', '/proxmox/snapshot', {
      type: _snapCtx.kind, vmid: _snapCtx.vmid, action: 'delete', name: name,
    });
    toast('Snapshot deleted', 'success');
    setTimeout(loadSnapshots, 1000);
  } catch (e) {
    toast('Failed: ' + (e.message || String(e)), 'error');
  }
}

// ═══════════════════════════════════════════════════════════════════════
// v2.4.2 — SSH preferences + quick SSH link
// ═══════════════════════════════════════════════════════════════════════

// The per-user default SSH username lives in the ui_prefs document
// under the top-level key 'default_ssh_username' (round-tripped by the
// existing _uiPrefs machinery).
function getDefaultSshUsername() {
  const u = _uiPrefs && _uiPrefs.default_ssh_username;
  return (typeof u === 'string') ? u : '';
}

// Populate the Settings field. Called when the Security pane opens.
function loadSshUsername() {
  const el = document.getElementById('cfg-ssh-username');
  if (el) el.value = getDefaultSshUsername();
}

// v3.3.0: save IP allowlist + enabled flag in one POST. Server-side
// guard refuses to enable the allowlist if the caller's own IP would
// be excluded.
// v3.3.0: save Healthchecks.io watchdog config. Empty URL disables.
// v3.14.0: metrics push (Prometheus Pushgateway)
async function loadMetricsPush() {
  const en = document.getElementById('cfg-metrics-push-enabled');
  if (!en) return;
  const d = await api('GET', '/metrics/push/config').catch(() => null);
  if (!d) return;
  en.checked = !!d.enabled;
  const url = document.getElementById('cfg-metrics-push-url');   if (url) url.value = d.url || '';
  const iv  = document.getElementById('cfg-metrics-push-interval'); if (iv) iv.value = d.interval || 60;
  const jb  = document.getElementById('cfg-metrics-push-job');   if (jb) jb.value = d.job || 'remotepower';
  const st  = document.getElementById('metrics-push-status');
  if (st) {
    if (d.last_error) st.textContent = `Last push failed: ${d.last_error}`;
    else if (d.last_push) st.textContent = `Last push ${timeAgo(d.last_push)}${d.last_status ? ` (HTTP ${d.last_status})` : ''}`;
    else st.textContent = d.enabled ? 'Enabled — not pushed yet.' : '';
  }
}
async function saveMetricsPush() {
  const payload = {
    enabled:  document.getElementById('cfg-metrics-push-enabled').checked,
    url:      document.getElementById('cfg-metrics-push-url').value.trim(),
    interval: parseInt(document.getElementById('cfg-metrics-push-interval').value, 10) || 60,
    job:      document.getElementById('cfg-metrics-push-job').value.trim() || 'remotepower',
  };
  const r = await api('PUT', '/metrics/push/config', payload).catch(() => null);
  if (r?.ok) { toast(r.enabled ? `Metrics push enabled (every ${r.interval}s)` : 'Metrics push disabled', 'success'); loadMetricsPush(); }
  else toast((r && r.error) || 'Failed', 'error');
}

// ── v3.14.0 (#27): GitOps — desired-state drift config from a Git repo ──────────
function _gitopsStatusText(d) {
  if (d.last_error) return `Last sync failed: ${d.last_error}`;
  if (d.last_sync) {
    const s = d.last_summary || {};
    const parts = [`+${s.added || 0}`, `~${s.updated || 0}`, `-${s.removed || 0}`].join(' / ');
    return `Last sync ${timeAgo(d.last_sync)} — ${parts} profiles`;
  }
  return d.enabled ? 'Enabled — not synced yet.' : '';
}
async function loadGitops() {
  const en = document.getElementById('cfg-gitops-enabled');
  if (!en) return;
  const d = await api('GET', '/gitops').catch(() => null);
  if (!d) return;
  en.checked = !!d.enabled;
  const url = document.getElementById('cfg-gitops-url');      if (url) url.value = d.url || '';
  const iv  = document.getElementById('cfg-gitops-interval'); if (iv) iv.value = d.interval || 900;
  const au  = document.getElementById('cfg-gitops-auth');
  if (au) au.placeholder = d.auth_header_set ? '•••••••• (saved — leave blank to keep)' : 'leave blank for public repos';
  const st  = document.getElementById('gitops-status');
  if (st) st.textContent = _gitopsStatusText(d);
}
async function saveGitops() {
  const payload = {
    enabled:  document.getElementById('cfg-gitops-enabled').checked,
    url:      document.getElementById('cfg-gitops-url').value.trim(),
    interval: parseInt(document.getElementById('cfg-gitops-interval').value, 10) || 900,
  };
  // Only send the auth header if the operator typed one — blank keeps the stored value.
  const au = document.getElementById('cfg-gitops-auth').value;
  if (au.trim()) payload.auth_header = au.trim();
  const r = await api('PUT', '/gitops', payload).catch(() => null);
  if (r?.ok) {
    document.getElementById('cfg-gitops-auth').value = '';
    toast(r.enabled ? `GitOps enabled (every ${r.interval}s)` : 'GitOps disabled', 'success');
    loadGitops();
  } else toast((r && r.error) || 'Failed', 'error');
}
async function saveBranding() {
  const payload = {
    brand_name: document.getElementById('cfg-brand-name').value.trim(),
    brand_accent: document.getElementById('cfg-brand-accent').value,
  };
  const r = await api('POST', '/config', payload).catch(() => null);
  if (r && r.ok) {
    toast('Branding saved', 'success');
    loadMe();   // re-applies the brand name + default accent immediately
  } else toast((r && r.error) || 'Failed', 'error');
}

async function saveScim() {
  const payload = { scim_enabled: document.getElementById('cfg-scim-enabled').checked };
  const tok = document.getElementById('cfg-scim-token').value;
  if (tok.trim()) payload.scim_token = tok.trim();
  const r = await api('POST', '/config', payload).catch(() => null);
  const reveal = document.getElementById('scim-token-reveal');
  if (r && r.ok) {
    document.getElementById('cfg-scim-token').value = '';
    if (r.scim_token && reveal) {
      reveal.hidden = false;
      reveal.textContent = 'SCIM bearer token (copy it into your IdP now — it will not be shown again):\n\n' + r.scim_token;
    }
    toast(payload.scim_enabled ? 'SCIM enabled' : 'SCIM disabled', 'success');
    loadSettings();
  } else toast((r && r.error) || 'Failed', 'error');
}

async function syncGitops(dry) {
  const st = document.getElementById('gitops-status');
  if (st) st.textContent = dry ? 'Dry run…' : 'Syncing…';
  const r = await api('POST', `/gitops/sync?dry=${dry ? 1 : 0}`).catch(() => null);
  if (r?.ok) {
    const skipped = (r.skipped && r.skipped.length) ? `, ${r.skipped.length} skipped (manual)` : '';
    toast(`${dry ? 'Dry run' : 'Synced'}: +${r.added} new, ${r.updated} updated, ${r.removed} removed${skipped}`, 'success');
    if (!dry) loadGitops();
    else if (st) st.textContent = `Dry run — would: +${r.added} / ~${r.updated} / -${r.removed} profiles`;
  } else toast((r && r.error) || 'Sync failed', 'error');
}

async function saveBlastRadius() {
  const n = parseInt(document.getElementById('cfg-batch-max-devices').value, 10) || 0;
  const p = parseInt(document.getElementById('cfg-batch-max-percent').value, 10) || 0;
  const r = await api('POST', '/config', {batch_max_devices: n, batch_max_fleet_percent: p});
  if (r?.ok) toast((n || p) ? `Guardrail saved (max ${n || '∞'} hosts / ${p || '∞'}% of fleet)` : 'Guardrail disabled', 'success');
  else toast(r?.error || 'Failed', 'error');
}

async function saveHealthchecks() {
  const url      = document.getElementById('cfg-healthchecks-url').value.trim();
  const interval = parseInt(document.getElementById('cfg-healthchecks-interval').value, 10) || 60;
  const r = await api('POST', '/config', {
    healthchecks_url: url,
    healthchecks_interval_seconds: interval,
  });
  if (r?.ok) {
    toast(url ? `Healthchecks watchdog enabled (every ${interval}s)` : 'Healthchecks watchdog disabled', 'success');
  } else {
    toast(r?.error || 'Failed', 'error');
  }
}

async function testHealthchecks() {
  const url = document.getElementById('cfg-healthchecks-url').value.trim();
  if (!url) { toast('Enter a URL first', 'error'); return; }
  // The server will fire the ping the next time the periodic check is
  // due. For an immediate test, fire it client-side as the operator —
  // confirms the URL is reachable from this browser at least.
  try {
    const r = await fetch(url, { method: 'GET', mode: 'no-cors' });
    toast('Test ping sent — check your Healthchecks.io dashboard', 'success');
  } catch (e) {
    toast('Test ping failed: ' + e.message, 'error');
  }
}

async function saveIpAllowlist() {
  const enabled = document.getElementById('cfg-ipal-enabled').checked;
  const raw     = document.getElementById('cfg-ipal-list').value || '';
  const list    = raw.split('\n').map(s => s.trim()).filter(Boolean);
  const r = await api('POST', '/config', {
    ip_allowlist:         list,
    ip_allowlist_enabled: enabled,
  });
  if (r && r.ok) {
    toast(enabled
      ? `IP allowlist enabled (${list.length} entr${list.length === 1 ? 'y' : 'ies'})`
      : 'IP allowlist saved (not enforced — toggle is off)',
      'success');
    loadSecurityDiag();
  } else {
    toast(r?.error || 'Failed to save IP allowlist', 'error');
  }
}

async function saveSshUsername() {
  const el = document.getElementById('cfg-ssh-username');
  if (!el) return;
  const val = el.value.trim();
  // Mirror the server-side rule so the user gets immediate feedback.
  if (val && !/^[A-Za-z0-9._-]{1,32}$/.test(val)) {
    toast('Username may use letters, digits, dot, dash, underscore (max 32)', 'error');
    return;
  }
  if (val) {
    _uiPrefs.default_ssh_username = val;
  } else {
    delete _uiPrefs.default_ssh_username;
  }
  try {
    await api('POST', '/ui-prefs', _uiPrefs);
    toast('SSH username saved', 'success');
  } catch (e) {
    toast('Save failed: ' + (e.message || String(e)), 'error');
  }
}

// Render the quick-SSH icon for a device row. The target host is the
// device's IP when known, else its hostname (the fallback the spec
// asked for). Returns '' when there's neither — nothing to connect to.
function sshLinkIcon(d) {
  const host = (d.ip || '').trim() || (d.hostname || '').trim();
  if (!host) return '';
  // escAttr the host since it goes into an onclick attribute.
  // v3.0.3: explicit color:var(--text) — without it the <a> takes the
  // browser's default link colour (blue), which is hard to read against
  // the dark sidebar/table. var(--text) resolves to near-white in dark
  // mode and near-black in light mode, so the icon stays visible in
  // both themes. The currentColor stroke on the SVG inherits this.
  return ` <a href="#" title="Quick SSH" data-action="quickSsh" data-arg="${escAttr(host)}" data-prevent-default` +
         ` class="isl-592">` +
         `<svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" class="isl-593">` +
         `<polyline points="4 17 10 11 4 5"/><line x1="12" y1="19" x2="20" y2="19"/></svg></a>`;
}

// Quick SSH action. A browser cannot open a terminal itself — it can
// only hand an ssh:// URL to the OS, which works only if the user's
// machine has registered an ssh:// handler (PuTTY, the OS, a terminal
// emulator). So we do BOTH: attempt the ssh:// hand-off, and always
// offer the plain `ssh user@host` string to copy, which works
// everywhere regardless of handler setup.
function quickSsh(host) {
  const user = getDefaultSshUsername();
  if (!user) {
    toast('Set a default SSH username first (Settings → Security → SSH preferences)', 'error');
    return;
  }
  const target = `${user}@${host}`;
  // Best-effort ssh:// hand-off to the OS.
  try {
    window.location.href = `ssh://${encodeURIComponent(user)}@${encodeURIComponent(host)}`;
  } catch (_) { /* no handler — the copy fallback below still helps */ }
  // Always-works fallback: copy the command to the clipboard.
  const cmd = `ssh ${target}`;
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(cmd).then(
      () => toast(`Copied: ${cmd}` , 'success'),
      () => toast(`SSH command: ${cmd}`, 'info'));
  } else {
    toast(`SSH command: ${cmd}`, 'info');
  }
}

// ═══════════════════════════════════════════════════════════════════════
// v2.4.4 — Mailbox monitor configuration (Settings → Mailbox monitor)
//
// Moved here from the device detail view. Pick a device, set its
// mailbox paths and the dashboard-promotion flag, save.
// ═══════════════════════════════════════════════════════════════════════

let _mailwatchOverview = [];   // cached /api/mailwatch result

// Called when the Mailbox monitor settings tab opens. Populates the
// device dropdown and caches current mailbox config.
async function loadMailwatchSettings() {
  const sel = document.getElementById('mailwatch-device');
  if (!sel) return;
  let devs = [], mw = {devices: []};
  try {
    [devs, mw] = await Promise.all([
      api('GET', '/devices'),
      api('GET', '/mailwatch'),
    ]);
  } catch (e) {
    toast('Could not load devices', 'error');
    return;
  }
  _mailwatchOverview = (mw && mw.devices) || [];
  const prev = sel.value;
  sel.innerHTML = '<option value="">— select a device —</option>' +
    (devs || []).map(d =>
      `<option value="${escAttr(d.id)}">${escHtml(d.name || d.id)}</option>`
    ).join('');
  if (prev) { sel.value = prev; loadMailwatchForDevice(); }
}

// Fill the path box + checkbox for the selected device.
function loadMailwatchForDevice() {
  const sel = document.getElementById('mailwatch-device');
  const cfg = document.getElementById('mailwatch-config');
  if (!sel || !cfg) return;
  const devId = sel.value;
  if (!devId) { cfg.style.display = 'none'; return; }
  cfg.style.display = 'block';
  const state = _mailwatchOverview.find(d => d.device_id === devId);
  const paths = (state && state.paths) || [];
  document.getElementById('mailwatch-paths').value = paths.join('\n');
  document.getElementById('mailwatch-dashboard').checked =
    !!(state && state.dashboard);
  document.getElementById('mailwatch-threshold').value =
    (state && state.threshold) ? state.threshold : '';
  // Show the most recent counts, if any have been reported.
  const cur = document.getElementById('mailwatch-current');
  const counts = (state && state.counts) || {};
  const keys = Object.keys(counts);
  if (!keys.length) {
    cur.innerHTML = paths.length
      ? '<div class="hint">No agent report yet — counts appear a few minutes after the agent next heartbeats.</div>'
      : '';
    return;
  }
  cur.innerHTML = '<div class="isl-594">Latest counts</div>' +
    keys.map(p => {
      const info = counts[p] || {};
      let v = '—';
      if (info.error) v = `<span class="c-amber">${escHtml(info.error)}</span>`;
      else if (typeof info.count === 'number') v = `<strong>${info.count}</strong> files`;
      return `<div class="isl-595">
        <code class="fs-11">${escHtml(p)}</code><span>${v}</span></div>`;
    }).join('');
}

async function saveMailwatch() {
  const sel = document.getElementById('mailwatch-device');
  if (!sel || !sel.value) { toast('Select a device first', 'error'); return; }
  const devId = sel.value;
  const paths = document.getElementById('mailwatch-paths').value
    .split('\n').map(s => s.trim()).filter(Boolean);
  const bad = paths.find(p => !p.startsWith('/'));
  if (bad) { toast(`Not an absolute path: ${bad}`, 'error'); return; }
  const dashboard = document.getElementById('mailwatch-dashboard').checked;
  const tRaw = document.getElementById('mailwatch-threshold').value.trim();
  const threshold = tRaw ? parseInt(tRaw, 10) : 0;
  if (tRaw && (!Number.isFinite(threshold) || threshold < 1)) {
    toast('Threshold must be a positive whole number', 'error');
    return;
  }
  try {
    await api('POST', `/devices/${encodeURIComponent(devId)}/mailwatch`,
              {paths: paths, dashboard: dashboard, threshold: threshold});
    toast('Mailbox monitor saved — the agent picks it up on its next heartbeat', 'success');
    loadMailwatchSettings();   // refresh cache
  } catch (e) {
    toast('Save failed: ' + (e.message || String(e)), 'error');
  }
}

// v2.4.5: force an out-of-band package scan. Sets a one-shot flag;
// the device sends a fresh package inventory + patch count within a
// heartbeat or two (it does not happen instantly — the agent has to
// receive the request on its next heartbeat, then report on the one
// after).
async function forcePackageScan(devId, name, btn) {
  // Give immediate visual feedback on the button so the click is confirmed
  const _origText = btn ? btn.textContent : '';
  if (btn) {
    btn.disabled    = true;
    btn.textContent = 'Sending…';
    btn.style.cssText += ';opacity:0.7;cursor:wait';
  }
  try {
    const r = await api('POST', `/devices/${encodeURIComponent(devId)}/scan-packages`, {});
    const ok  = r?.ok || r?.message;
    const msg = r?.message || 'Package scan queued — fresh list within ~60s';
    if (btn) {
      btn.textContent    = ok ? 'Queued' : 'Failed';
      btn.style.color    = ok ? 'var(--green)' : 'var(--red)';
      btn.style.opacity  = '1';
      btn.style.cursor   = 'default';
      btn.disabled       = false;
      setTimeout(() => { if (btn.isConnected) { btn.textContent = _origText; btn.style.color = ''; } }, 4000);
    }
    toast(msg, ok ? 'success' : 'error');
  } catch (e) {
    if (btn) {
      btn.textContent    = '✗ Error';
      btn.style.color    = 'var(--red)';
      btn.style.opacity  = '1';
      btn.style.cursor   = 'default';
      btn.disabled       = false;
      setTimeout(() => { if (btn.isConnected) { btn.textContent = _origText; btn.style.color = ''; } }, 4000);
    }
    toast('Scan request failed: ' + (e.message || String(e)), 'error');
  }
}

// v2.4.7: status endpoint token management.
async function generateStatusToken() {
  if (!await uiConfirm('Generate a status token? Any previous token stops working.')) return;
  try {
    const r = await api('POST', '/status-token', {enabled: true});
    if (r && r.status_token) _renderStatusToken(r.status_token);
    toast('Status token generated', 'success');
  } catch (e) {
    toast('Failed: ' + (e.message || String(e)), 'error');
  }
}

async function revokeStatusToken() {
  if (!await uiConfirm('Disable the status endpoint? External dashboards will stop working.')) return;
  try {
    await api('POST', '/status-token', {enabled: false});
    const box = document.getElementById('status-token-box');
    if (box) box.innerHTML =
      '<button class="btn-primary" data-action="generateStatusToken" >Generate status token</button>';
    toast('Status endpoint disabled', 'success');
  } catch (e) {
    toast('Failed: ' + (e.message || String(e)), 'error');
  }
}

function _renderStatusToken(token) {
  const box = document.getElementById('status-token-box');
  if (!box) return;
  const url = `${location.origin}/api/status?token=${encodeURIComponent(token)}`;
  box.innerHTML = `
    <div class="hint-mb6">Poll this URL from your dashboard tool:</div>
    <input type="text" class="form-input isl-66" readonly value="${escAttr(url)}" data-self-select="1">
    <div class="isl-596">
      <button class="btn-icon" data-action="generateStatusToken" >Rotate token</button>
      <button class="btn-icon c-red" data-action="revokeStatusToken" >Disable endpoint</button>
    </div>`;
}

// v5.1.0: public status page (component groups + incident history) config editor.
let _spComps = [];
let _spDevCache = null;
let _spMonCache = null;

function _spDevName(id) {
  if (_spDevCache) { const d = _spDevCache.find(x => x.id === id); if (d) return d.name || id; }
  return id;
}

function _loadStatusPageInto(data) {
  const sp = (data && data.status_page) || {};
  const en = document.getElementById('cfg-sp-enabled'); if (en) en.checked = !!sp.enabled;
  const ti = document.getElementById('cfg-sp-title'); if (ti) ti.value = sp.title || '';
  const inc = document.getElementById('cfg-sp-incidents'); if (inc) inc.checked = sp.show_incidents !== false;
  const dy = document.getElementById('cfg-sp-days'); if (dy) dy.value = sp.incident_days || 30;
  _spComps = Array.isArray(sp.components) ? sp.components.map(c => ({
    id: c.id || '', name: c.name || '', group: c.group || '',
    device_ids: Array.isArray(c.device_ids) ? c.device_ids.slice() : [],
    monitors: Array.isArray(c.monitors) ? c.monitors.slice() : [],
  })) : [];
  // Prime caches so chips show device names, not ids (best-effort).
  if (!_spDevCache) { _scanDeviceList().then(l => { _spDevCache = l; _renderSpComponents(); }).catch(() => {}); }
  _renderSpComponents();
  _renderSpShare(data);
}

function _renderSpShare(data) {
  const box = document.getElementById('sp-share'); if (!box) return;
  const tok = data && data.status_token;
  if (!tok) { box.textContent = 'Generate a status token above to get a shareable link.'; return; }
  const url = `${location.origin}/status.html?token=${encodeURIComponent(tok)}`;
  box.innerHTML = `<div class="hint-mb6">Share this link:</div><input type="text" class="form-input isl-66" readonly value="${escAttr(url)}" data-self-select="1">`;
}

function _renderSpComponents() {
  const box = document.getElementById('sp-components'); if (!box) return;
  if (!_spComps.length) { box.innerHTML = '<div class="empty-state">No components yet — add one to group devices/monitors.</div>'; return; }
  box.innerHTML = _spComps.map((c, i) => `
    <div class="dash-card mb-16">
      <div class="row-8-center">
        <input type="text" class="form-input sp-name" data-i="${i}" placeholder="Component name" value="${escAttr(c.name)}">
        <input type="text" class="form-input sp-group" data-i="${i}" placeholder="Group (optional)" value="${escAttr(c.group)}">
        <button class="btn-icon c-red c-danger-outline" title="Remove" data-action="spRemoveComponent" data-arg="${i}">${_icon('trash',14)}</button>
      </div>
      <div class="hint-mb6">Devices:</div>
      <div>${c.device_ids.map(d => `<span class="group-badge">${escHtml(_spDevName(d))} <button class="btn-icon" data-action="spRemoveDev" data-arg="${i}" data-arg2="${escAttr(d)}">×</button></span>`).join(' ') || '<span class="hint">none</span>'}</div>
      <input type="text" class="form-input sp-devsearch" data-i="${i}" placeholder="Search devices to add…" autocomplete="off">
      <div class="sp-devres hidden" data-i="${i}"></div>
      <div class="hint-mb6">Monitors:</div>
      <div>${c.monitors.map(m => `<span class="group-badge">${escHtml(m)} <button class="btn-icon" data-action="spRemoveMon" data-arg="${i}" data-arg2="${escAttr(m)}">×</button></span>`).join(' ') || '<span class="hint">none</span>'}</div>
      <input type="text" class="form-input sp-monsearch" data-i="${i}" placeholder="Search monitors to add…" autocomplete="off">
      <div class="sp-monres hidden" data-i="${i}"></div>
    </div>`).join('');
  _wireSpInputs();
}

function _wireSpInputs() {
  document.querySelectorAll('#sp-components .sp-name').forEach(inp => {
    inp.addEventListener('input', () => { _spComps[+inp.dataset.i].name = inp.value; });
  });
  document.querySelectorAll('#sp-components .sp-group').forEach(inp => {
    inp.addEventListener('input', () => { _spComps[+inp.dataset.i].group = inp.value; });
  });
  document.querySelectorAll('#sp-components .sp-devsearch').forEach(inp => {
    const i = +inp.dataset.i;
    inp.addEventListener('input', () => _spDevResults(i, inp.value));
    inp.addEventListener('focus', () => _spDevResults(i, inp.value));
  });
  document.querySelectorAll('#sp-components .sp-monsearch').forEach(inp => {
    const i = +inp.dataset.i;
    inp.addEventListener('input', () => _spMonResults(i, inp.value));
    inp.addEventListener('focus', () => _spMonResults(i, inp.value));
  });
}

async function _spDevResults(i, term) {
  const box = document.querySelector(`#sp-components .sp-devres[data-i="${i}"]`); if (!box) return;
  if (!_spDevCache) { try { _spDevCache = await _scanDeviceList(); } catch (e) { _spDevCache = []; } }
  const q = (term || '').toLowerCase().trim();
  const have = new Set(_spComps[i].device_ids);
  let m = _spDevCache.filter(d => !have.has(d.id));
  if (q) m = m.filter(d => (d.name || '').toLowerCase().includes(q) || (d.ip || '').toLowerCase().includes(q) || (d.group || '').toLowerCase().includes(q));
  m = m.slice(0, 15);
  box.innerHTML = m.length
    ? m.map(d => `<div class="pointer mb-8" data-action="spAddDev" data-arg="${i}" data-arg2="${escAttr(d.id)}"><strong>${escHtml(d.name || d.id)}</strong>${d.ip ? ` <span class="hint">${escHtml(d.ip)}</span>` : ''}</div>`).join('')
    : '<div class="hint">No matching devices.</div>';
  box.classList.remove('hidden');
}

async function _spMonResults(i, term) {
  const box = document.querySelector(`#sp-components .sp-monres[data-i="${i}"]`); if (!box) return;
  if (!_spMonCache) {
    try {
      const r = await api('GET', '/monitors');
      const list = Array.isArray(r) ? r : (r && Array.isArray(r.monitors) ? r.monitors : []);
      _spMonCache = list.map(x => (typeof x === 'string' ? x : (x.label || x.name || x.target || ''))).filter(Boolean);
    } catch (e) { _spMonCache = []; }
  }
  const q = (term || '').toLowerCase().trim();
  const have = new Set(_spComps[i].monitors);
  let m = _spMonCache.filter(lbl => !have.has(lbl));
  if (q) m = m.filter(lbl => lbl.toLowerCase().includes(q));
  m = m.slice(0, 15);
  box.innerHTML = m.length
    ? m.map(lbl => `<div class="pointer mb-8" data-action="spAddMon" data-arg="${i}" data-arg2="${escAttr(lbl)}">${escHtml(lbl)}</div>`).join('')
    : '<div class="hint">No matching monitors.</div>';
  box.classList.remove('hidden');
}

function spAddComponent() { _spComps.push({ id: '', name: '', group: '', device_ids: [], monitors: [] }); _renderSpComponents(); }
function spRemoveComponent(i) { _spComps.splice(+i, 1); _renderSpComponents(); }
function spAddDev(i, id) { i = +i; if (!_spComps[i].device_ids.includes(id)) _spComps[i].device_ids.push(id); _renderSpComponents(); }
function spRemoveDev(i, id) { i = +i; _spComps[i].device_ids = _spComps[i].device_ids.filter(x => x !== id); _renderSpComponents(); }
function spAddMon(i, lbl) { i = +i; if (!_spComps[i].monitors.includes(lbl)) _spComps[i].monitors.push(lbl); _renderSpComponents(); }
function spRemoveMon(i, lbl) { i = +i; _spComps[i].monitors = _spComps[i].monitors.filter(x => x !== lbl); _renderSpComponents(); }

async function saveStatusPage() {
  const comps = _spComps.filter(c => (c.name || '').trim()).map(c => ({
    id: c.id || '', name: c.name.trim(), group: (c.group || '').trim(),
    device_ids: c.device_ids || [], monitors: c.monitors || [],
  }));
  const body = { status_page: {
    enabled: document.getElementById('cfg-sp-enabled').checked,
    title: document.getElementById('cfg-sp-title').value.trim(),
    show_incidents: document.getElementById('cfg-sp-incidents').checked,
    incident_days: Math.max(1, Math.min(90, parseInt(document.getElementById('cfg-sp-days').value, 10) || 30)),
    components: comps,
  } };
  try { await api('POST', '/config', body); toast('Status page saved', 'success'); }
  catch (e) { toast('Failed: ' + (e.message || String(e)), 'error'); }
}

// ── moved to static/js/app-hostconfig.js (v3.13.0 split) ──
// ── v2.8.1: Listening Ports — Monitor page ───────────────────────────────────

let _portsGrouped = [];

async function loadListeningPorts() {
  const el = document.getElementById('ports-container');
  if (!el) return;
  el.innerHTML = '<span class="c-muted-fs13">Loading…</span>';
  const devs = await api('GET', '/devices');
  if (!Array.isArray(devs)) { el.textContent = 'Failed to load'; return; }

  // Telemetry view — include unmonitored hosts (they still report data; only
  // alerting is suppressed). Just needs to be online + agented to have ports.
  const monitored = devs.filter(d => !d.agentless && d.online);
  if (!monitored.length) {
    _portsGrouped = [];
    el.textContent = 'No online devices.';
    return;
  }

  // v3.3.0: batch sysinfo fetch via /api/devices/sysinfo?ids=… (one
  // CGI process instead of N+1). Falls back to empty ports per device
  // if a particular id is missing from the response.
  const idsParam = monitored.map(d => encodeURIComponent(d.id)).join(',');
  const batch = await api('GET', `/devices/sysinfo?ids=${idsParam}`)
    .catch(() => ({ sysinfo: {} }));
  const sysmap = (batch && batch.sysinfo) || {};
  const portData = monitored.map(d => ({
    id: d.id, name: d.name,
    ports: (sysmap[d.id] && sysmap[d.id].listening_ports) || [],
  }));

  const rows = portData.flatMap(d =>
    d.ports.map(p => ({ device: d.name, dev_id: d.id, proto: p.proto||'tcp', port: p.port||0, process: p.process||'' }))
  ).sort((a,b) => a.port - b.port || a.device.localeCompare(b.device));

  if (!rows.length) {
    _portsGrouped = [];
    el.textContent = 'No listening port data yet — agent reports ports with sysinfo (every ~10 min).';
    return;
  }

  // Group by port for fleet-wide view
  const byPort = {};
  for (const r of rows) {
    const key = `${r.proto}/${r.port}`;
    if (!byPort[key]) byPort[key] = { proto: r.proto, port: r.port, hosts: [] };
    byPort[key].hosts.push({ device: r.device, process: r.process });
  }

  _portsGrouped = Object.values(byPort).sort((a,b) => a.port - b.port);
  _renderPortsFiltered();
}

function _renderPortsFiltered() {
  const el = document.getElementById('ports-container');
  if (!el || !_portsGrouped.length) return;
  const q = (document.getElementById('ports-filter')?.value || '').trim().toLowerCase();
  const filtered = q ? _portsGrouped.filter(e => {
    const procs = e.hosts.map(h => h.process).join(' ').toLowerCase();
    const devs  = e.hosts.map(h => h.device).join(' ').toLowerCase();
    return `${e.proto}/${e.port}`.includes(q) || procs.includes(q) || devs.includes(q);
  }) : _portsGrouped;

  if (!filtered.length) {
    el.innerHTML = '<span class="c-muted-fs13">No ports match filter.</span>';
    return;
  }

  // v3.2.1: sortable
  const _sortedFiltered = tableCtl.sortRows('ports', filtered, (e) => {
    const procs = [...new Set(e.hosts.map(h => h.process).filter(Boolean))].join(', ');
    return {
      port: e.port || 0,                            // numeric — sorts by port number
      process: (procs || '').toLowerCase(),
      devices: e.hosts.length,
    };
  });
  const visible = _sortedFiltered.slice(0, 10);
  const hidden  = _sortedFiltered.slice(10);
  el.innerHTML = `
    <div class="table-card">
      <table>
        <thead id="ports-thead"><tr>
          <th data-col="port">Port</th><th data-col="process">Process</th><th data-col="devices">Devices</th>
        </tr></thead>
        <tbody id="ports-table-body">
          ${visible.map(e => {
            const procs = [...new Set(e.hosts.map(h => h.process).filter(Boolean))];
            const devLinks = e.hosts.map(h =>
              `<span class="cmd-badge" title="${escHtml(h.device)}">${escHtml(h.device)}</span>`
            ).join(' ');
            return `<tr>
              <td><code class="fs-12">${escHtml(e.proto)}/${e.port}</code></td>
              <td class="hint">${escHtml(procs.join(', ') || '—')}</td>
              <td class="fs-12">${devLinks}</td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>` +
    (hidden.length ? `<button class="btn-secondary isl-55"
       data-action-btn="_expandPortsFromStore" data-store-key="${_storeEvtData(hidden)}">Show ${hidden.length} more ports</button>` : '');
  // Wire after the DOM is in place — thead is built by innerHTML above
  tableCtl.wireSortOnly('ports-thead', 'ports', _renderPortsFiltered);
}


// ── Top Processes fleet view ──────────────────────────────────────────────────

let _processRows = [];

async function loadProcesses() {
  const tbody = document.getElementById('processes-tbody');
  if (!tbody) return;
  // Wire sort indicators eagerly so the ↕ arrows appear even before data
  // arrives (and in empty / failure states). Other Monitoring tables do
  // the same — keeps the column UX consistent.
  tableCtl.wireSortOnly('processes-thead', 'processes', _renderProcessesFiltered);
  tbody.innerHTML = _skeletonRows(5);
  const devs = await api('GET', '/devices');
  if (!Array.isArray(devs)) { tbody.innerHTML = '<tr><td colspan="5" class="empty-state">Failed to load.</td></tr>'; return; }

  // Telemetry view — include unmonitored hosts (only alerting is suppressed).
  const monitored = devs.filter(d => !d.agentless && d.online);
  if (!monitored.length) {
    _processRows = [];
    tbody.innerHTML = '<tr><td colspan="5" class="empty-state">No online devices.</td></tr>';
    return;
  }

  // v3.3.0: batch sysinfo fetch (one CGI process for N devices).
  const idsParam = monitored.map(d => encodeURIComponent(d.id)).join(',');
  const batch = await api('GET', `/devices/sysinfo?ids=${idsParam}`)
    .catch(() => ({ sysinfo: {} }));
  const sysmap = (batch && batch.sysinfo) || {};
  const procData = monitored.map(d => ({
    id: d.id, name: d.name,
    procs: (sysmap[d.id] && sysmap[d.id].top_processes) || [],
  }));

  _processRows = procData.flatMap(d =>
    d.procs.map(p => ({ device: d.name, dev_id: d.id, name: p.name || '', pid: p.pid || 0, cpu: p.cpu || 0, mem: p.mem || 0 }))
  );

  if (!_processRows.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="empty-state">No process data yet — requires psutil on the agent. Updates every ~60 s.</td></tr>';
    return;
  }
  _renderProcessesFiltered();
}

function _renderProcessesFiltered() {
  const tbody = document.getElementById('processes-tbody');
  if (!tbody) return;
  tableCtl.wireSortOnly('processes-thead', 'processes', _renderProcessesFiltered);
  const q = (document.getElementById('processes-filter')?.value || '').toLowerCase();
  let rows = q ? _processRows.filter(r => r.name.toLowerCase().includes(q) || r.device.toLowerCase().includes(q)) : _processRows;
  rows = tableCtl.sortRows('processes', rows, r => ({ name: r.name.toLowerCase(), pid: r.pid, device: r.device.toLowerCase(), cpu: r.cpu, mem: r.mem }));
  if (!rows.length) { tbody.innerHTML = '<tr><td colspan="5" class="empty-state">No matches.</td></tr>'; return; }
  tbody.innerHTML = rows.map(r => `<tr>
    <td class="fw-500">${escHtml(r.name)}</td>
    <td class="hint">${r.pid}</td>
    <td>${escHtml(r.device)}</td>
    <td class="ta-right">${r.cpu > 0 ? `<span class="${r.cpu > 50 ? 'c-red-bold' : r.cpu > 20 ? 'c-amber' : ''}">${r.cpu.toFixed(1)}%</span>` : '<span class="c-muted">—</span>'}</td>
    <td class="ta-right">${r.mem > 0 ? `<span class="${r.mem > 20 ? 'c-amber' : ''}">${r.mem.toFixed(1)}%</span>` : '<span class="c-muted">—</span>'}</td>
  </tr>`).join('');
}

// ── v2.8.1: Settings → Dashboard personalisation ─────────────────────────────

// v3.2.3: canonical kind list moved server-side (CHANNEL_KINDS in api.py).
// The matrix UI reads /api/dashboard/kinds — no more duplicated arrays here.

async function loadDashboardSettings() {
  const cfg = await api('GET', '/config');
  if (!cfg) return;

  const hiddenAttn = new Set(cfg.dashboard_hidden_attention_kinds || []);
  const hiddenAct  = new Set(cfg.dashboard_hidden_activity_events || []);

  // Brute force settings
  const bfEnabled   = cfg.brute_force_enabled !== false;
  const bfThreshold = cfg.brute_force_threshold || 20;
  const bfWindow    = Math.round((cfg.brute_force_window_seconds || 300) / 60);

  document.getElementById('dash-bf-enabled').checked  = bfEnabled;
  document.getElementById('dash-bf-threshold').value  = bfThreshold;
  document.getElementById('dash-bf-window').value     = bfWindow;

  // v3.4.1: health-score alert threshold (0 = disabled)
  const hat = document.getElementById('health-alert-threshold');
  if (hat) hat.value = parseInt(cfg.health_alert_threshold, 10) || 0;

  // v3.4.1: quiet hours
  const qh = cfg.quiet_hours || {};
  const qhEn = document.getElementById('qh-enabled');
  if (qhEn) qhEn.value = qh.enabled ? '1' : '0';
  if (document.getElementById('qh-start') && qh.start) document.getElementById('qh-start').value = qh.start;
  if (document.getElementById('qh-end') && qh.end) document.getElementById('qh-end').value = qh.end;
  const qhSev = document.getElementById('qh-min-sev');
  if (qhSev && qh.min_severity) qhSev.value = qh.min_severity;

  // v3.4.2: after-hours detection
  const ah = cfg.after_hours || {};
  const ahEn = document.getElementById('ah-enabled');
  if (ahEn) ahEn.value = ah.enabled ? '1' : '0';
  if (document.getElementById('ah-start') && ah.start) document.getElementById('ah-start').value = ah.start;
  if (document.getElementById('ah-end') && ah.end) document.getElementById('ah-end').value = ah.end;
  if (document.getElementById('ah-events')) document.getElementById('ah-events').value = (ah.events || []).join(', ');

  // v3.4.2: on-call + escalation
  const oc = cfg.oncall || {}, es = cfg.escalation || {};
  const setVal = (id, v) => { const e = document.getElementById(id); if (e) e.value = v; };
  setVal('oncall-enabled', oc.enabled ? '1' : '0');
  setVal('oncall-rotation', oc.rotation_days || 7);
  setVal('oncall-contacts', (oc.contacts || []).join(', '));
  setVal('esc-enabled', es.enabled ? '1' : '0');
  setVal('esc-severities', (es.severities || ['critical', 'high']).join(', '));
  setVal('esc-tiers', (es.tiers || []).map(t => t.after_minutes).join(', '));
  setVal('esc-tier-targets', (es.tiers || []).map(t => t.target || '').join(', '));   // v5.4.1 (G2)
  api('GET', '/oncall').then(r => { const e = document.getElementById('oncall-current'); if (e && r) e.textContent = r.current || '(rotation off)'; }).catch(() => {});

  // v3.2.3: channel routing matrix — replaces the two legacy
  // kind/activity panes. Server is the source of truth for the kind
  // roster; we just render the table and POST diffs back.
  loadChannelMatrix();

  // Backup monitors
  renderBackupMonitors(cfg.backup_monitors || []);
  renderProcessWatches(cfg.process_watches || []);
}

// v3.2.3: channel routing matrix. The server is canonical for the kind
// roster (CHANNEL_KINDS in api.py) and the labels for each channel —
// frontend just renders the table and POSTs a single-row diff per click.
const CHANNEL_LABELS = {
  needs_attention: 'Needs Attention',
  recent_activity: 'Recent Activity',
  alerts:          'Alerts',
  webhook:         'Webhook',
};
let _channelMatrixCache = null;

async function loadChannelMatrix() {
  const el = document.getElementById('dash-channel-matrix');
  if (!el) return;
  const data = await api('GET', '/dashboard/kinds');
  if (!data || !data.kinds) {
    el.innerHTML = '<div class="hint">Failed to load channel routing.</div>';
    return;
  }
  _channelMatrixCache = data;
  const channels = data.channels || ['needs_attention', 'recent_activity', 'alerts', 'webhook'];
  // Header
  const head = `<thead><tr>
    <th class="ta-left">Kind</th>
    ${channels.map(c => `<th class="ta-center">${escHtml(CHANNEL_LABELS[c] || c)}</th>`).join('')}
  </tr></thead>`;
  // Group by group field
  const groups = {};
  for (const k of data.kinds) {
    (groups[k.group || 'other'] ||= []).push(k);
  }
  const groupOrder = ['operational', 'informational', 'other'];
  const groupTitle = {operational: 'Operational alerts', informational: 'Informational', other: 'Other'};
  let body = '';
  let first = true;
  for (const g of groupOrder) {
    if (!groups[g]) continue;
    if (!first) {
      body += `<tr><td colspan="${channels.length + 1}">&nbsp;</td></tr>`;
    }
    first = false;
    body += `<tr class="c-muted"><td colspan="${channels.length + 1}" class="fw-500">${escHtml(groupTitle[g] || g)}</td></tr>`;
    for (const k of groups[g]) {
      body += `<tr>
        <td class="fw-500">${escHtml(k.label)}<div class="meta-sm c-muted">${escHtml((k.events || []).join(', '))}</div></td>
        ${channels.map(c => `<td class="ta-center"><input type="checkbox" ${k.channels[c] ? 'checked' : ''} data-change="toggleChannelRoute" data-change-arg="${k.kind}|${c}"></td>`).join('')}
      </tr>`;
    }
  }
  el.innerHTML = `<div class="table-card sticky-head-scroll"><table>${head}<tbody>${body}</tbody></table></div>`;
}

async function toggleChannelRoute(arg, on) {
  // Dispatcher only passes one custom arg, so kind+channel are joined
  // with '|' in the data-change-arg attribute.
  const [kind, channel] = String(arg).split('|');
  if (!kind || !channel || !_channelMatrixCache) return;
  // Optimistic update so the UI feels instant; rollback on failure.
  const row = _channelMatrixCache.kinds.find(k => k.kind === kind);
  if (!row) return;
  const prev = row.channels[channel];
  row.channels[channel] = !!on;
  const payload = {channel_routing: {[kind]: {[channel]: !!on}}};
  const r = await api('POST', '/dashboard/kinds', payload);
  if (!r || !r.ok) {
    row.channels[channel] = prev;
    toast(r?.error || 'Failed to update routing', 'error');
    loadChannelMatrix();
  }
}

async function saveBruteForceSettings() {
  const enabled   = document.getElementById('dash-bf-enabled').checked;
  const threshold = parseInt(document.getElementById('dash-bf-threshold').value, 10);
  const windowMin = parseInt(document.getElementById('dash-bf-window').value, 10);
  const r = await api('POST', '/config', {
    brute_force_enabled:        enabled,
    brute_force_threshold:      threshold,
    brute_force_window_seconds: windowMin * 60,
  });
  if (r?.ok) toast('Brute-force settings saved', 'success');
  else toast(r?.error || 'Failed', 'error');
}

async function saveAfterHours() {
  const enabled = document.getElementById('ah-enabled').value === '1';
  const start = document.getElementById('ah-start').value;
  const end = document.getElementById('ah-end').value;
  const events = document.getElementById('ah-events').value.split(',').map(s => s.trim()).filter(Boolean);
  if (enabled && (!start || !end)) { toast('Set business start and end times', 'error'); return; }
  if (enabled && !events.length) { toast('List at least one event to watch', 'error'); return; }
  const r = await api('POST', '/config', { after_hours: { enabled, start, end, events } }).catch(() => null);
  if (r?.ok) toast(enabled ? `After-hours watch on (${start}–${end})` : 'After-hours watch off', 'success');
  else toast(r?.error || 'Failed', 'error');
}

async function saveOncall() {
  const oncall = {
    enabled: document.getElementById('oncall-enabled').value === '1',
    rotation_days: parseInt(document.getElementById('oncall-rotation').value) || 7,
    contacts: document.getElementById('oncall-contacts').value.split(',').map(s => s.trim()).filter(Boolean),
  };
  const escalation = {
    enabled: document.getElementById('esc-enabled').value === '1',
    severities: document.getElementById('esc-severities').value.split(',').map(s => s.trim().toLowerCase()).filter(Boolean),
    // v5.4.1 (G2): zip the minutes with the aligned per-tier targets BEFORE
    // filtering so position-based targets stay matched to their tier.
    tiers: (() => {
      const mins = document.getElementById('esc-tiers').value.split(',').map(s => parseInt(s.trim()));
      const tgts = (document.getElementById('esc-tier-targets')?.value || '').split(',').map(s => s.trim());
      return mins.map((after_minutes, i) => ({ after_minutes, target: tgts[i] || '' }))
        .filter(t => t.after_minutes > 0)
        .map(t => { const o = { after_minutes: t.after_minutes }; if (t.target) o.target = t.target; return o; });
    })(),
  };
  if (escalation.enabled && !escalation.tiers.length) { toast('Add at least one escalation tier (minutes)', 'error'); return; }
  if (oncall.enabled && !oncall.contacts.length) { toast('Add at least one on-call contact', 'error'); return; }
  const r = await api('POST', '/config', { oncall, escalation }).catch(() => null);
  if (r?.ok) {
    toast('On-call & escalation saved', 'success');
    api('GET', '/oncall').then(rr => { const e = document.getElementById('oncall-current'); if (e && rr) e.textContent = rr.current || '(rotation off)'; }).catch(() => {});
  } else toast(r?.error || 'Failed', 'error');
}

async function saveQuietHours() {
  const enabled = document.getElementById('qh-enabled').value === '1';
  const start = document.getElementById('qh-start').value;
  const end = document.getElementById('qh-end').value;
  const min_severity = document.getElementById('qh-min-sev').value;
  if (enabled && (!start || !end)) { toast('Set both a start and end time', 'error'); return; }
  const r = await api('POST', '/config', { quiet_hours: { enabled, start, end, min_severity } });
  if (r?.ok) toast(enabled ? `Quiet hours ${start}–${end}` : 'Quiet hours off', 'success');
  else toast(r?.error || 'Failed', 'error');
}

async function saveHealthAlertSettings() {
  let threshold = parseInt(document.getElementById('health-alert-threshold').value, 10);
  if (isNaN(threshold) || threshold < 0) threshold = 0;
  threshold = Math.min(100, threshold);
  const r = await api('POST', '/config', { health_alert_threshold: threshold });
  if (r?.ok) toast(threshold ? `Health alerts on: below ${threshold}` : 'Health alerts disabled', 'success');
  else toast(r?.error || 'Failed', 'error');
}

// ── Backup monitors CRUD ──────────────────────────────────────────────────────

let _backupMonitors = [];

// v3.3.0: backup monitor in-place edit. -1 = not editing (Add button
// creates a new entry); ≥0 = the index in _backupMonitors being edited
// (Add button morphs into Save and replaces the row at that index).
let _backupEditIdx = -1;




// ─── v3.14.0 #32: cloud import accounts (AWS EC2) ──────────────────────────
let _cloudAccounts = [];
function renderCloudAccounts(accounts) {
  _cloudAccounts = (accounts || []).map(a => ({ ...a }));
  const el = document.getElementById('cloud-accounts-list');
  if (!el) return;
  if (!_cloudAccounts.length) {
    el.innerHTML = '<div class="isl-616">No cloud accounts configured.</div>';
    return;
  }
  el.innerHTML = _cloudAccounts.map((a, i) => `
    <div class="isl-617">
      <span class="cmd-badge">${escHtml(a.provider || 'aws')}</span>
      <span class="isl-618">${escHtml(a.region || '')}</span>
      <span class="hint"><code>${escHtml(a.access_key_id || '')}</code></span>
      <span class="hint">${a.secret_key_set ? 'secret set' : '<span class="c-red">no secret</span>'}</span>
      <button class="btn-icon c-red" data-action="removeCloudAccount" data-arg="${i}" title="Remove">${_icon('trash',14)}</button>
    </div>`).join('');
}
async function _saveCloudAccounts() {
  // Send provider/region/access_key_id only; the server preserves existing
  // secrets (matched by provider+region+key id) and merges any newly typed one.
  const payload = _cloudAccounts.map(a => ({ provider: a.provider || 'aws',
    region: a.region, access_key_id: a.access_key_id,
    ...(a.secret_key ? { secret_key: a.secret_key } : {}) }));
  return api('POST', '/config', { cloud_accounts: payload });
}
async function addCloudAccount() {
  const region = (document.getElementById('cloud-region')?.value || '').trim();
  const akid = (document.getElementById('cloud-akid')?.value || '').trim();
  const secret = document.getElementById('cloud-secret')?.value || '';
  if (!region || !akid) { toast('Region and access key ID required', 'error'); return; }
  _cloudAccounts.push({ provider: 'aws', region, access_key_id: akid, secret_key: secret, secret_key_set: !!secret });
  const r = await _saveCloudAccounts();
  if (r?.ok) {
    toast('Cloud account added', 'success');
    document.getElementById('cloud-region').value = '';
    document.getElementById('cloud-akid').value = '';
    document.getElementById('cloud-secret').value = '';
    loadSettings();
  } else { _cloudAccounts.pop(); toast(r?.error || 'Failed', 'error'); }
}
async function removeCloudAccount(idx) {
  _cloudAccounts.splice(idx, 1);
  const r = await _saveCloudAccounts();
  if (r?.ok) { renderCloudAccounts(_cloudAccounts); toast('Removed', 'info'); }
  else toast('Failed', 'error');
}
async function runCloudImport() {
  const st = document.getElementById('cloud-import-status');
  if (st) st.textContent = 'Importing…';
  const r = await api('POST', '/cloud/import', {}).catch(() => null);
  if (r?.ok) {
    const msg = `Imported ${r.imported}, updated ${r.updated}` + (r.errors?.length ? `, ${r.errors.length} error(s)` : '');
    if (st) st.textContent = msg;
    toast(msg, r.errors?.length ? 'info' : 'success');
    if (r.errors?.length) console.warn('cloud import errors:', r.errors);
    loadDevices();
  } else { if (st) st.textContent = ''; toast(r?.error || 'Import failed', 'error'); }
}


// ─── v3.14.0 #36: watched-process CPU/memory thresholds ────────────────────
// Same list-editor shape as backup monitors: add/remove rows, each POSTs the
// whole list to /config. Server fires process_alert / process_recovered.
let _processWatches = [];
function renderProcessWatches(watches) {
  _processWatches = watches || [];
  const el = document.getElementById('process-watches-list');
  if (!el) return;
  if (!_processWatches.length) {
    el.innerHTML = '<div class="isl-616">No process thresholds configured.</div>';
    return;
  }
  el.innerHTML = _processWatches.map((w, i) => `
    <div class="isl-617">
      <span class="isl-618"><code>${escHtml(w.name)}</code></span>
      <span class="cmd-badge">${w.metric === 'mem' ? 'Memory' : 'CPU'} ≥ ${escHtml(String(w.threshold))}%</span>
      <button class="btn-icon c-red" data-action="removeProcessWatch" data-arg="${i}" title="Remove">${_icon('trash',14)}</button>
    </div>`).join('');
}

async function addProcessWatch() {
  const name = document.getElementById('pw-name').value.trim();
  const metric = document.getElementById('pw-metric').value === 'mem' ? 'mem' : 'cpu';
  let threshold = parseFloat(document.getElementById('pw-threshold').value);
  if (!name) { toast('Process name required', 'error'); return; }
  if (!(threshold > 0 && threshold <= 100)) threshold = 80;
  _processWatches.push({name, metric, threshold});
  const r = await api('POST', '/config', {process_watches: _processWatches});
  if (r?.ok) {
    toast('Process threshold added', 'success');
    document.getElementById('pw-name').value = '';
    document.getElementById('pw-threshold').value = '80';
    renderProcessWatches(_processWatches);
  } else { _processWatches.pop(); toast(r?.error || 'Failed', 'error'); }
}

async function removeProcessWatch(idx) {
  _processWatches.splice(idx, 1);
  const r = await api('POST', '/config', {process_watches: _processWatches});
  if (r?.ok) { renderProcessWatches(_processWatches); toast('Removed', 'info'); }
  else toast('Failed', 'error');
}

// ══ v2.9.0: Device Drawer ═════════════════════════════════════════════════════
// Full-screen drawer replacing detail-modal + ⋮ dropdown.
// Tabs: "Actions & Settings" and "Audit".
// ══════════════════════════════════════════════════════════════════════════════

let _drawerDeviceId   = null;
let _drawerDeviceName = null;
let _drawerDeviceData = null;          // cached device object from /api/devices
let _drawerAuditLoaded = {};           // which audit sections have been fetched

// ── Open / close ──────────────────────────────────────────────────────────────

async function openDeviceDrawer(id, name, defaultTab = 'actions') {
  // v5.0.1: validate the device id at the boundary — defensive, and a clean
  // sanitizer barrier for static analysis. Device ids are always
  // [A-Za-z0-9_-]{1,64} (server _validate_id); anything else can't be a real
  // device and must never reach a fetch URL or a drawer-panel innerHTML.
  if (typeof id !== 'string' || !/^[A-Za-z0-9_-]{1,64}$/.test(id)) return;
  _drawerDeviceId   = id;
  _drawerDeviceName = name;
  _drawerAuditLoaded = {};

  // Fall back to the id so the header never reads "undefined" when the drawer
  // is opened without a name (e.g. from the command palette). The real name is
  // filled in below once /devices resolves.
  document.getElementById('drawer-device-name').textContent = name || id;
  document.getElementById('drawer-device-sub').textContent  = 'Loading…';

  const drawer = document.getElementById('device-drawer');
  // v5.4.1 (H3): remember the opener + move focus into the drawer so keyboard /
  // screen-reader users land inside it (and get restored on close).
  window._drawerReturnFocus = document.activeElement;
  drawer.classList.add('open');
  document.body.style.overflow = 'hidden';
  setTimeout(() => {
    const f = drawer.querySelector('button:not([disabled]), a[href], input:not([disabled]), select, textarea, [tabindex]:not([tabindex="-1"])');
    (f || drawer).focus();
  }, 0);

  // v4.3.0: deep-linkable drawer — the URL becomes #device/<id> while open,
  // so a device view can be copied/pasted/bookmarked (and webhooks/tickets
  // can link straight to a host). replaceState, not pushState, per the
  // showPage() convention (back-button must not unwind every drawer open).
  try { history.replaceState(null, '', '#device/' + encodeURIComponent(id)); } catch (_) {}

  // Fetch device data for status badge + settings form
  try {
    const devs = await api('GET', '/devices');
    _drawerDeviceData = (devs || []).find(d => d.id === id) || {};
    // Fill the real device name now that we have it (the caller may have
    // passed no name — e.g. the command palette opens with the id only).
    _drawerDeviceName = _drawerDeviceData.name || name || id;
    document.getElementById('drawer-device-name').textContent = _drawerDeviceName;
    const online = _drawerDeviceData.online;
    const status = online ? '● Online' : '○ Offline';
    const color  = online ? 'var(--green)' : 'var(--red)';
    // v5.1.0 #7: path breadcrumb readout (fleet / <group> / <host>)
    const crumb = `<span class="rp-crumb">fleet<i>/</i>${_drawerDeviceData.group ? escHtml(_drawerDeviceData.group) + '<i>/</i>' : ''}<b>${escHtml(_drawerDeviceName)}</b></span>`;
    document.getElementById('drawer-device-sub').innerHTML =
      crumb + ` <span class="isl-401" data-color="${color}">${status}</span>`;
  } catch(e) {
    _drawerDeviceData = {};
    document.getElementById('drawer-device-sub').textContent = '';
  }

  _renderDrawerActions();
  _renderDrawerSettings();
  switchDrawerTab(defaultTab);
}

function closeDeviceDrawer() {
  const drawer = document.getElementById('device-drawer');
  drawer.classList.remove('open');
  document.body.style.overflow = '';
  _drawerDeviceId   = null;
  _drawerDeviceName = null;
  _drawerAuditLoaded = {};
  // Leave the URL on the devices page once the deep-linked drawer closes.
  try {
    if (location.hash.startsWith('#device/')) history.replaceState(null, '', '#devices');
  } catch (_) {}
  // v5.4.1 (H3): restore focus to whatever opened the drawer.
  try { if (window._drawerReturnFocus && window._drawerReturnFocus.focus) window._drawerReturnFocus.focus(); } catch (_) {}
  window._drawerReturnFocus = null;
}

// Close on Escape
document.addEventListener('keydown', e => {
  if (e.key === 'Escape' && _drawerDeviceId) closeDeviceDrawer();
});

// v5.4.1 (H3): trap Tab inside the open device drawer so keyboard focus can't
// wander to the page behind it (matches the modal focus-trap behaviour).
document.addEventListener('keydown', e => {
  if (e.key !== 'Tab') return;
  const drawer = document.getElementById('device-drawer');
  if (!drawer || !drawer.classList.contains('open')) return;
  const vis = Array.from(drawer.querySelectorAll(
    'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])'
  )).filter(el => el.offsetParent !== null);
  if (!vis.length) return;
  const first = vis[0], last = vis[vis.length - 1];
  if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
  else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
});

function switchDrawerTab(tab) {
  // CSP L1 fallout (v3.0.5): the drawer-tab-audit panel has the d-none
  // utility class for its initial-hide; setting style.display = '' to
  // show it only clears the inline attribute and leaves the class
  // hiding the panel. Use explicit 'block' so the inline value beats
  // the class. Same bug pattern as the AI page reveal.
  ['actions', 'audit'].forEach(t => {
    const panel = document.getElementById(`drawer-tab-${t}`);
    if (panel) panel.style.display = (t === tab) ? 'block' : 'none';
    document.getElementById(`drawer-tab-btn-${t}`)?.classList.toggle('active', t === tab);
  });
  if (tab === 'audit' && _drawerDeviceId) _renderDrawerAuditSections();
}

