async function _drawerLoadSnmpConfig(devId) {
  try {
    const r = await api('GET', `/devices/${encodeURIComponent(devId)}/snmp`);
    if (!r) return;
    const cfg = r.config || {};
    const data = r.data || {};
    const en = document.getElementById('ds-snmp-enabled');
    const port = document.getElementById('ds-snmp-port');
    const comm = document.getElementById('ds-snmp-community');
    const status = document.getElementById('ds-snmp-status');
    if (en)   en.checked = !!cfg.enabled;
    if (port) port.value = cfg.port || 161;
    if (comm) comm.placeholder = cfg.has_community
                ? `(keep current — preview: ${cfg.community_preview || '…'})`
                : 'public';
    if (status) {
      if (!cfg.enabled) {
        status.innerHTML = '<span class="c-muted">Disabled</span>';
      } else if (data.last_ok && !data.last_error) {
        status.innerHTML =
          `<span class="snmp-pill snmp-ok">SNMP OK</span> ` +
          `<span class="hint">${_formatTs(data.last_ok)} · sysName ${_escapeHtml(data.sysName || '?')}</span>`;
      } else if (data.last_error) {
        status.innerHTML =
          `<span class="snmp-pill snmp-fail">SNMP fail</span> ` +
          `<span class="hint">${_escapeHtml(data.last_error)}</span>`;
      } else {
        status.innerHTML = '<span class="hint">Enabled, never polled yet — click "Poll now"</span>';
      }
    }
  } catch (_) { /* viewer or transient — leave blank */ }
}

async function _drawerSnmpPollNow() {
  const id = _drawerDeviceId;
  if (!id) return;
  const fb = document.getElementById('ds-snmp-feedback');
  if (fb) fb.innerHTML = '<span class="sev-pill sev-medium">polling</span> Up to 4 s…';
  try {
    const r = await api('POST', `/devices/${encodeURIComponent(id)}/snmp/poll`, {});
    if (!r || !r.ok) {
      if (fb) fb.innerHTML = `<span class="sev-pill sev-critical">error</span> ${_escapeHtml((r && r.error) || 'unknown')}`;
      return;
    }
    if (r.data && r.data.last_ok) {
      if (fb) fb.innerHTML = `<span class="sev-pill sev-success">ok</span> sysName: ${_escapeHtml(r.data.sysName || '?')} · uptime ${r.data.sysUpTime}`;
      _drawerLoadSnmpConfig(id);   // refresh the status block
    } else {
      if (fb) fb.innerHTML = `<span class="sev-pill sev-critical">poll failed</span> ${_escapeHtml(r.data && r.data.last_error || 'unknown error')}`;
    }
  } catch (e) {
    if (fb) fb.innerHTML = `<span class="sev-pill sev-critical">error</span> ${_escapeHtml(e && e.message ? e.message : e)}`;
  }
}

async function _drawerSaveSettings() {
  const id = _drawerDeviceId;
  if (!id) return;

  const group    = document.getElementById('ds-group')?.value.trim() || '';
  const tagsRaw  = document.getElementById('ds-tags')?.value  || '';
  const icon     = document.getElementById('ds-icon')?.value.trim() || '';
  const monitored= document.getElementById('ds-monitored')?.checked;
  const poll     = parseInt(document.getElementById('ds-poll')?.value || '60', 10);
  const svcRaw   = document.getElementById('ds-services')?.value || '';
  const logRaw   = document.getElementById('ds-logrules')?.value || '';
  const driftRaw = document.getElementById('ds-drift')?.value || '';
  const allowRaw = document.getElementById('ds-allowlist')?.value || '';

  const tags     = tagsRaw.split(',').map(s=>s.trim()).filter(Boolean);
  const services = svcRaw.split(',').map(s=>s.trim()).filter(Boolean);
  const driftFiles = driftRaw.split('\n').map(s=>s.trim()).filter(s=>s.startsWith('/'));
  const allowlist  = allowRaw.split('\n').map(s=>s.trim()).filter(Boolean);

  // Parse log rules: "unit : pattern" per line
  const logWatch = logRaw.split('\n').map(l => {
    const [unit, ...rest] = l.split(':');
    return unit && rest.length ? {unit: unit.trim(), pattern: rest.join(':').trim()} : null;
  }).filter(Boolean);

  const _alertDelay = parseInt(document.getElementById('ds-alert-delay')?.value || '0', 10);
  const body = {
    group, tags, icon, monitored,
    poll_interval: Math.max(30, poll),
    offline_alert_delay_min: Math.max(0, Math.min(1440, isNaN(_alertDelay) ? 0 : _alertDelay)),
    watched_services: services,
    log_watch: logWatch,
    watched_files: driftFiles,
    cmd_allowlist: allowlist,
  };

  // v3.3.4: agentless reachability mode + manual up/down (form only shows
  // these for agentless devices).
  const reachEl = document.getElementById('ds-reachability');
  if (reachEl) {
    body.reachability = reachEl.value;
    body.manual_status = !!document.getElementById('ds-manual-status')?.checked;
  }
  // v3.14.0 #48: agentless SSH connection details.
  const sshUserEl = document.getElementById('ds-ssh-user');
  if (sshUserEl) {
    body.ssh_user = sshUserEl.value.trim();
    body.ssh_port = parseInt(document.getElementById('ds-ssh-port')?.value || '22', 10) || 22;
  }
  // v3.14.0 #38: agent release channel (form only shows it for agent devices).
  const chEl = document.getElementById('ds-channel');
  if (chEl) body.update_channel = chEl.value;
  // v3.14.0 #31: per-host opt-in for one-click CIS remediation.
  const remEl = document.getElementById('ds-remediation');
  if (remEl) body.remediation_enabled = remEl.checked;

  const r = await api('POST', `/devices/${id}`, body);
  if (r?.ok) toast('Settings saved', 'success');
  else { toast(r?.error || 'Failed to save', 'error'); return; }

  // v3.2.0 (B5): persist SNMP config too if the form has those inputs.
  // Separate endpoint because SNMP config is on the agentless device
  // record but has its own validation rules (community required when
  // enabled, port range 1..65535).
  const snmpEnabled = document.getElementById('ds-snmp-enabled');
  if (snmpEnabled) {
    const snmpBody = {
      enabled: snmpEnabled.checked,
      port:    parseInt(document.getElementById('ds-snmp-port')?.value || '161', 10),
    };
    const comm = document.getElementById('ds-snmp-community')?.value || '';
    if (comm) snmpBody.community = comm;
    const sr = await api('PATCH', `/devices/${id}/snmp`, snmpBody);
    if (sr?.ok) {
      toast('SNMP config saved', 'success');
      // Refresh the status block so the operator sees the new state
      _drawerLoadSnmpConfig(id);
      const c = document.getElementById('ds-snmp-community');
      if (c) c.value = '';
    } else {
      toast(sr?.error || 'SNMP save failed', 'error');
    }
  }
}

// ── Audit tab ─────────────────────────────────────────────────────────────────

// v3.3.0: audit-section icons now use Lucide SVGs via _icon(name).
// Each section's `icon` is a key from the _ICONS dictionary (defined
// near _renderDrawerActions). New section? Add an _ICONS entry too.
// v3.4.0: sections carry a `group` so the (now 14+) audit panels render in
// labeled bands instead of one long flat scroll. Order within a group is the
// array order; group order is _AUDIT_GROUP_ORDER below.
const _AUDIT_SECTIONS = [
  {key: 'sysinfo',   title: 'System Info',       icon: 'monitor',  group: 'Health'},
  {key: 'metrics',   title: 'Metrics',           icon: 'clock',    group: 'Health'},
  {key: 'hardware',  title: 'Health & Hardware', icon: 'hardDrive',group: 'Health'},
  {key: 'ports',     title: 'Listening Ports',   icon: 'unplug',   group: 'Security'},
  {key: 'firewall',  title: 'Firewall',          icon: 'shield',   group: 'Security'},
  {key: 'cve',       title: 'CVE Summary',       icon: 'sparkles', group: 'Security'},
  {key: 'drift',     title: 'Drift State',       icon: 'search',   group: 'Security'},
  {key: 'packages',  title: 'Packages',          icon: 'package',  group: 'Software'},
  {key: 'containers',title: 'Containers',        icon: 'ship',     group: 'Software'},
  {key: 'helm',      title: 'Helm Releases',     icon: 'cloud',    group: 'Software'},
  {key: 'commands',  title: 'Command History',   icon: 'terminal', group: 'Activity'},
  {key: 'logs',      title: 'Logs',              icon: 'fileCode', group: 'Activity'},
  {key: 'events',    title: 'Fleet Events',      icon: 'radio',    group: 'Activity'},
  {key: 'backups',   title: 'Backups',           icon: 'hardDrive',group: 'System'},
  {key: 'snmp',      title: 'SNMP',              icon: 'radio',    group: 'System'},
  {key: 'hostcfg',   title: 'Host Config',       icon: 'settings', group: 'System'},
];
const _AUDIT_GROUP_ORDER = ['Health', 'Security', 'Software', 'Activity', 'System', 'Integrations'];

function _renderDrawerAuditSections() {
  const el = document.getElementById('drawer-audit-sections');
  if (!el || el.dataset.rendered === _drawerDeviceId) return;
  el.dataset.rendered = _drawerDeviceId;

  // CSP L1 (v3.0.5 fix): the inline `onToggle="…"` attribute was
  // blocked by `script-src 'self'`. <details> has no `data-action`
  // equivalent through the delegated-click handler (toggle isn't a
  // click), so we attach the toggle listener directly after rendering.
  // v3.3.4: RouterOS (MikroTik) card — agentless devices only (that's how
  // routers are added); irrelevant on Linux agent hosts.
  const sections = _AUDIT_SECTIONS.slice();
  if (_drawerDeviceData && _drawerDeviceData.agentless) {
    sections.push({key: 'routeros', title: 'RouterOS (MikroTik)', icon: 'radio',  group: 'Integrations'});
    sections.push({key: 'opnsense', title: 'OPNsense',            icon: 'shield', group: 'Integrations'});
    sections.push({key: 'synology', title: 'Synology (DSM)',      icon: 'server', group: 'Integrations'});
  }
  const _sectionHtml = s =>
    `<details class="audit-section" id="audit-sec-${s.key}" data-audit-key="${s.key}">
      <summary>
        <span>${_icon(s.icon, 14)} ${s.title} <span class="audit-section-badge" id="audit-badge-${s.key}">collapsed</span></span>
      </summary>
      <div class="audit-section-body" id="audit-body-${s.key}">
        <div class="c-muted">Click to load…</div>
      </div>
    </details>`;
  // Render in labeled groups; only emit a group that actually has sections.
  let html = '';
  for (const group of _AUDIT_GROUP_ORDER) {
    const inGroup = sections.filter(s => (s.group || 'System') === group);
    if (!inGroup.length) continue;
    html += `<div class="audit-group-label">${escHtml(group)}</div>`
          + inGroup.map(_sectionHtml).join('');
  }
  el.innerHTML = html;
  // Wire the toggle event for each <details> after innerHTML.
  el.querySelectorAll('details[data-audit-key]').forEach(d => {
    d.addEventListener('toggle', () => _onAuditToggle(d.dataset.auditKey, d));
  });
}

function _onAuditToggle(key, el) {
  if (!el.open) return;
  if (_drawerAuditLoaded[key]) return;   // already loaded
  _drawerAuditLoaded[key] = true;
  _loadAuditSection(key);
}

async function _loadAuditSection(key) {
  const id   = _drawerDeviceId;
  const body = document.getElementById(`audit-body-${key}`);
  const badge= document.getElementById(`audit-badge-${key}`);
  if (!body || !id) return;
  body.innerHTML = '<div class="c-muted">Loading…</div>';

  try {
    switch (key) {

      case 'sysinfo': {
        const data = await api('GET', `/devices/${id}/sysinfo`);
        const si   = data?.sysinfo || {};
        const jrnl = data?.journal || [];
        if (!si.uptime && !jrnl.length) {
          body.innerHTML = '<div class="c-muted">No sysinfo yet — agent reports every ~10 min.</div>';
          return;
        }
        let h = '';
        const pills = [
          ['Uptime',    si.uptime],
          ['Platform',  si.platform],
          // v4.6.0: hardware identity — collected + persisted but previously
          // shown only on the CMDB page; bind it into the drawer too.
          ['CPU model', si.cpu || null],
          ['Kernel',    si.kernel || null],
          ['CPU count', si.cpu_count],
          ['Total RAM', si.mem_total_mb != null
                          ? (Number(si.mem_total_mb) >= 1024
                              ? (Number(si.mem_total_mb) / 1024).toFixed(1) + ' GB'
                              : Number(si.mem_total_mb) + ' MB') : null],
          ['Total disk', si.disk_total_gb != null
                          ? Number(si.disk_total_gb).toFixed(0) + ' GB' : null],
          ['Load avg',  si.loadavg_1m],
          // v3.13.0: surface root-disk and swap pressure as at-a-glance pills
          // (both already in sysinfo; previously only on the devices table).
          ['Disk', si.disk_percent != null ? Number(si.disk_percent).toFixed(1) + '%' : null],
          ['Swap', si.swap_percent != null ? Number(si.swap_percent).toFixed(1) + '%' : null],
          ['Last boot', si.last_boot ? new Date(si.last_boot*1000).toLocaleString() : null],
          // v3.8.0: why the host last restarted (the command before the reboot)
          ['Boot reason', data?.last_boot_reason || null],
          // v3.8.0: who is logged in right now (active login sessions)
          ['Logged in', (si.logged_in||[]).length ? si.logged_in.join(', ') : null],
          // v4.1.0 "VisualMatters": bind the remaining agent signals the Checks
          // page already used but the drawer never showed — at-a-glance per host.
          ['FD usage',  si.fd_percent != null ? Number(si.fd_percent).toFixed(0) + '%' : null],
          ['Conntrack', si.conntrack_percent != null ? Number(si.conntrack_percent).toFixed(0) + '%' : null],
          // v4.4.0: honor the server's threshold-aware `skewed` verdict — a host
          // can be NTP-synced yet beyond the offset threshold (server fires
          // clock_skew); show that instead of a plain "synced".
          ['Clock',     si.clock ? (si.clock.synced === false ? 'NOT synced'
                          : (si.clock.skewed ? 'skewed' : 'synced'))
                          + (si.clock.offset_ms != null ? ` (${si.clock.offset_ms}ms)` : '') : null],
          ['Gateway',   si.gateway ? (si.gateway.reachable === false ? 'unreachable' : 'reachable')
                          + (si.gateway.ip ? ` · ${si.gateway.ip}` : '') : null],
          ['Mail queue', si.mailq != null ? `${si.mailq} queued` : null],
          ['Last OOM',  si.last_oom_ts ? new Date(si.last_oom_ts*1000).toLocaleString()
                          + (si.last_oom_proc ? ` (${si.last_oom_proc})` : '') : null],
        ];
        h += `<div class="sysinfo-row isl-610">` +
          pills.filter(([,v])=>v!=null).map(([l,v])=>
            `<div class="sysinfo-pill"><div class="label">${l}</div><div class="value">${escHtml(String(v))}</div></div>`
          ).join('') + `</div>`;
        if ((si.network||[]).length) {
          h += `<div class="mb-8">` +
            si.network.map(n=>
              `<span class="cmd-badge fs-11">${escHtml(n.iface)}: ${escHtml(n.ip||'?')}${n.mac ? ` · ${escHtml(n.mac)}` : ''}</span> `
            ).join('') + `</div>`;
        }
        // Reboot-required indicator — data already in sysinfo.
        if (si.reboot_required === true) {
          const rebootIco = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14" stroke-linecap="round" stroke-linejoin="round" class="va-middle"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>`;
          h += `<div class="fs-12 mt-8 c-amber">${rebootIco} <strong>Reboot required</strong>${
            si.reboot_reason ? ` <span class="c-muted">(${escHtml(String(si.reboot_reason))})</span>` : ''
          }</div>`;
        }
        // v3.8.0: failed systemd units — now persisted server-side, surface
        // them per-device (also drives the Fleet Query filter + compliance).
        if (Array.isArray(si.failed_units) && si.failed_units.length) {
          const failIco = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14" stroke-linecap="round" stroke-linejoin="round" class="va-middle"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>`;
          h += `<div class="fs-12 mt-8 c-red">${failIco} <strong>${si.failed_units.length} failed unit${si.failed_units.length===1?'':'s'}</strong> ` +
            `<button class="btn-icon cell-sm" data-action="aiDiagnoseUnits" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName)}" data-arg3="${escAttr(si.failed_units.join(','))}" title="AI: diagnose these failed units">${_icon('sparkles',12)} AI diagnose</button></div>` +
            `<div class="mb-8 mt-4 scroll-cap-sm">` + si.failed_units.map(u=>
              `<span class="cmd-badge fs-11">${escHtml(String(u))}</span> `
            ).join('') + `</div>`;
        }
        // v3.12.0: mount-point problems (fstab-vs-mount + stalled NFS/SMB).
        if (Array.isArray(si.mount_issues) && si.mount_issues.length) {
          const mIco = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14" stroke-linecap="round" stroke-linejoin="round" class="va-middle"><path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>`;
          h += `<div class="fs-12 mt-8 c-red">${mIco} <strong>${si.mount_issues.length} mount issue${si.mount_issues.length===1?'':'s'}</strong></div>` +
            `<div class="mb-8 mt-4 scroll-cap-sm">` + si.mount_issues.map(mi=>{
              const stalled = (mi.issue==='stalled');
              return `<span class="cmd-badge fs-11 ${stalled?'c-red':'c-amber'}"><code>${escHtml(mi.path||'?')}</code> — ${stalled?'stalled':'not mounted'}${mi.fstype?` (${escHtml(mi.fstype)})`:''}</span> `;
            }).join('') + `</div>`;
        }
        if ((si.mounts||[]).length) {
          // v3.13.0: network shares (NFS/SMB/CIFS) get a badge + their server,
          // and a stalled share (no usable usage) shows "stalled" not "null%".
          h += `<div class="scrollable-table-wrap audit-scroll"><table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">Mount</th><th>FS</th><th>Used</th><th>Total</th><th>%</th><th class="ta-center">Inode%</th></tr></thead>
            <tbody>` + si.mounts.map(m=>{
              const netBadge = m.network ? ` <span class="pill" data-color="var(--accent)">net</span>` : '';
              // v4.1.0: a silently remounted read-only filesystem is a data-loss
              // outage — surface it as a badge (the agent already reports `ro`).
              const roBadge = m.ro ? ` <span class="pill" data-color="var(--red)">RO</span>` : '';
              // Show the share server inline (not just a tooltip) so an SMB/NFS
              // mount is unmistakable: e.g. "cifs · //192.168.2.100/data".
              const fsCell = escHtml(m.fstype || '—') + (m.network && m.server ? ` · <code>${escHtml(m.server)}</code>` : '');
              if (m.stalled) {
                return `<tr><td class="isl-629"><code>${escHtml(m.path)}</code>${netBadge}${roBadge}</td>
                   <td class="fs-11 c-muted">${fsCell}</td>
                   <td class="ta-center c-muted" colspan="4"><span class="pill" data-color="var(--red)">stalled</span></td></tr>`;
              }
              const pct = (m.percent != null) ? m.percent : null;
              const ino = (m.inode_percent != null) ? m.inode_percent : null;
              return `<tr><td class="isl-629"><code>${escHtml(m.path)}</code>${netBadge}${roBadge}</td>
                   <td class="fs-11 c-muted">${fsCell}</td>
                   <td class="ta-center">${m.used_gb}GB</td>
                   <td class="ta-center">${m.total_gb}GB</td>
                   <td class="isl-630 ${pct>85?'c-red': pct>70?'c-amber': ''}">${pct!=null?pct+'%':'—'}</td>
                   <td class="ta-center ${ino>90?'c-red': ino>80?'c-amber': 'c-muted'}">${ino!=null?ino+'%':'—'}</td></tr>`;
            }).join('') + `</tbody></table></div>`;
        }
        // v3.13.0: per-host storage / RAID health (ZFS / mdadm / btrfs).
        // Previously only on the fleet Storage page — surface this host's own
        // pools/arrays where an operator inspecting one device expects them.
        if (Array.isArray(si.storage_health) && si.storage_health.length) {
          const poolState = (s) => {
            const ok = /online|healthy|active|clean/i.test(s||'');
            const bad = /degraded|faulted|fail|offline|unavail/i.test(s||'');
            const color = bad ? 'var(--red)' : ok ? 'var(--green)' : 'var(--amber)';
            return `<span class="pill" data-color="${color}">${escHtml(s||'—')}</span>`;
          };
          h += `<div class="mt-16 mb-8 fw-500 fs-13">Pools / arrays</div>
            <div class="scrollable-table-wrap audit-scroll">
            <table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">Name</th><th>Kind</th><th>State</th><th class="ta-center">Capacity</th><th>Scrub</th></tr></thead>
            <tbody>` + si.storage_health.map(p=>
              `<tr><td class="isl-629"><code>${escHtml(p.name||'—')}</code></td>
                   <td class="fs-11 c-muted">${escHtml(p.kind||'—')}</td>
                   <td>${poolState(p.state)}</td>
                   <td class="ta-center ${p.capacity>90?'c-red':p.capacity>80?'c-amber':''}">${p.capacity!=null?p.capacity+'%':'—'}</td>
                   <td class="fs-11 c-muted">${escHtml(p.scrub||'—')}</td></tr>`
            ).join('') + `</tbody></table></div>`;
        }
        // Top processes by CPU — data already in sysinfo (top_processes:
        // [{pid,name,cpu,mem}]). Shown fleet-wide on the Processes page; surface
        // a compact view here too.
        if (Array.isArray(si.top_processes) && si.top_processes.length) {
          h += `<div class="mt-16 mb-8 fw-500 fs-13">Top processes</div>
            <table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">PID</th><th>Name</th><th class="ta-center">CPU%</th><th class="ta-center">Mem%</th><th></th></tr></thead>
            <tbody>` + si.top_processes.slice(0, 8).map(p=>
              `<tr><td class="isl-629"><code>${escHtml(String(p.pid != null ? p.pid : '—'))}</code></td>
                   <td>${escHtml(p.name || '—')}</td>
                   <td class="ta-center">${p.cpu != null ? escHtml(String(p.cpu)) : '—'}</td>
                   <td class="ta-center">${p.mem != null ? escHtml(String(p.mem)) : '—'}</td>
                   <td class="ta-center">${(p.pid != null && p.pid > 1) ? `<button class="btn-icon cell-sm" data-action="killProcess" data-arg="${escAttr(id)}" data-arg2="${escAttr(String(p.pid))}" data-arg3="${escAttr(p.name||'')}" title="Send SIGTERM to pid ${escAttr(String(p.pid))}">Kill</button>` : ''}</td></tr>`
            ).join('') + `</tbody></table>`;
        }
        // v3.14.0 #37: per-interface bandwidth (bytes/sec, busiest first). The
        // agent diffs net_io counters between heartbeats; per-process byte
        // accounting isn't portable, so "top talkers" is at interface grain.
        if (Array.isArray(si.network_io) && si.network_io.length) {
          const ifs = si.network_io.slice().sort((a,b)=>
            ((b.rx_bps||0)+(b.tx_bps||0)) - ((a.rx_bps||0)+(a.tx_bps||0)));
          h += `<div class="mt-16 mb-8 fw-500 fs-13">Network bandwidth</div>
            <div class="scrollable-table-wrap audit-scroll">
            <table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">Interface</th><th class="ta-center">↓ In</th><th class="ta-center">↑ Out</th><th class="ta-center">Total recv</th><th class="ta-center">Total sent</th><th class="ta-center" title="Receive / transmit errors">Err</th><th class="ta-center" title="Receive / transmit drops">Drop</th></tr></thead>
            <tbody>` + ifs.map(n=>{
              const errs = (n.rx_err||0)+(n.tx_err||0);
              const drops = (n.rx_drop||0)+(n.tx_drop||0);
              return `<tr><td class="isl-629"><code>${escHtml(n.iface||'—')}</code></td>
                   <td class="ta-center">${_fmtBps(n.rx_bps)}</td>
                   <td class="ta-center">${_fmtBps(n.tx_bps)}</td>
                   <td class="ta-center fs-11 c-muted">${n.rx_total!=null?_fmtBytes(n.rx_total):'—'}</td>
                   <td class="ta-center fs-11 c-muted">${n.tx_total!=null?_fmtBytes(n.tx_total):'—'}</td>
                   <td class="ta-center fs-11 ${errs?'c-red':'c-muted'}">${errs||'0'}</td>
                   <td class="ta-center fs-11 ${drops?'c-amber':'c-muted'}">${drops||'0'}</td></tr>`;
            }).join('') + `</tbody></table></div>`;
        }
        // NTP / chrony sources (peer detail) — name / sync state / stratum / reach.
        if (si.clock && Array.isArray(si.clock.peers) && si.clock.peers.length) {
          h += `<div class="mt-16 mb-8 fw-500 fs-13">NTP sources</div>
            <div class="scrollable-table-wrap audit-scroll"><table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">Source</th><th>State</th><th class="ta-center">Stratum</th><th class="ta-center">Reach</th></tr></thead>
            <tbody>` + si.clock.peers.map(pr=>{
              const st = pr.state||'';
              const col = st==='synced'?'c-green':(st==='unreachable'||st==='falseticker')?'c-red':'c-muted';
              return `<tr><td class="isl-629"><code>${escHtml(pr.name||'—')}</code></td><td class="${col}">${escHtml(st||'—')}</td><td class="ta-center">${escHtml(String(pr.stratum||'—'))}</td><td class="ta-center fs-11 c-muted">${escHtml(String(pr.reach||'—'))}</td></tr>`;
            }).join('') + `</tbody></table></div>`;
        }
        // v3.13.0: systemd timers (scheduled jobs) — failed-first. Data already
        // in sysinfo; the timer_failed event fires off it but the full inventory
        // had no per-device home.
        if (Array.isArray(si.timers) && si.timers.length) {
          const tsorted = si.timers.slice().sort((a,b)=> (b.failed?1:0) - (a.failed?1:0));
          const nFailed = si.timers.filter(t=>t.failed).length;
          h += `<div class="mt-16 mb-8 fw-500 fs-13">Scheduled jobs / timers` +
            (nFailed ? ` <span class="pill" data-color="var(--red)">${nFailed} failed</span>` : '') + `</div>
            <div class="scrollable-table-wrap audit-scroll">
            <table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">Timer</th><th>Activates</th><th class="ta-center">State</th></tr></thead>
            <tbody>` + tsorted.map(t=>
              `<tr><td class="isl-629"><code>${escHtml(t.unit||'—')}</code></td>
                   <td class="fs-11 c-muted">${escHtml(t.activates||'—')}</td>
                   <td class="ta-center">${t.failed?'<span class="pill" data-color="var(--red)">failed</span>':'<span class="c-green">ok</span>'}</td></tr>`
            ).join('') + `</tbody></table></div>`;
        }
        // v3.13.0: access watch — recent logins and distinct source IPs. The
        // login_new_source event fires off this, but the who/from-where table
        // (the highest-value security data on the host) had no UI before.
        if (si.auth && (Array.isArray(si.auth.recent_logins) && si.auth.recent_logins.length)) {
          // Aggregate user → distinct sources + most-recent login time
          // (v4.4.0: the agent now reports a per-login epoch `ts`).
          const byUser = new Map();
          for (const e of si.auth.recent_logins) {
            if (!e || !e.user) continue;
            if (!byUser.has(e.user)) byUser.set(e.user, {srcs: [], lastTs: 0});
            const rec = byUser.get(e.user);
            if (e.source && !rec.srcs.includes(e.source)) rec.srcs.push(e.source);
            const ts = Number(e.ts) || 0;
            if (ts > rec.lastTs) rec.lastTs = ts;
          }
          h += `<div class="mt-16 mb-8 fw-500 fs-13">Access — recent logins</div>
            <div class="scrollable-table-wrap audit-scroll">
            <table class="isl-627">
            <thead><tr class="c-muted"><th class="isl-628">User</th><th>Source IPs (distinct)</th><th>Last seen</th></tr></thead>
            <tbody>` + [...byUser.entries()].map(([u,rec])=>
              `<tr><td class="isl-629"><code>${escHtml(u)}</code></td>
                   <td class="fs-11">${rec.srcs.length ? rec.srcs.map(s=>`<span class="cmd-badge fs-11">${escHtml(s)}</span>`).join(' ') : '<span class="c-muted">—</span>'}</td>
                   <td class="fs-11">${rec.lastTs ? escHtml(new Date(rec.lastTs*1000).toLocaleString()) : '<span class="c-muted">—</span>'}</td></tr>`
            ).join('') + `</tbody></table></div>`;
        }
        if (jrnl.length) {
          h += `<div class="isl-631">Journal — last ${jrnl.length} lines</div>
                <div class="journal-wrap isl-632">${escHtml(jrnl.join('\n'))}</div>`;
        }
        body.innerHTML = h;
        badge.textContent = si.uptime || '';
        // AI investigate buttons
        if (jrnl.length) {
          const aiDiv = document.createElement('div');
          aiDiv.style.cssText = 'display:flex;gap:8px;margin-top:10px;flex-wrap:wrap';
          aiDiv.innerHTML = `
            <button class="btn-secondary fs-12"
              data-action-btn="_aiFindProblemBtn" data-dev-id="${escAttr(id)}" data-journal-sel=".journal-wrap" >
              ${_icon('sparkles',14)} Find the problem
            </button>
            <button class="btn-secondary fs-12"
              data-action="aiInvestigateDevice" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName)}" >
              ${_icon('sparkles',14)} Full investigation
            </button>`;
          body.appendChild(aiDiv);
        }
        break;
      }

      case 'ports': {
        const data = await api('GET', `/devices/${id}/sysinfo`);
        const ports = data?.sysinfo?.listening_ports || [];
        if (!ports.length) {
          body.innerHTML = '<div class="c-muted">No port data yet. Agent reports ports with sysinfo (~10 min).</div>';
          badge.textContent = 'none';
          return;
        }
        // v3.13.0: surface bind address + world/lan/local scope per socket
        // (already on the fleet Exposure page) so single-host inspection shows
        // that e.g. :22 is bound 0.0.0.0/world right here.
        const scopeBadge = (s) => {
          const color = s === 'world' ? 'var(--red)' : s === 'lan' ? 'var(--amber)' : 'var(--muted)';
          return `<span class="pill" data-color="${color}">${escHtml(s || '—')}</span>`;
        };
        body.innerHTML = `
          <input class="audit-filter" placeholder="Filter ports…" data-input="_filterPorts" data-input-el="1" data-input-arg="${id}">
          <div class="scrollable-table-wrap audit-scroll">
          <table class="ports-table isl-633" id="ports-tbl-${id}">
            <thead><tr class="isl-634">
              <th>Proto</th><th>Port</th><th>Address</th><th>Scope</th><th>Process</th>
            </tr></thead>
            <tbody id="ports-body-${id}">
              ${ports.sort((a,b)=>a.port-b.port).map(p=>
                `<tr data-q="${escAttr(`${p.proto} ${p.port} ${p.process||''} ${p.addr||''} ${p.scope||''}`)}">
                  <td><code>${escHtml(p.proto)}</code></td>
                  <td><strong>${p.port}</strong></td>
                  <td class="fs-11 c-muted"><code>${escHtml(p.addr||'—')}</code></td>
                  <td>${scopeBadge(p.scope)}</td>
                  <td class="c-muted">${escHtml(p.process||'—')}</td>
                </tr>`
              ).join('')}
            </tbody>
          </table></div>`;
        badge.textContent = `${ports.length} ports`;
        break;
      }

      case 'firewall': {
        const data = await api('GET', `/devices/${id}/sysinfo`);
        const fw   = data?.sysinfo?.firewall;
        const fwfp = data?.sysinfo?.firewall_fp;
        if (!fw || !(fw.backends || []).length) {
          body.innerHTML = '<div class="c-muted">No firewall data yet. Agents on v3.12.0+ report nftables / iptables / ufw / ebtables posture with sysinfo (~10 min).</div>';
          badge.textContent = 'none';
          return;
        }
        const yes = '<span class="c-green">●</span>';
        const no  = '<span class="c-muted">○</span>';
        const stateCell = (a) => a === true ? `<span class="c-green">active</span>`
          : a === false ? `<span class="c-muted">inactive</span>`
          : `<span class="c-amber" title="The agent couldn't read this ruleset — usually it isn't running as root">unknown</span>`;
        const rows = fw.backends.map(b => {
          const extra = b.policy ? `policy ${escHtml(b.policy)}`
                      : (b.default ? escHtml(b.default) : '—');
          return `<tr>
            <td><code>${escHtml(b.name)}</code></td>
            <td class="ta-center">${b.present ? yes : no}</td>
            <td class="ta-center">${stateCell(b.active)}</td>
            <td class="ta-center">${(b.active === null) ? '—' : (b.rules ?? 0)}</td>
            <td class="c-muted">${extra}</td>
          </tr>`;
        }).join('');
        // Only warn on an EXPLICIT no-firewall (active===false); not when unknown.
        const warn = fw.active === false ?
          `<div class="fs-12 mb-8 c-red"><strong>No active host firewall.</strong> This raises the asset's risk score.</div>`
          : (fw.active === null ? `<div class="fs-12 mb-8 c-amber">Firewall state couldn't be read (the agent may not be running as root). Not counted against risk.</div>` : '');
        // v3.13.0: host firewall fingerprint (the drift baseline the
        // firewall_changed event fires off) — show the active ruleset summary.
        const fpLine = (fwfp && fwfp.backend) ?
          `<div class="fs-12 mb-8 c-muted">Ruleset: <code>${escHtml(fwfp.backend)}</code> · ${fwfp.rules||0} active rule${(fwfp.rules===1)?'':'s'}` +
          (fwfp.fp ? ` · fingerprint <code>${escHtml(String(fwfp.fp).slice(0,12))}</code>` : '') + `</div>`
          : '';
        body.innerHTML = warn + fpLine + `
          <div class="scrollable-table-wrap audit-scroll">
          <table class="ports-table isl-633">
            <thead><tr class="isl-634">
              <th>Backend</th><th class="ta-center">Installed</th><th class="ta-center">State</th><th class="ta-center">Rules</th><th>Default</th>
            </tr></thead>
            <tbody>${rows}</tbody>
          </table></div>`;
        badge.textContent = fw.active === true ? 'active' : fw.active === false ? 'inactive' : 'unknown';
        break;
      }

      case 'packages': {
        const data = await api('GET', `/devices/${id}/sysinfo`);
        const pkg  = data?.sysinfo?.packages || {};
        // v4.6.1 (SECURITY): coerce to a number so a malicious agent can't put
        // markup in `upgradable` and have it land in innerHTML below unescaped.
        const upg  = (typeof pkg.upgradable === 'number') ? pkg.upgradable : '?';
        body.innerHTML = `
          <div class="sysinfo-row isl-610">
            <div class="sysinfo-pill"><div class="label">Manager</div><div class="value">${escHtml(pkg.manager||'unknown')}</div></div>
            <div class="sysinfo-pill"><div class="label">Upgradable</div><div class="value isl-635 ${upg>0?'c-amber':'c-green'}">${upg}</div></div>
            <div class="sysinfo-pill"><div class="label">Last scan</div><div class="value">${data?.sysinfo?.pkg_scan_ts ? timeAgo(data.sysinfo.pkg_scan_ts) : '—'}</div></div>
          </div>
          <button class="btn-secondary fs-12" data-action-btn="_forcePackageScanBtn" data-dev-id="${id}" data-dev-name="${escAttr(_drawerDeviceName)}" >⟳ Scan now</button>`;
        badge.textContent = upg > 0 ? `${upg} upgradable` : 'up to date';
        break;
      }

      case 'logs': {
        const devs = await api('GET', '/devices');
        const dev  = (devs||[]).find(d=>d.id===id) || {};
        const units= Object.keys(dev.journal_units || {});
        if (!units.length) {
          // try fetching from sysinfo endpoint as fallback
          const data = await api('GET', `/devices/${id}/sysinfo`);
          const jrnl = data?.journal || [];
          if (!jrnl.length) {
            body.innerHTML = '<div class="c-muted">No log data yet.</div>';
            return;
          }
          body.innerHTML = `<div class="journal-wrap isl-636">${escHtml(jrnl.join('\n'))}</div>`;
          badge.textContent = `${jrnl.length} lines`;
          return;
        }
        // Fetch all unit logs and let user filter
        const logData = await api('GET', `/logs?device_id=${encodeURIComponent(id)}&limit=100`);
        const entries = logData?.entries || logData?.logs || [];
        badge.textContent = `${entries.length} entries`;
        body.innerHTML = `
          <input class="audit-filter" id="log-filter-${id}" placeholder="Filter by unit or text…"
                 data-input="_filterLogs" data-input-arg="${id}">
          <div id="log-lines-${id}" class="isl-637">
            ${entries.length
              ? entries.map(e=>
                  `<div class="log-line" data-unit="${escAttr(e.unit||'')}" data-line="${escAttr(e.line||e.msg||'')}">
                    <span class="log-unit-badge">${escHtml(e.unit||'—')}</span>
                    <span class="journal-wrap fs-11">${escHtml(e.line||e.msg||'')}</span>
                  </div>`
                ).join('')
              : '<div class="c-muted">No log entries.</div>'}
          </div>`;
        break;
      }

      case 'commands': {
        const data = await api('GET', `/devices/${id}/output`);
        const outputs = (data?.outputs || []).slice().reverse();
        if (!outputs.length) {
          body.innerHTML = '<div class="c-muted">No commands run yet.</div>';
          badge.textContent = 'none';
          return;
        }
        // Show last 5 by default (v2.9.0: collapsed, expand button)
        const recent = outputs.slice(0, 5);
        const older  = outputs.slice(5);
        const renderCmds = (cmds) => cmds.map((o, i) => {
          const rc    = o.rc ?? o.exit_code ?? '?';
          const ts    = o.ts ? new Date(o.ts*1000).toLocaleString() : '';
          const outTxt= o.output || o.stdout || '(no output)';
          return `<div class="audit-cmd-entry" id="cmd-entry-${id}-${i}">
            <div class="audit-cmd-summary" data-action="toggleAuditCmd" data-arg="${id}" data-arg2="${i}">
              <code class="isl-638">${escHtml(o.cmd||'?')}</code>
              <span class="isl-639">rc=${rc} · ${ts}</span>
              <span class="isl-640">▶</span>
            </div>
            <div class="audit-cmd-output">${escHtml(outTxt)}</div>
          </div>`;
        }).join('');
        body.innerHTML = renderCmds(recent) +
          (older.length
            ? `<div id="older-cmds-${id}" class="d-none">${renderCmds(older)}</div>
               <button class="btn-secondary isl-641" data-action="_showOlderCmds" data-arg="${id}" >Show ${older.length} older commands</button>`
            : '');
        badge.textContent = `${outputs.length} commands`;
        break;
      }

      case 'events': {
        const data = await api('GET', `/fleet/events?device_id=${encodeURIComponent(id)}&limit=30`);
        const evs  = Array.isArray(data) ? data : (data?.events || data?.items || []);
        if (!evs.length) {
          body.innerHTML = '<div class="c-muted">No fleet events for this device.</div>';
          badge.textContent = 'none';
          return;
        }
        badge.textContent = `${evs.length}`;
        body.innerHTML = evs.slice(0,30).map(ev => {
          const p = ev.payload || {};
          const cls = EVENT_CLASS[ev.event] || 'info';
          return `<div class="isl-642">
            <span class="activity-dot ${cls}"></span>
            <div class="isl-445">
              <div class="fs-12">${escHtml((ev.event||'').replace(/_/g,' '))}</div>
              <div class="meta-sm-nm">${ev.ts ? timeAgo(ev.ts) : ''}</div>
            </div>
          </div>`;
        }).join('');
        break;
      }

      case 'drift': {
        const data = await api('GET', '/drift');
        const devDrift = (data?.drifts || data || []).find?.(d=>d.device_id===id)
                      || (typeof data==='object' && data[id]) || null;
        if (!devDrift) {
          body.innerHTML = '<div class="c-muted">No drift state for this device.</div>';
          badge.textContent = 'clean';
          return;
        }
        const drifted = devDrift.drifted || devDrift.files || [];
        badge.textContent = drifted.length ? `${drifted.length} changed` : 'clean';
        body.innerHTML = !drifted.length
          ? '<div class="c-green">All watched files at baseline.</div>'
          : drifted.map(f =>
              `<div class="isl-643">
                <code class="c-amber">${escHtml(f.path||f)}</code>
                ${f.changed_at ? `<span class="meta-sm-nm"> · ${timeAgo(f.changed_at)}</span>` : ''}
               </div>`
            ).join('');
        break;
      }

      case 'cve': {
        // Use the per-device endpoint which returns the full findings list
        const data = await api('GET', `/devices/${id}/cve`);
        if (!data || data.error) {
          // Fallback: try fleet summary
          const fleet = await api('GET', '/cve/findings');
          const devCve = (fleet?.devices || []).find(d => d.device_id === id);
          if (!devCve) {
            body.innerHTML = '<div class="c-muted">No CVE data for this device yet.</div>';
            badge.textContent = 'none'; return;
          }
          const c = devCve.counts || {};
          badge.innerHTML = c.critical > 0 ? `<span class="c-red fw-600">${c.critical} critical</span>` : c.high > 0 ? `<span class="c-amber">${c.high} high</span>` : 'clean';
          body.innerHTML = `<div class="sysinfo-row">` +
            ['critical','high','medium','low'].map(s => {
              const n = c[s]||0;
              const vc = n > 0 ? (s === 'critical' ? 'c-red fw-600' : s === 'high' ? 'c-amber' : '') : '';
              return `<div class="sysinfo-pill"><div class="label">${s}</div>
               <div class="value isl-644 ${vc}">${n}</div></div>`;
            }).join('') + '</div>';
          break;
        }
        const findings = data.findings || [];
        // Group by severity — correct accumulation
        const bySev = {};
        for (const f of findings) {
          const sev = f.severity || 'unknown';
          if (!bySev[sev]) bySev[sev] = [];
          bySev[sev].push(f);
        }
        const crit = (bySev.critical||[]).length;
        const high = (bySev.high||[]).length;
        badge.innerHTML = crit > 0 ? `<span class="c-red fw-600">${crit} critical</span>` : high > 0 ? `<span class="c-amber">${high} high</span>` : findings.length ? `${findings.length} total` : 'clean';
        body.innerHTML = `
          <div class="sysinfo-row isl-610">
            ${['critical','high','medium','low'].map(sev => {
              const n = (bySev[sev]||[]).length;
              const vc = n > 0 ? (sev === 'critical' ? 'c-red fw-600' : sev === 'high' ? 'c-amber' : '') : '';
              return `<div class="sysinfo-pill">
                <div class="label">${sev}</div>
                <div class="value isl-645 ${vc}">${n}</div>
              </div>`;
            }).join('')}
          </div>` +
          ['critical','high','medium','low'].filter(s => bySev[s]?.length).map(sev => {
            const col = sev==='critical'?'var(--red)':sev==='high'?'var(--amber)':'var(--muted)';
            return `<div class="mb-6">
              <div class="isl-646" data-color="${col}">${sev}</div>
              ${bySev[sev].slice(0,5).map(f =>
                `<div class="isl-647">
                  <code class="isl-648" data-color="${col}">${escHtml(f.cve_id||f.vuln_id||f.id||'')}</code>
                  <span class="c-muted"> — ${escHtml(f.package||f.pkg||'')} ${escHtml(f.version||'')}</span>
                </div>`).join('')}
              ${bySev[sev].length>5 ? `<div class="meta-sm-nm">…and ${bySev[sev].length-5} more</div>` : ''}
            </div>`;
          }).join('') ||
          '<div class="c-green">No CVEs found.</div>';
        // Cross-feature: CVE findings → a prefilled AI remediation runbook.
        if (crit > 0 || high > 0) {
          const top = (bySev.critical || []).concat(bySev.high || [])
            .map(f => f.cve_id || f.vuln_id || f.id || '').filter(Boolean).slice(0, 6).join(', ');
          const trig = `${_drawerDeviceName} has ${crit} critical and ${high} high CVE finding(s)`
            + (top ? ` (e.g. ${top})` : '') + '. Give me a prioritized, safe remediation runbook.';
          body.insertAdjacentHTML('beforeend',
            `<div class="mt-8"><a class="compliance-fix" data-action="deviceRunbook" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName || '')}" data-arg3="${escAttr(trig)}">${_icon('bookOpen', 13)} Suggest a remediation runbook &rarr;</a></div>`);
        }
        break;
      }

      case 'containers': {
        // Use per-device endpoint — returns {items:[...]} matching containersOpen()
        const data = await api('GET', `/devices/${id}/containers`);
        const ctrs = data?.items || data?.containers || [];
        if (!ctrs.length) {
          body.innerHTML = '<div class="c-muted">No container data for this device.</div>';
          badge.textContent = 'none'; return;
        }
        badge.textContent = `${ctrs.length} container${ctrs.length!==1?'s':''}`;
        // Container age from uptime_seconds (preferred) or started_at (epoch).
        const _fmtDur = (s) => {
          s = Math.max(0, Math.floor(s));
          const d = Math.floor(s / 86400);
          const h = Math.floor((s % 86400) / 3600);
          const m = Math.floor((s % 3600) / 60);
          if (d > 0) return `${d}d ${h}h`;
          if (h > 0) return `${h}h ${m}m`;
          if (m > 0) return `${m}m`;
          return `${s}s`;
        };
        // v3.4.2: health badge + live CPU/mem + published ports — the agent
        // reports all of these; only Name/Status/Image/Age used to render.
        const _healthBadge = (h) => {
          if (!h) return '';
          const cls = h === 'healthy' ? 'c-green' : h === 'unhealthy' ? 'c-red' : 'c-amber';
          return ` <span class="${cls} fs-11">(${escHtml(h)})</span>`;
        };
        const _resCell = (c) => {
          const parts = [];
          if (typeof c.cpu_percent === 'number') parts.push(`${c.cpu_percent.toFixed(1)}% cpu`);
          if (typeof c.mem_percent === 'number') parts.push(`${c.mem_percent.toFixed(1)}% mem`);
          else if (c.mem_usage) parts.push(escHtml(c.mem_usage));
          return parts.length ? parts.join(' · ') : '—';
        };
        // v3.13.0 bind: surface restart_count (the crash-loop signal the
        // server alerts on, container_restart_loop) — previously collected
        // and alerted but never shown in the only table that lists containers.
        const _restartCell = (c) => {
          const rc = c.restart_count;
          if (typeof rc !== 'number') return '<span class="c-muted">—</span>';
          if (rc === 0) return '<span class="c-muted">0</span>';
          const cls = rc >= 5 ? 'c-red' : 'c-amber';
          return `<span class="${cls}" title="restart count">${rc}&times;</span>`;
        };
        // v3.14.0: per-container stale-image badge — the server stamps
        // update_available using the same registry-digest join as the fleet
        // Image Updates page, so the drawer and that page never disagree.
        const _updBadge = (c) => c.update_available
          ? ` <span class="upd-badge" title="A newer image is available in the registry">update</span>`
          : '';
        body.innerHTML = `<div class="scrollable-table-wrap audit-scroll"><table class="isl-649">
          <thead><tr class="c-muted">
            <th class="isl-650">Name</th>
            <th>Status</th><th>Restarts</th><th>Image</th><th>CPU / Mem</th><th>Ports</th><th>Age</th>
          </tr></thead>
          <tbody>
            ${ctrs.map(c => {
              const stat = (c.status || c.State || '').toLowerCase();
              const up   = stat.includes('up ') || stat.includes('running') || stat === 'running';
              const col  = up ? 'var(--green)' : stat.includes('exit') ? 'var(--red)' : 'var(--muted)';
              const img  = (c.image || c.Image || '—').split(':')[0];
              const ports = (c.ports || []).slice(0, 6).map(p => escHtml(p)).join(', ')
                            + ((c.ports || []).length > 6 ? '…' : '');
              let age = '—';
              if (typeof c.uptime_seconds === 'number' && c.uptime_seconds > 0) {
                age = _fmtDur(c.uptime_seconds);
              } else if (typeof c.started_at === 'number' && c.started_at > 0) {
                age = _fmtDur(Math.floor(Date.now() / 1000) - c.started_at);
              }
              const unhealthy = !up || /unhealthy|restart/.test((c.health||'') + ' ' + stat);
              const ctrAi = unhealthy ? ` <button class="btn-icon cell-sm" data-action="aiDiagnoseContainer" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName)}" data-arg3="${escAttr(c.name||c.Names||'?')}" title="AI: diagnose this container">${_icon('sparkles',12)}</button>` : '';
              // v3.14.0: on-demand container log fetch (queues `container:…:logs:…`).
              const cName = c.name || c.Names || '';
              const ctrLogs = cName ? ` <button class="btn-icon cell-sm" data-action="fetchContainerLogs" data-arg="${escAttr(id)}" data-arg2="${escAttr(cName)}" data-arg3="${escAttr(c.runtime||'docker')}" title="Fetch this container's recent logs">${_icon('terminal',12)}</button>` : '';
              return `<tr class="border-top">
                <td class="isl-651"><code>${escHtml(c.name||c.Names||'?')}</code>${_healthBadge(c.health)}${ctrAi}${ctrLogs}</td>
                <td class="isl-652" data-color="${col}">${escHtml(c.status||c.State||'?')}</td>
                <td>${_restartCell(c)}</td>
                <td class="isl-653">${escHtml(img)}${_updBadge(c)}</td>
                <td class="hint">${_resCell(c)}</td>
                <td class="hint mono-12">${ports || '—'}</td>
                <td class="hint">${escHtml(age)}</td>
              </tr>`;
            }).join('')}
          </tbody></table></div>`;
        break;
      }

      case 'metrics': {
        // Read from the devices list which always has fresh sysinfo metrics
        const devs  = await api('GET', '/devices');
        const dev   = (devs || []).find(d => d.id === id);
        const si    = dev?.sysinfo || {};
        const mst   = dev?.metric_state || {};
        const rootM = (si.mounts||[]).find(m => m.path === '/');
        const pairs = [
          ['CPU',    si.cpu_percent,   'cpu:'],
          ['Memory', si.mem_percent,   'memory:'],
          ['Swap',   si.swap_percent,  'swap:'],
          ['Load',   si.loadavg_1m,    'cpu:'],
          ['Disk /', rootM?.percent,   'disk:/'],
        ].filter(([,v]) => v != null && typeof v === 'number');
        if (!pairs.length) {
          body.innerHTML = '<div class="c-muted">No metric data yet — agent needs psutil.</div>';
          badge.textContent = 'none';
          return;
        }
        badge.textContent = 'loaded';
        body.innerHTML = `<div class="sysinfo-row">` +
          pairs.map(([k, v, sk]) => {
            const lv  = mst[sk] || 'ok';
            const col = lv === 'critical' ? 'var(--red)' : lv === 'warning' ? 'var(--amber)' : 'inherit';
            return `<div class="sysinfo-pill">
              <div class="label">${escHtml(k)}</div>
              <div class="value isl-648">${v.toFixed(1)}%</div>
            </div>`;
          }).join('') + `</div>`;
        break;
      }

      case 'snmp': {
        // Inbound traps (independent of polling) — fetch first so they show even
        // when the on-demand deep poll below fails / SNMP polling isn't configured.
        let trapsHtml = '';
        try {
          const _sd = await api('GET', `/devices/${id}/snmp`);
          const _traps = (_sd && _sd.traps) || [];
          if (_traps.length) {
            trapsHtml = `<h4 class="mt-0">Recent inbound traps (${_traps.length})</h4>`
              + `<div class="scrollable-table-wrap audit-scroll"><table class="fs-13">`
              + `<thead><tr class="c-muted"><th>Time</th><th>OID</th><th>Value</th><th>Agent</th></tr></thead><tbody>`
              + _traps.map(t => `<tr><td class="fs-11 c-muted">${new Date((t.ts||0)*1000).toLocaleString()}</td><td><code>${escHtml(t.oid||'—')}</code></td><td>${escHtml(t.value||'—')}</td><td class="fs-11">${escHtml(t.agent||'—')}</td></tr>`).join('')
              + `</tbody></table></div>`;
          }
        } catch (_e) { /* traps best-effort */ }
        // v3.2.0: deep SNMP read — sys-group, ifTable, Host Resources MIB,
        // vendor-specific (Mikrotik). Slower than the standard 5-min poll
        // (multiple round trips), so it's on-demand only.
        let data;
        try {
          data = await api('GET', `/devices/${id}/snmp/deep`);
        } catch (e) {
          body.innerHTML = trapsHtml + `<div class="c-muted ${trapsHtml ? 'mt-12' : ''}">SNMP polling not configured or unreachable.</div>`;
          badge.textContent = trapsHtml ? 'traps' : 'n/a';
          return;
        }
        if (!data || data.error) {
          body.innerHTML = trapsHtml + `<div class="c-red ${trapsHtml ? 'mt-12' : ''}">${escHtml((data && data.error) || 'request failed')}</div>`;
          badge.textContent = 'error';
          return;
        }
        const sysObj = (data.system || {}).sysObjectID || '';
        const isMikrotik = sysObj.startsWith('1.3.6.1.4.1.14988');
        let h = trapsHtml;
        // Sys-group
        if (data.system) {
          h += '<h4 class="mt-0">System</h4><table class="fs-13">';
          for (const [k, v] of Object.entries(data.system)) {
            if (k === '_oids') continue;
            h += `<tr><td class="c-muted-padded">${escHtml(k)}</td><td>${escHtml(String(v ?? '—'))}</td></tr>`;
          }
          h += '</table>';
        }
        // Per-CPU load (hrProcessorTable — Mikrotik + Linux + BSD)
        if (Array.isArray(data.processors) && data.processors.length) {
          h += '<h4 class="mt-12">CPU load (per core)</h4>';
          h += '<div class="sysinfo-row">';
          for (const p of data.processors) {
            const v = p.load_pct;
            const col = (v ?? 0) > 80 ? 'var(--red)' : (v ?? 0) > 50 ? 'var(--amber)' : 'var(--green)';
            h += `<div class="sysinfo-pill">
              <div class="label">CPU ${p.index}</div>
              <div class="value isl-348" data-color="${col}">${v != null ? v + '%' : '—'}</div>
            </div>`;
          }
          h += '</div>';
        }
        // UCD-SNMP load averages + memory (net-snmp boxes)
        if (data.ucd_snmp && Object.keys(data.ucd_snmp).length) {
          const u = data.ucd_snmp;
          h += '<h4 class="mt-12">Load &amp; memory (UCD-SNMP)</h4>';
          if (u.laLoad_1m != null) {
            h += '<div class="sysinfo-row">' +
              `<div class="sysinfo-pill"><div class="label">Load 1m</div><div class="value">${u.laLoad_1m.toFixed(2)}</div></div>` +
              `<div class="sysinfo-pill"><div class="label">Load 5m</div><div class="value">${(u.laLoad_5m ?? 0).toFixed(2)}</div></div>` +
              `<div class="sysinfo-pill"><div class="label">Load 15m</div><div class="value">${(u.laLoad_15m ?? 0).toFixed(2)}</div></div>` +
              '</div>';
          }
          if (u.memTotalReal && u.memAvailReal) {
            const usedKb = u.memTotalReal - u.memAvailReal;
            const usedPct = (usedKb / u.memTotalReal * 100).toFixed(1);
            const col = usedPct > 90 ? 'var(--red)' : usedPct > 75 ? 'var(--amber)' : 'inherit';
            h += `<div class="mt-8 fs-13"><strong>Real memory:</strong> <span data-color="${col}">${(usedKb/1024).toFixed(0)} / ${(u.memTotalReal/1024).toFixed(0)} MB (${usedPct}%)</span></div>`;
          }
          if (u.memTotalSwap && u.memAvailSwap != null) {
            const swapUsedKb = u.memTotalSwap - u.memAvailSwap;
            const swapPct = u.memTotalSwap > 0 ? (swapUsedKb / u.memTotalSwap * 100).toFixed(1) : '0.0';
            h += `<div class="fs-13"><strong>Swap:</strong> ${(swapUsedKb/1024).toFixed(0)} / ${(u.memTotalSwap/1024).toFixed(0)} MB (${swapPct}%)</div>`;
          }
          if (u.ssCpuRawUser != null) {
            h += `<div class="hint mt-4">Raw CPU ticks (deltas tell you %): user=${escHtml(String(u.ssCpuRawUser ?? '?'))} system=${escHtml(String(u.ssCpuRawSystem ?? '?'))} idle=${escHtml(String(u.ssCpuRawIdle ?? '?'))} wait=${escHtml(String(u.ssCpuRawWait ?? '?'))}</div>`;
          }
        }
        // Vendor-specific — Mikrotik
        if (data.mikrotik && Object.keys(data.mikrotik).length) {
          h += '<h4 class="mt-12">Mikrotik vendor</h4><table class="fs-13">';
          const labels = {
            mtxrSystemVersion:  'RouterOS version',
            mtxrSystemUptime:   'Uptime (1/100 s)',
            mtxrHlCoreVoltage:  'Core voltage (mV)',
            mtxrHlTemperature:  'CPU temperature (°C)',
            mtxrHlBoardTemp:    'Board temperature (°C)',
            mtxrHlCpuFrequency: 'CPU frequency (MHz)',
          };
          for (const [k, v] of Object.entries(data.mikrotik)) {
            let display = String(v ?? '—');
            if (k === 'mtxrHlBoardTemp' && typeof v === 'number') display = (v / 10).toFixed(1) + ' °C';
            if (k === 'mtxrHlTemperature' && typeof v === 'number') display = (v / 10).toFixed(1) + ' °C';
            h += `<tr><td class="c-muted-padded">${escHtml(labels[k] || k)}</td><td>${escHtml(display)}</td></tr>`;
          }
          h += '</table>';
        }
        // Vendor-specific — Ubiquiti UniFi
        if (data.ubnt && Object.keys(data.ubnt).length) {
          h += '<h4 class="mt-12">Ubiquiti UniFi</h4><table class="fs-13">';
          const labels = {
            unifiApSystemModel:   'Model',
            unifiApSystemVersion: 'Firmware',
            airosVersion:         'AirOS version',
          };
          for (const [k, v] of Object.entries(data.ubnt)) {
            if (k === 'radios') continue;   // rendered separately
            h += `<tr><td class="c-muted-padded">${escHtml(labels[k] || k)}</td><td>${escHtml(String(v ?? '—'))}</td></tr>`;
          }
          h += '</table>';
          if (Array.isArray(data.ubnt.radios) && data.ubnt.radios.length) {
            h += '<table class="fs-13 mt-8"><thead><tr><th>Radio</th><th class="ta-right">Clients</th></tr></thead><tbody>';
            for (const r of data.ubnt.radios) {
              h += `<tr><td>${escHtml(r.name || `radio${r.index}`)}</td><td class="ta-right">${r.clients ?? 0}</td></tr>`;
            }
            h += '</tbody></table>';
          }
        }
        // Host Resources MIB
        if (data.host_resources && Object.keys(data.host_resources).length) {
          h += '<h4 class="mt-12">Host Resources MIB</h4><table class="fs-13">';
          const labels = {
            hrSystemUptime:     'Uptime (1/100 s)',
            hrSystemNumUsers:   'Logged-in users',
            hrSystemProcesses:  'Running processes',
            hrMemorySize:       'Physical memory (kB)',
          };
          for (const [k, v] of Object.entries(data.host_resources)) {
            h += `<tr><td class="c-muted-padded">${escHtml(labels[k] || k)}</td><td>${escHtml(String(v ?? '—'))}</td></tr>`;
          }
          h += '</table>';
        }
        // Storage table
        if (Array.isArray(data.storage) && data.storage.length) {
          h += '<h4 class="mt-12">Storage</h4><div class="scrollable-table-wrap audit-scroll"><table class="fs-13"><thead><tr><th>Mount</th><th class="ta-right">Size</th><th class="ta-right">Used</th><th class="ta-right">%</th></tr></thead><tbody>';
          for (const s of data.storage) {
            const sizeMb = s.size_bytes ? (s.size_bytes / 1024 / 1024).toFixed(0) : '?';
            const usedMb = s.used_bytes != null ? (s.used_bytes / 1024 / 1024).toFixed(0) : '?';
            const pct = s.used_pct != null ? `${s.used_pct}%` : '—';
            const pctCls = (s.used_pct ?? 0) > 90 ? 'c-red' : (s.used_pct ?? 0) > 70 ? 'c-amber' : '';
            h += `<tr><td>${escHtml(s.descr || '?')}</td><td class="ta-right">${sizeMb} MB</td><td class="ta-right">${usedMb} MB</td><td class="ta-right ${pctCls}">${pct}</td></tr>`;
          }
          h += '</tbody></table></div>';
        }
        // v3.3.4: Synology DSM health (system + disks + RAID/volumes)
        if (data.synology && (data.synology.system || (data.synology.disks||[]).length)) {
          const syn = data.synology;
          const sy = syn.system || {};
          const okBadge = (v) => v === 'normal'
            ? '<span class="status-pill ok">normal</span>'
            : (v ? `<span class="status-pill critical">${escHtml(v)}</span>` : '—');
          h += '<h4 class="mt-12">Synology</h4>';
          h += `<div class="hint mb-6">${escHtml(sy.model || 'Synology')}${sy.dsm_version ? ' · ' + escHtml(sy.dsm_version) : ''}${sy.serial ? ' · ' + escHtml(sy.serial) : ''}</div>`;
          h += '<table class="fs-13"><tbody>';
          h += `<tr><td class="c-muted-padded">System</td><td>${okBadge(sy.system)}</td></tr>`;
          h += `<tr><td class="c-muted-padded">Power</td><td>${okBadge(sy.power)}</td></tr>`;
          h += `<tr><td class="c-muted-padded">Fan</td><td>${okBadge(sy.fan)}</td></tr>`;
          if (sy.temperature_c != null) {
            const tCls = sy.temperature_c > 65 ? 'c-red' : sy.temperature_c > 55 ? 'c-amber' : '';
            h += `<tr><td class="c-muted-padded">Temperature</td><td class="${tCls}">${sy.temperature_c}°C</td></tr>`;
          }
          if (sy.upgrade) h += `<tr><td class="c-muted-padded">DSM update</td><td>${sy.upgrade === 'available' ? '<span class="c-amber">available</span>' : escHtml(sy.upgrade)}</td></tr>`;
          h += '</tbody></table>';
          if ((syn.disks || []).length) {
            h += '<div class="scrollable-table-wrap audit-scroll"><table class="fs-13 mt-6"><thead><tr><th>Disk</th><th>Model</th><th>Status</th><th class="ta-right">Temp</th></tr></thead><tbody>';
            for (const d of syn.disks) {
              const dCls = d.status && d.status !== 'normal' ? 'c-red' : '';
              const dt = d.temperature_c != null ? `${d.temperature_c}°C` : '—';
              h += `<tr><td><strong>${escHtml(d.id || '?')}</strong></td><td class="hint">${escHtml(d.model || '—')}</td><td class="${dCls}">${escHtml(d.status || '—')}</td><td class="ta-right">${dt}</td></tr>`;
            }
            h += '</tbody></table></div>';
          }
          if ((syn.volumes || []).length) {
            h += '<div class="scrollable-table-wrap audit-scroll"><table class="fs-13 mt-6"><thead><tr><th>Volume</th><th>Status</th></tr></thead><tbody>';
            for (const v of syn.volumes) {
              const vCls = v.status && v.status !== 'normal' ? 'c-red' : '';
              h += `<tr><td><strong>${escHtml(v.name || '?')}</strong></td><td class="${vCls}">${escHtml(v.status || '—')}</td></tr>`;
            }
            h += '</tbody></table></div>';
          }
          h += '<div class="hint mt-6">DSM upgrade is in the <strong>Synology (DSM)</strong> section below.</div>';
        }
        // Interface table
        if (Array.isArray(data.interfaces) && data.interfaces.length) {
          h += `<h4 class="mt-12">Interfaces (${data.interfaces.length})</h4>`;
          h += '<div class="scrollable-table-wrap audit-scroll"><table class="fs-13"><thead><tr><th>Name</th><th>Admin</th><th>Oper</th><th class="ta-right">Speed</th><th class="ta-right">In</th><th class="ta-right">Out</th><th class="ta-right">Errs</th></tr></thead><tbody>';
          for (const ifn of data.interfaces) {
            const speedMbps = ifn.speed_bps ? Math.round(ifn.speed_bps / 1e6) + ' Mbps' : '—';
            const upCls = ifn.oper === 'up' ? 'c-green' : 'c-muted';
            const fmtB = (b) => {
              if (!b || b < 1024) return String(b || 0);
              const u = ['B','KB','MB','GB','TB']; let i=0; let v=b;
              while (v >= 1024 && i < u.length-1) { v /= 1024; i++; }
              return v.toFixed(v < 10 ? 1 : 0) + u[i];
            };
            const errs = (ifn.in_errors || 0) + (ifn.out_errors || 0);
            const errCls = errs > 0 ? 'c-amber' : '';
            h += `<tr><td><strong>${escHtml(ifn.descr || `if${ifn.index}`)}</strong></td><td>${escHtml(ifn.admin)}</td><td class="${upCls}">${escHtml(ifn.oper)}</td><td class="ta-right">${speedMbps}</td><td class="ta-right">${fmtB(ifn.in_octets)}</td><td class="ta-right">${fmtB(ifn.out_octets)}</td><td class="ta-right ${errCls}">${errs}</td></tr>`;
          }
          h += '</tbody></table></div>';
        }
        // Errors
        if (data.errors && Object.keys(data.errors).length) {
          h += '<h4 class="mt-12">Partial errors</h4><ul class="hint">';
          for (const [k, v] of Object.entries(data.errors)) {
            h += `<li><code>${escHtml(k)}</code>: ${escHtml(v)}</li>`;
          }
          h += '</ul>';
        }
        const counts = [];
        if (data.interfaces?.length) counts.push(`${data.interfaces.length} if`);
        if (data.processors?.length) counts.push(`${data.processors.length} cpu`);
        if (data.storage?.length)    counts.push(`${data.storage.length} stor`);
        if (data.ucd_snmp && Object.keys(data.ucd_snmp).length) counts.push('ucd');
        if (data.mikrotik && Object.keys(data.mikrotik).length) counts.push('mikrotik');
        if (data.ubnt && Object.keys(data.ubnt).length) counts.push('ubnt');
        if (data.synology && (data.synology.disks || []).length) counts.push(`synology ${data.synology.disks.length}d`);
        else if (data.synology) counts.push('synology');
        badge.textContent = counts.join(' · ') || 'loaded';
        body.innerHTML = h || '<div class="c-muted">No SNMP data returned.</div>';
        break;
      }

      case 'routeros': {
        const data = await api('GET', `/devices/${id}/routeros`);
        _renderRouterosCard(body, badge, data || {});
        break;
      }

      case 'opnsense': {
        const data = await api('GET', `/devices/${id}/opnsense`);
        _renderOpnsenseCard(body, badge, data || {});
        break;
      }

      case 'synology': {
        await _renderSynologyCard(body, badge);
        break;
      }

      case 'hostcfg': {
        const data = await api('GET', `/devices/${id}/host-config`);
        const cfg  = data?.current || data || {};
        if (!cfg || !Object.keys(cfg).length) {
          body.innerHTML = '<div class="c-muted">No host config state collected yet.</div>';
          badge.textContent = 'none';
          return;
        }
        badge.textContent = 'loaded';
        body.innerHTML = `<pre class="isl-654">${escHtml(JSON.stringify(cfg, null, 2))}</pre>`;
        break;
      }

      // v3.4.0: SMART, kernel/livepatch, passive inventory, disk-fill
      // forecast, "what changed", plus on-demand speedtest + LAN discovery.
      case 'hardware': {
        const [hw, fc, ch] = await Promise.all([
          api('GET', `/devices/${id}/hardware`),
          api('GET', `/devices/${id}/forecast`).catch(() => ({})),
          api('GET', `/devices/${id}/changes?days=7`).catch(() => ({})),
        ]);
        body.innerHTML = _renderHardwareSection(id, hw || {}, fc || {}, ch || {});
        const disks = (hw && hw.smart) || [];
        const failed = disks.filter(d => d && d.failed).length;
        badge.textContent = failed ? `${failed} disk alert${failed>1?'s':''}`
                          : (disks.length ? `${disks.length} disk${disks.length>1?'s':''}` : 'no data');
        if (disks.length) {
          tableCtl.wireSortOnly('hw-smart-thead', 'hw_smart',
            () => _loadAuditSectionForce('hardware'));
        }
        break;
      }

      case 'helm': {
        const data = await api('GET', `/devices/${id}/helm`);
        const rels = (data && data.releases) || [];
        if (!rels.length) {
          body.innerHTML = '<div class="c-muted">No Helm releases reported. The agent runs <code>helm list -A</code> when helm + a kubeconfig are present.</div>';
          badge.textContent = 'none';
          break;
        }
        tableCtl.wireSortOnly('helm-thead', 'helm', () => _loadAuditSectionForce('helm'));
        const rows = tableCtl.sortRows('helm', rels, r => ({
          name: r.name, namespace: r.namespace, chart: r.chart,
          appver: r.app_version || '', status: r.status,
          revision: parseInt(r.revision, 10) || 0, updated: r.updated || '',
        }));
        body.innerHTML = `<div class="scrollable-table-wrap audit-scroll"><table class="audit-table">
          <thead id="helm-thead"><tr>
            <th data-col="name">Release</th><th data-col="namespace">Namespace</th>
            <th data-col="chart">Chart</th><th data-col="appver">App version</th>
            <th data-col="status">Status</th>
            <th data-col="revision">Rev</th><th data-col="updated">Updated</th></tr></thead>
          <tbody>` + rows.map(r => {
            const ok = String(r.status).toLowerCase() === 'deployed';
            // helm's `updated` is a long "YYYY-MM-DD HH:MM:SS. ... UTC" string;
            // keep just the date+time for the column.
            const upd = (r.updated || '').split('.')[0].trim();
            return `<tr><td>${escHtml(r.name)}</td><td>${escHtml(r.namespace)}</td>
              <td><code>${escHtml(r.chart)}</code></td>
              <td>${escHtml(r.app_version || '—')}</td>
              <td class="${ok?'c-green':'c-amber'}">${escHtml(r.status)}</td>
              <td class="ta-center">${escHtml(r.revision)}</td>
              <td class="fs-11 c-muted">${escHtml(upd || '—')}</td></tr>`;
          }).join('') + `</tbody></table></div>`;
        badge.textContent = `${rels.length} release${rels.length>1?'s':''}`;
        break;
      }

      case 'backups': {
        // v3.4.2: live backup freshness for this device's watched paths — the
        // ok/age data the heartbeat records (and that fires backup_stale) but
        // never used to be visible per-device.
        const data = await api('GET', `/devices/${id}/backups`);
        const baks = (data && data.backups) || [];
        if (!baks.length) {
          body.innerHTML = '<div class="c-muted">No backup monitors report for this device. Add watched backup paths in <strong>Settings → Advanced → Backup monitors</strong>; the agent reports each path\'s freshness on every heartbeat.</div>';
          badge.textContent = 'none';
          break;
        }
        const stale = baks.filter(b => !b.ok).length;
        const sorted = tableCtl.sortRows('device_backups', baks, b => ({
          label: b.label, age: (b.age_h == null ? Infinity : b.age_h),
          threshold: b.max_age_hours || 0, status: b.ok ? 1 : 0,
          verify: b.verify_status || '',
        }));
        const _fmtAge = h => h == null ? 'missing' : (h >= 48 ? `${(h/24).toFixed(1)}d` : `${h}h`);
        body.innerHTML = `<div class="scrollable-table-wrap audit-scroll"><table class="audit-table">
          <thead id="device-backups-thead"><tr>
            <th data-col="label">Backup</th><th data-col="age">Age</th>
            <th data-col="threshold">Threshold</th><th data-col="status">Status</th>
            <th data-col="verify">Verify</th></tr></thead>
          <tbody>` + sorted.map(b => {
            let vcell = '<td class="fs-11 c-muted">—</td>';
            if (b.verify_enabled) {
              const vs = b.verify_status || 'unknown';
              const vcls = vs === 'ok' ? 'c-green' : (vs === 'failed' || vs === 'timeout' || vs === 'error' || vs === 'unreachable') ? 'c-red' : (vs === 'tool_missing' ? 'c-amber' : 'c-muted');
              const vlbl = vs === 'ok' ? 'verified' : vs;
              vcell = `<td class="${vcls}" title="${escAttr(((b.verify_tool || '') + ' ' + (b.verify_output || '')).trim())}">${escHtml(vlbl)}</td>`;
            }
            return `<tr>
              <td><code>${escHtml(b.label)}</code>${b.label !== b.path ? `<div class="fs-11 c-muted">${escHtml(b.path)}</div>` : ''}</td>
              <td class="${b.ok ? '' : 'c-red'}">${escHtml(_fmtAge(b.age_h))}</td>
              <td class="fs-11 c-muted">≤ ${escHtml(_fmtAge(b.max_age_hours))}</td>
              <td class="${b.ok ? 'c-green' : 'c-red'}">${b.ok ? 'fresh' : 'stale'}</td>${vcell}</tr>`;
          }).join('')
          + `</tbody></table></div>`;
        tableCtl.wireSortOnly('device-backups-thead', 'device_backups', () => _loadAuditSectionForce('backups'));
        badge.textContent = stale ? `${stale} stale` : `${baks.length} fresh`;
        break;
      }

      default:
        body.innerHTML = `<div class="c-muted">Section "${key}" not implemented.</div>`;
    }
  } catch(err) {
    body.innerHTML = `<div class="c-red">Error loading: ${escHtml(String(err))}</div>`;
    if (_drawerAuditLoaded[key]) delete _drawerAuditLoaded[key]; // allow retry
  }
}

// v3.4.0: force a re-render of one audit section (used by sort + after an
// on-demand action completes).
function _loadAuditSectionForce(key) {
  _drawerAuditLoaded[key] = true;
  _loadAuditSection(key);
}

function _fmtDays(d) {
  if (d == null) return '—';
  if (d < 1)   return '<1 day';
  if (d < 60)  return `${Math.round(d)} days`;
  return `${(d/30).toFixed(1)} months`;
}

// The "is this disk failing?" verdict is computed server-side
// (_smart_disk_failed) and delivered as `disk.failed`, so the client never
// re-derives the rule — the front/back copies drifted once (UNKNOWN handling).
function _renderHardwareSection(id, hw, fc, ch) {
  let h = '';
  const k = hw.kernel || {};

  // ── Kernel / livepatch ────────────────────────────────────────────
  if (k.running) {
    const stale = k.reboot_for_kernel;
    h += `<div class="hw-block"><div class="hw-h">Kernel</div>
      <div class="sysinfo-row isl-610">
        <div class="sysinfo-pill"><div class="label">Running</div><div class="value"><code>${escHtml(k.running)}</code></div></div>
        ${k.latest_installed ? `<div class="sysinfo-pill"><div class="label">Newest installed</div><div class="value"><code>${escHtml(k.latest_installed)}</code></div></div>` : ''}
        <div class="sysinfo-pill"><div class="label">Reboot for kernel</div><div class="value ${stale?'c-amber':'c-green'}">${stale ? 'Yes — newer kernel installed' : 'No'}</div></div>
        ${k.livepatch ? `<div class="sysinfo-pill"><div class="label">Livepatch</div><div class="value">${escHtml(k.livepatch.provider||'')} ${k.livepatch.patched?'<span class="c-green">applied</span>':(k.livepatch.state?`<span class="hint">${escHtml(k.livepatch.state)}</span>`:'')}</div></div>` : ''}
      </div></div>`;
  }

  // ── SMART ──────────────────────────────────────────────────────────
  const disks = hw.smart || [];
  if (disks.length) {
    const _uncorr = d => Math.max(d.offline_uncorrectable || 0, d.reported_uncorrect || 0);
    const sorted = tableCtl.sortRows('hw_smart', disks, d => ({
      device: d.device, health: d.health, model: d.model,
      realloc: d.reallocated_sectors || 0, pending: d.pending_sectors || 0,
      crc: (d.crc_errors || 0) + _uncorr(d),
      temp: d.temperature_c || 0, hours: d.power_on_hours || 0,
      wear: d.wear_pct ?? -1,
    }));
    // v3.14.0: project end-of-life from wear rate over power-on hours.
    const _wearEol = (d) => {
      if (d.wear_pct == null || d.wear_pct <= 0 || !d.power_on_hours) return '';
      const yrsLeft = ((100 - d.wear_pct) / d.wear_pct) * (d.power_on_hours / 8760);
      if (!isFinite(yrsLeft) || yrsLeft > 50) return '';
      return yrsLeft < 1 ? `~${Math.round(yrsLeft * 12)} mo left` : `~${yrsLeft.toFixed(1)} yr left`;
    };
    h += `<div class="hw-block"><div class="hw-h">SMART disk health</div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead id="hw-smart-thead"><tr>
        <th data-col="device">Device</th><th data-col="model">Model</th>
        <th data-col="health">Health</th><th data-col="realloc">Realloc</th>
        <th data-col="pending">Pending</th><th data-col="crc" title="CRC errors / uncorrectable sectors — these drive the FAILED verdict">CRC / Unc.</th><th data-col="temp">Temp</th>
        <th data-col="hours">Power-on h</th><th data-col="wear" title="SSD/NVMe wear (used %); projected life from wear rate">Wear</th></tr></thead><tbody>` +
      sorted.map(d => {
        const hUp = String(d.health||'').toUpperCase();
        const healthCls = d.failed ? 'c-red'
          : (hUp === 'PASSED' || hUp === 'OK') ? 'c-green' : 'c-muted';
        const crc = d.crc_errors, unc = _uncorr(d);
        const crcBad = (crc || 0) > 0 || unc > 0;
        const crcCell = (crc == null && !unc) ? '—'
          : `${crc ?? 0}<span class="c-muted"> / </span>${unc}`;
        return `<tr><td><code>${escHtml(d.device)}</code>${d.serial ? `<div class="fs-11 c-muted">sn ${escHtml(d.serial)}</div>` : ''}</td>
          <td>${escHtml(d.model||'—')}</td>
          <td class="${healthCls}">${escHtml(d.health||'?')}</td>
          <td class="ta-center ${(d.reallocated_sectors||0)>0?'c-red':''}">${d.reallocated_sectors??'—'}</td>
          <td class="ta-center ${(d.pending_sectors||0)>0?'c-red':''}">${d.pending_sectors??'—'}</td>
          <td class="ta-center ${crcBad?'c-red':''}">${crcCell}</td>
          <td class="ta-center">${d.temperature_c!=null?d.temperature_c+'°C':'—'}</td>
          <td class="ta-center">${d.power_on_hours??'—'}</td>
          <td class="ta-center ${d.wear_pct>=90?'c-red':d.wear_pct>=80?'c-amber':''}">${d.wear_pct!=null?`${d.wear_pct}%${_wearEol(d)?`<div class="fs-11 c-muted">${_wearEol(d)}</div>`:''}`:'—'}</td></tr>`;
      }).join('') + `</tbody></table></div>`;
    // Cross-feature: a failing disk → a prefilled AI runbook.
    const bad = disks.filter(d => d && d.failed);
    if (bad.length) {
      const trig = `SMART reports a failing/pre-fail disk on ${_drawerDeviceName}: ${bad.map(d=>`${d.device} (${d.health})`).join(', ')}. How do I safely investigate and replace it?`;
      h += `<div class="mt-6"><a class="compliance-fix" data-action="deviceRunbook" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName||'')}" data-arg3="${escAttr(trig)}">${_icon('bookOpen',13)} Get a runbook for this disk &rarr;</a></div>`;
    }
    h += `</div>`;
  }

  // ── v3.14.0: GPUs ──────────────────────────────────────────────────
  const gpus = hw.gpus || [];
  if (gpus.length) {
    h += `<div class="hw-block"><div class="hw-h">GPUs</div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr>
        <th>Name</th><th>Vendor</th><th class="ta-center">Util</th><th class="ta-center">Memory</th><th class="ta-center">Temp</th><th class="ta-center">Power</th></tr></thead><tbody>` +
      gpus.map(g => {
        const mem = (g.mem_used_mb != null && g.mem_total_mb != null) ? `${Math.round(g.mem_used_mb)} / ${Math.round(g.mem_total_mb)} MB` : '—';
        const tcls = g.temp_c >= 85 ? 'c-red' : g.temp_c >= 75 ? 'c-amber' : '';
        return `<tr><td>${escHtml(g.name || 'GPU')}</td><td class="hint">${escHtml(g.vendor || '—')}</td>
          <td class="ta-center">${g.util_pct != null ? g.util_pct + '%' : '—'}</td>
          <td class="ta-center">${mem}</td>
          <td class="ta-center ${tcls}">${g.temp_c != null ? g.temp_c + '°C' : '—'}</td>
          <td class="ta-center">${g.power_w != null ? g.power_w + ' W' : '—'}</td></tr>`;
      }).join('') + `</tbody></table></div></div>`;
  }

  // ── v3.14.0: UPS / power ───────────────────────────────────────────
  const upses = hw.ups || [];
  if (upses.length) {
    h += `<div class="hw-block"><div class="hw-h">UPS / power</div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr>
        <th>UPS</th><th>Status</th><th class="ta-center">Battery</th><th class="ta-center">Load</th><th class="ta-center">Runtime</th><th class="ta-center">Power</th></tr></thead><tbody>` +
      upses.map(u => {
        const onBatt = /OB|BATT/i.test(u.status || '');
        const rt = (typeof u.runtime_s === 'number') ? `${Math.round(u.runtime_s / 60)} min` : '—';
        return `<tr>
          <td><code>${escHtml(u.name || 'UPS')}</code> <span class="hint">${escHtml(u.driver || '')}</span></td>
          <td class="${onBatt ? 'c-red fw-600' : 'c-green'}">${escHtml(u.status || '—')}</td>
          <td class="ta-center ${(u.battery_pct != null && u.battery_pct < 50) ? 'c-amber' : ''}">${u.battery_pct != null ? u.battery_pct + '%' : '—'}</td>
          <td class="ta-center">${u.load_pct != null ? u.load_pct + '%' : '—'}</td>
          <td class="ta-center">${rt}</td>
          <td class="ta-center">${u.power_w != null ? u.power_w + ' W' : '—'}</td></tr>`;
      }).join('') + `</tbody></table></div></div>`;
  }

  // ── v3.14.0: Local accounts ────────────────────────────────────────
  const accts = hw.accounts || [];
  if (accts.length) {
    const flagged = accts.filter(a => (a.flags || []).length);
    const sorted = [...accts].sort((a, b) => ((b.flags || []).length) - ((a.flags || []).length) || (a.uid - b.uid));
    const flabel = { uid0: 'extra UID 0', empty_password: 'empty password', stale_password: 'stale password' };
    h += `<div class="hw-block"><div class="hw-h">Local accounts${flagged.length ? ` — <span class="c-amber">${flagged.length} flagged</span>` : ''}</div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr>
        <th>User</th><th class="ta-center">UID</th><th>Shell</th><th class="ta-center">Login</th><th class="ta-center">Pw age</th><th>Flags</th></tr></thead><tbody>` +
      sorted.map(a => {
        const fl = (a.flags || []).filter(f => f !== 'sudo').map(f => `<span class="kev-badge" title="${escAttr(flabel[f] || f)}">${escHtml(flabel[f] || f)}</span>`).join(' ');
        const sudo = a.sudo ? '<span class="epss-chip">sudo</span>' : '';
        const login = a.login ? (a.locked ? '<span class="c-muted">locked</span>' : '<span class="c-green">yes</span>') : '<span class="c-muted">no</span>';
        return `<tr><td><code>${escHtml(a.user)}</code></td>
          <td class="ta-center ${a.uid === 0 ? 'c-red' : ''}">${a.uid}</td>
          <td class="hint mono-12">${escHtml(a.shell || '—')}</td>
          <td class="ta-center">${login}</td>
          <td class="ta-center hint">${a.age_days != null ? a.age_days + 'd' : '—'}</td>
          <td>${fl} ${sudo}</td></tr>`;
      }).join('') + `</tbody></table></div></div>`;
  }

  // ── v3.14.0: Local certificate files ───────────────────────────────
  const certFiles = hw.cert_files || [];
  if (certFiles.length) {
    const nowS = Date.now() / 1000;
    const sorted = [...certFiles].sort((a, b) => (a.not_after || 0) - (b.not_after || 0));
    h += `<div class="hw-block"><div class="hw-h">Local certificate files</div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr>
        <th>Path</th><th>Subject</th><th>Issuer</th><th class="ta-center">Expires</th></tr></thead><tbody>` +
      sorted.map(c => {
        const days = c.not_after ? Math.floor((c.not_after - nowS) / 86400) : null;
        const cls = days == null ? '' : (days < 14 ? 'c-red' : days < 45 ? 'c-amber' : '');
        const exp = days == null ? '—' : (days < 0 ? 'expired' : `${days}d`);
        return `<tr><td class="mono-12">${escHtml(c.path)}</td>
          <td class="hint">${escHtml(c.subject || '—')}</td>
          <td class="hint">${escHtml(c.issuer || '—')}</td>
          <td class="ta-center ${cls}">${exp}</td></tr>`;
      }).join('') + `</tbody></table></div></div>`;
  }

  // ── Forecast ───────────────────────────────────────────────────────
  const mounts = (fc && fc.mounts) || [];
  const risers = mounts.filter(m => m.days_to_full != null);
  if (risers.length) {
    h += `<div class="hw-block"><div class="hw-h">Disk-fill forecast <span class="c-muted fs-11">(${fc.sample_days||0} daily samples)</span></div>
      <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr>
        <th>Mount</th><th>Used</th><th>Trend</th><th>Fills in</th></tr></thead><tbody>` +
      risers.map(m => `<tr><td><code>${escHtml(m.path)}</code></td>
        <td class="ta-center">${m.current_percent}%</td>
        <td class="ta-center">${m.trend_gb_per_day} GB/day</td>
        <td class="ta-center ${m.days_to_full<14?'c-red':m.days_to_full<45?'c-amber':''}">${_fmtDays(m.days_to_full)}</td></tr>`
      ).join('') + `</tbody></table></div>`;
    // Cross-feature: an imminent fill → a prefilled AI runbook.
    const urgent = risers.filter(m => m.days_to_full != null && m.days_to_full < 30)
                         .sort((a,b)=>a.days_to_full-b.days_to_full)[0];
    if (urgent) {
      const trig = `Disk ${urgent.path} on ${_drawerDeviceName} is at ${urgent.current_percent}% and projected to fill in ~${Math.round(urgent.days_to_full)} days (growing ${urgent.trend_gb_per_day} GB/day). What should I check and clean up?`;
      h += `<div class="mt-6"><a class="compliance-fix" data-action="deviceRunbook" data-arg="${escAttr(id)}" data-arg2="${escAttr(_drawerDeviceName||'')}" data-arg3="${escAttr(trig)}">${_icon('bookOpen',13)} Get a runbook for low disk space &rarr;</a></div>`;
    }
    h += `</div>`;
  }

  // ── What changed (7 days) ──────────────────────────────────────────
  const changes = (ch && ch.changes) || [];
  if (changes.length) {
    h += `<div class="hw-block"><div class="hw-h">What changed (last 7 days)</div>
      <ul class="hw-changes">` + changes.map(c => `<li>${escHtml(c)}</li>`).join('') + `</ul>
      <div class="mt-6"><a class="compliance-fix" data-action="openDriftForDevice" data-arg="${escAttr(_drawerDeviceName||'')}">${_icon('search',13)} Check watched-file config drift &rarr;</a></div></div>`;
  }

  // ── Passive inventory ──────────────────────────────────────────────
  const inv = hw.hardware || {};
  if (inv.system || (inv.memory||[]).length || (inv.temps||[]).length || (inv.raid||[]).length) {
    h += `<div class="hw-block"><div class="hw-h">Inventory</div>`;
    if (inv.system) {
      h += `<div class="mb-8">${['manufacturer','product','serial'].filter(x=>inv.system[x]).map(x=>`<span class="cmd-badge fs-11">${x}: ${escHtml(inv.system[x])}</span>`).join(' ')}</div>`;
    }
    if ((inv.memory||[]).length) {
      // v3.4.2: surface manufacturer + serial — the identifying detail you need
      // to order/swap a specific DIMM (the agent reports both when dmidecode runs).
      h += `<div class="fs-11 c-muted mb-4">Memory (${inv.memory.length} module${inv.memory.length>1?'s':''})</div>
        <div class="scrollable-table-wrap audit-scroll"><table class="audit-table"><thead><tr><th>Slot</th><th>Size</th><th>Type</th><th>Speed</th><th>Manufacturer</th><th>Serial</th></tr></thead><tbody>` +
        inv.memory.map(d=>`<tr><td>${escHtml(d.locator||'—')}</td><td>${escHtml(d.size||'—')}</td><td>${escHtml(d.type||'—')}</td><td>${escHtml(d.speed||'—')}</td><td>${escHtml(d.manufacturer||'—')}</td><td class="mono-12">${escHtml(d.serial||'—')}</td></tr>`).join('') +
        `</tbody></table></div>`;
    }
    if ((inv.raid||[]).length) {
      // v3.4.2: include the member block devices so a degraded array names the
      // exact disk to replace.
      h += `<div class="fs-11 c-muted mb-4 mt-8">RAID</div>` +
        inv.raid.map(r=>{
          // v3.8.0: the agent emits `devices` as a space-separated string
          // (e.g. "sda1 sdb1"); accept both string and array so the member
          // disks actually render (was silently dropped).
          const _devs = Array.isArray(r.devices) ? r.devices
            : (typeof r.devices === 'string' ? r.devices.split(/[\s,]+/).filter(Boolean) : []);
          const mem = _devs.length
            ? ` <span class="c-muted">[${_devs.map(x=>escHtml(x)).join(', ')}]</span>` : '';
          return `<span class="cmd-badge fs-11">${escHtml(r.name)} ${escHtml(r.level)} <span class="${/active|clean/i.test(r.state)?'c-green':'c-amber'}">${escHtml(r.state)}</span>${mem}</span>`;
        }).join(' ');
    }
    if ((inv.temps||[]).length) {
      const hot = inv.temps.filter(t=>t.current_c>=75);
      h += `<div class="fs-11 c-muted mb-4 mt-8">Temperatures${hot.length?` — <span class="c-red">${hot.length} hot</span>`:''}</div>` +
        inv.temps.slice(0,16).map(t=>`<span class="cmd-badge fs-11 ${t.current_c>=75?'c-red':''}">${escHtml(t.label)}: ${t.current_c}°C</span>`).join(' ');
    }
    h += `</div>`;
  }

  // ── On-demand actions: speedtest + LAN discovery ───────────────────
  const st = (hw.speedtest || []).slice(-1)[0];
  const disc = hw.discovery || {};
  const unmanaged = (disc.hosts||[]).filter(x=>!x.managed);
  const dn = _drawerDeviceName || '';
  h += `<div class="hw-block"><div class="hw-h">On-demand diagnostics</div>
    <div class="hw-actions">
      <button class="btn-secondary fs-12" data-action="deviceSpeedtest" data-arg="${escAttr(id)}">${_icon('zap',14)} Run speed test</button>
      <button class="btn-secondary fs-12" data-action="deviceNetscan" data-arg="${escAttr(id)}">${_icon('search',14)} Scan LAN</button>
      <button class="btn-secondary fs-12" data-action="deviceRunbook" data-arg="${escAttr(id)}" data-arg2="${escAttr(dn)}">${_icon('bookOpen',14)} Suggest runbook</button>
      <button class="btn-secondary fs-12" data-action="deviceDocDraft" data-arg="${escAttr(id)}" data-arg2="${escAttr(dn)}">${_icon('sparkles',14)} Draft CMDB doc</button>
    </div>
    <div id="hw-diag-status" class="mt-8"></div>`;
  if (st) {
    h += st.ok
      ? `<div class="fs-12 mt-8">Last speed test: <b>${st.download_mbps}</b> Mbps down · <b>${st.upload_mbps}</b> Mbps up · ${st.ping_ms} ms ping <span class="c-muted">(${timeAgo(st.ts)})</span></div>`
      : `<div class="fs-12 mt-8 c-amber">Last speed test failed: ${escHtml(st.error||'')}</div>`;
  }
  if ((disc.hosts||[]).length) {
    h += `<div class="fs-12 mt-8">LAN scan (${escHtml(disc.method||'')}, ${timeAgo(disc.ts)}): ${disc.hosts.length} host${disc.hosts.length>1?'s':''}, <b>${unmanaged.length}</b> unmanaged.</div>`;
  }
  h += `</div>`;

  return h || '<div class="c-muted">No hardware data reported yet. The agent collects SMART / kernel / inventory every ~5 reports.</div>';
}

async function toggleQuarantine(id, on) {
  const r = await api('PATCH', `/devices/${id}/quarantine`, {quarantined: !!on});
  if (r && r.ok) {
    if (_drawerDeviceData) _drawerDeviceData.quarantined = r.quarantined;
    toast(r.quarantined ? 'Device quarantined — actions disabled.'
                        : 'Quarantine lifted.', 'success');
  } else {
    toast((r && r.error) || 'Failed', 'error');
    const cb = document.getElementById('ds-quarantine');
    if (cb) cb.checked = !on;   // revert on failure
  }
}

// v3.4.0: these queue a command the agent runs on its *next poll*, so the
// result isn't instant. Rather than a fire-and-forget toast (which felt like
// "nothing happened"), we show a live "running…" status under the buttons and
// poll the hardware endpoint until a fresh result lands or we time out.
async function deviceSpeedtest(id) {
  const status = document.getElementById('hw-diag-status');
  const base = await _diagBaselineTs(id, 'speedtest');
  const r = await api('POST', `/devices/${id}/speedtest`, {});
  if (!(r && r.ok)) { toast((r && r.error) || 'Failed to queue', 'error');
    if (status) status.innerHTML = `<div class="c-red">${escHtml((r && r.error) || 'Failed to queue')}</div>`;
    return; }
  toast('Speed test queued — running on the device…', 'success');
  if (status) status.innerHTML = `<div class="diag-pending">${_icon('clock',13)} Speed test queued — waiting for the agent to run it and report back (next poll)…</div>`;
  _awaitDiag(id, 'speedtest', base, 'Speed test');
}

async function deviceNetscan(id) {
  const status = document.getElementById('hw-diag-status');
  const base = await _diagBaselineTs(id, 'discovery');
  const r = await api('POST', `/devices/${id}/netscan`, {});
  if (!(r && r.ok)) { toast((r && r.error) || 'Failed to queue', 'error');
    if (status) status.innerHTML = `<div class="c-red">${escHtml((r && r.error) || 'Failed to queue')}</div>`;
    return; }
  toast('LAN scan queued — running on the device…', 'success');
  if (status) status.innerHTML = `<div class="diag-pending">${_icon('clock',13)} LAN scan queued — waiting for the agent to run it and report back (next poll)…</div>`;
  _awaitDiag(id, 'discovery', base, 'LAN scan');
}

async function _diagBaselineTs(id, kind) {
  try {
    const hw = await api('GET', `/devices/${id}/hardware`);
    if (kind === 'speedtest') { const a = (hw && hw.speedtest) || []; return a.length ? a[a.length-1].ts : 0; }
    return ((hw && hw.discovery) || {}).ts || 0;
  } catch (_) { return 0; }
}

// Poll until a result newer than `baseTs` shows up (or time out). Stops if the
// operator navigates away from this device's drawer.
function _awaitDiag(id, kind, baseTs, label) {
  let tries = 0;
  const maxTries = 50;          // ~5 min at 6s
  const tick = async () => {
    if (_drawerDeviceId !== id) return;   // drawer closed / switched device
    tries++;
    let hw = null;
    try { hw = await api('GET', `/devices/${id}/hardware`); } catch (_) {}
    let res = null, ts = 0;
    if (hw) {
      if (kind === 'speedtest') { const a = hw.speedtest || []; if (a.length) { res = a[a.length-1]; ts = res.ts; } }
      else { res = hw.discovery || {}; ts = res.ts || 0; }
    }
    const status = document.getElementById('hw-diag-status');
    if (ts && ts !== baseTs) {
      if (status) status.innerHTML = _renderDiagResult(kind, res);
      toast(`${label} finished`, 'success');
      return;
    }
    if (tries >= maxTries) {
      if (status) status.innerHTML = `<div class="c-amber">${label} still pending after 5 min — the device may be offline, polling slowly, or the required tool isn't installed. It'll appear here once it reports.</div>`;
      return;
    }
    setTimeout(tick, 6000);
  };
  setTimeout(tick, 6000);
}

function _renderDiagResult(kind, res) {
  if (kind === 'speedtest') {
    if (!res) return '';
    return res.ok
      ? `<div class="diag-done c-green">${_icon('zap',13)} <b>${res.download_mbps}</b> Mbps down · <b>${res.upload_mbps}</b> Mbps up · ${res.ping_ms} ms ping ${res.jitter_ms!=null?`· ${res.jitter_ms} ms jitter`:''} <span class="c-muted">(${timeAgo(res.ts)})</span></div>`
      : `<div class="diag-done c-amber">Speed test ran but failed: ${escHtml(res.error || 'unknown')} — is <code>librespeed-cli</code> installed on the host?</div>`;
  }
  const n = (res.hosts || []).length;
  const unmanaged = (res.hosts || []).filter(x => !x.managed).length;
  return `<div class="diag-done c-green">${_icon('search',13)} LAN scan (${escHtml(res.method||'')}): ${n} host(s), <b>${unmanaged}</b> unmanaged <span class="c-muted">(${timeAgo(res.ts)})</span>. See Network map → Unmanaged hosts.</div>`;
}

