// #14 compliance report (Compliance page).
// ─── v3.4.0: Forecast page — fleet disk-fill projection + regression chart ───
let _forecastRows = [];
let _forecastSel = 0;

async function loadForecast() {
  const body = document.getElementById('forecast-body');
  const chart = document.getElementById('forecast-chart');
  const summary = document.getElementById('forecast-summary');
  if (!body) return;
  const r = await api('GET', '/forecast');
  if (!r || !Array.isArray(r.mounts)) {
    body.innerHTML = '<div class="c-red">Failed to load forecast.</div>';
    if (chart) chart.innerHTML = '';
    return;
  }
  _forecastRows = r.mounts;
  _forecastSel = 0;
  if (summary) {
    const filling = _forecastRows.filter(m => m.days_to_full != null).length;
    summary.textContent = _forecastRows.length
      ? `${_forecastRows.length} mount(s) across ${r.devices} device(s) with history — ${filling} projected to fill.`
      : '';
  }
  if (!_forecastRows.length) {
    body.innerHTML = `<div class="empty-state"><div class="empty-icon">${_icon('trendingUp', 28)}</div>`
      + `<div class="empty-title">No forecast yet</div>`
      + `<div class="empty-text">RemotePower needs a few days of daily metrics history per host before it can project disk-fill.<br>Check back once agents have been reporting for several days.</div></div>`;
    if (chart) chart.innerHTML = '';
    return;
  }
  _forecastShown = _FORECAST_PAGE;
  _renderForecastTable();
  _renderForecastChart();
}

function forecastSelect(idx) {
  _forecastSel = Number(idx) || 0;
  _renderForecastTable();
  _renderForecastChart();
}

// ── Timeline page (v3.4.1) ───────────────────────────────────────────────────
// Per-device chronological history: fleet events + command runs merged into one
// stream by GET /api/devices/<id>/timeline. The device <select> drives it; the
// kind chips filter the already-fetched rows client-side (no re-fetch).
let _timelineItems = [];
let _timelineKindFilter = new Set();
let _timelineFleet = true;   // '*' scope (whole fleet) vs a single device
const _TIMELINE_PAGE = 50;   // rows rendered per page (Load more reveals more)
let _timelineShown = _TIMELINE_PAGE;
const _TIMELINE_SEV = { critical: 'sev-critical', high: 'sev-high',
  medium: 'sev-medium', low: 'sev-low', warning: 'sev-medium', info: 'sev-low' };

function _timelineFillDevices(list) {
  const sel = document.getElementById('timeline-device');
  if (!sel) return;
  const prev = sel.value;
  // v3.4.1: the first option is the whole-fleet view; the rest are devices.
  const opts = ['<option value="*">Whole fleet</option>'];
  (list || []).slice()
    .sort((a, b) => (a.name || a.id || '').localeCompare(b.name || b.id || ''))
    .forEach(d => {
      const id = d.id || d.device_id;
      if (!id) return;
      opts.push(`<option value="${_escapeHtml(id)}">${_escapeHtml(d.name || id)}</option>`);
    });
  sel.innerHTML = opts.join('');
  if (prev) sel.value = prev;
}

function enterTimeline() {
  const sel = document.getElementById('timeline-device');
  if (!sel) return;
  if (window._devicesCache && window._devicesCache.length) {
    _timelineFillDevices(window._devicesCache);
  } else {
    api('GET', '/devices').then(d => {
      if (d) { window._devicesCache = d; _timelineFillDevices(d); }
    }).catch(() => {});
  }
  // v3.4.1: command palette / drawer can deep-link a device into the timeline.
  if (window._timelinePendingDevice) {
    sel.value = window._timelinePendingDevice;
    window._timelinePendingDevice = null;
  }
  if (!sel.value) sel.value = '*';   // default to the whole-fleet view
  loadTimeline();
}

async function loadTimeline() {
  const sel = document.getElementById('timeline-device');
  const body = document.getElementById('timeline-body');
  const summary = document.getElementById('timeline-summary');
  if (!sel || !body) return;
  const scope = sel.value || '*';
  _timelineFleet = (scope === '*');
  body.innerHTML = '<div class="c-muted">Loading…</div>';
  const url = _timelineFleet
    ? '/fleet/timeline?limit=300'
    : `/devices/${encodeURIComponent(scope)}/timeline?limit=300`;
  const r = await api('GET', url).catch(() => null);
  if (!r || !Array.isArray(r.items)) {
    body.innerHTML = '<div class="c-red">Failed to load timeline.</div>';
    return;
  }
  _timelineItems = r.items;
  // Drop active filters that don't apply to this scope's kind set.
  _timelineKindFilter = new Set([..._timelineKindFilter].filter(k => (r.kinds || []).includes(k)));
  if (summary) summary.textContent = _timelineFleet
    ? `${r.total} event(s) across ${(r.devices || []).length} device(s)`
    : `${r.total} event(s) for ${r.device_name}`;
  _timelineShown = _TIMELINE_PAGE;
  _renderTimelineKinds(r.kinds || []);
  _renderTimeline();
}

function timelineShowMore() {
  _timelineShown += _TIMELINE_PAGE;
  _renderTimeline();
}

function _renderTimelineKinds(kinds) {
  const wrap = document.getElementById('timeline-kinds');
  if (!wrap) return;
  if (!kinds.length) { wrap.innerHTML = ''; return; }
  const chip = (k, label, active) =>
    `<button class="tl-chip${active ? ' active' : ''}" data-action="timelineToggleKind" data-arg="${_escapeHtml(k)}">${_escapeHtml(label)}</button>`;
  const parts = [chip('', 'All', _timelineKindFilter.size === 0)];
  kinds.forEach(k => parts.push(chip(k, k.replace(/_/g, ' '), _timelineKindFilter.has(k))));
  wrap.innerHTML = parts.join('');
}

function timelineToggleKind(kind) {
  if (!kind) _timelineKindFilter.clear();
  else if (_timelineKindFilter.has(kind)) _timelineKindFilter.delete(kind);
  else _timelineKindFilter.add(kind);
  _timelineShown = _TIMELINE_PAGE;   // reset paging when the filter changes
  _renderTimelineKinds([...new Set(_timelineItems.map(i => i.kind))]);
  _renderTimeline();
}

function _renderTimeline() {
  const body = document.getElementById('timeline-body');
  if (!body) return;
  let items = _timelineItems;
  if (_timelineKindFilter.size) items = items.filter(i => _timelineKindFilter.has(i.kind));
  if (!items.length) {
    const where = _timelineFleet ? 'across the fleet' : 'for this device';
    body.innerHTML = `<div class="empty-state"><div class="empty-icon">${_icon('clock', 28)}</div>`
      + `<div class="empty-title">No timeline entries</div>`
      + `<div class="empty-text">No events or command runs recorded ${where} yet${_timelineKindFilter.size ? ' in the selected categories' : ''}.</div></div>`;
    return;
  }
  const total = items.length;
  const page = items.slice(0, _timelineShown);
  const rows = page.map(it => {
    const sev = _TIMELINE_SEV[it.severity] || 'sev-low';
    const whenAbs = new Date((it.ts || 0) * 1000).toLocaleString();
    // In fleet mode each row names its device (clickable → that device's timeline).
    const devChip = (_timelineFleet && it.device_id)
      ? `<button class="tl-devchip" data-action="openDeviceTimeline" data-arg="${_escapeHtml(it.device_id)}" title="Open ${_escapeHtml(it.device_name || it.device_id)}'s timeline">${_escapeHtml(it.device_name || it.device_id)}</button>`
      : '';
    return `<div class="tl-row">`
      + `<div class="tl-dot ${sev}"></div>`
      + `<div class="tl-main">`
      +   `<div class="tl-head">${devChip}<span class="tl-title">${_escapeHtml(it.title || it.kind)}</span>`
      +   `<span class="sev-pill ${sev}">${_escapeHtml(it.severity)}</span>`
      +   `<span class="tl-kind">${_escapeHtml((it.kind || '').replace(/_/g, ' '))}</span></div>`
      +   (it.detail ? `<div class="tl-detail">${_escapeHtml(it.detail)}</div>` : '')
      + `</div>`
      + `<div class="tl-time" title="${_escapeHtml(whenAbs)}">${_escapeHtml(timeAgo(it.ts))}</div>`
      + `</div>`;
  });
  let footer = '';
  if (total > _timelineShown) {
    footer = `<div class="tl-more"><span class="c-muted fs-12">Showing ${page.length} of ${total}</span>`
      + `<button class="btn-secondary fs-12" data-action="timelineShowMore">Load ${Math.min(_TIMELINE_PAGE, total - _timelineShown)} more</button></div>`;
  } else if (total > _TIMELINE_PAGE) {
    footer = `<div class="tl-more"><span class="c-muted fs-12">Showing all ${total}</span></div>`;
  }
  body.innerHTML = `<div class="tl-list">${rows.join('')}</div>${footer}`;
}

// ── Reports page (v3.4.1) ────────────────────────────────────────────────────
// On-demand fleet posture export (JSON/CSV) + scheduled email delivery config.
async function loadReports() {
  const preview = document.getElementById('reports-preview');
  // Posture summary preview (reuses the same report the export downloads).
  if (preview) {
    const rep = await api('GET', '/report/fleet').catch(() => null);
    if (!rep) {
      preview.innerHTML = '<div class="c-red">Failed to load report summary.</div>';
    } else {
      const h = rep.health || {}; const c = rep.cve || {};
      const p = rep.patches || {}; const d = rep.devices || {};
      const fws = (rep.compliance && rep.compliance.frameworks) || {};
      const fwPills = Object.keys(fws).map(fw =>
        `<span class="sev-pill sev-low">${_escapeHtml(fw.toUpperCase())}: ${fws[fw].score != null ? fws[fw].score + '%' : 'N/A'}</span>`).join(' ');
      preview.innerHTML =
        `<div class="rep-grid">`
        + `<div class="rep-cell"><div class="rep-k">Health</div><div class="rep-v" data-color="${_HEALTH_COLOR[h.grade] || 'var(--muted)'}">${h.score != null ? h.score : '—'}<span class="rep-unit">/100</span></div><div class="rep-sub c-muted">${_escapeHtml(h.grade || '')}</div></div>`
        + `<div class="rep-cell"><div class="rep-k">Devices</div><div class="rep-v">${d.online || 0}<span class="rep-unit">/${d.total || 0} online</span></div></div>`
        + `<div class="rep-cell"><div class="rep-k">Patches</div><div class="rep-v">${p.total_pending || 0}</div><div class="rep-sub c-muted">${p.devices_with_patches || 0} device(s)</div></div>`
        + `<div class="rep-cell"><div class="rep-k">CVEs</div><div class="rep-v">${(c.critical || 0) + (c.high || 0)}</div><div class="rep-sub c-muted">${c.critical || 0} crit · ${c.high || 0} high</div></div>`
        + `</div>`
        + (fwPills ? `<div class="rep-compliance">${fwPills}</div>` : '');
    }
  }
  loadReportsCapacity();
  loadReportsIntegrity();
  loadReportsAnomalies();
  loadReportsMetering();
  loadReportsSla();
  // Schedule config.
  const sch = await api('GET', '/report/schedule').catch(() => null);
  if (sch) {
    const en = document.getElementById('report-sched-enabled');
    const cron = document.getElementById('report-sched-cron');
    const rec = document.getElementById('report-sched-recipients');
    const status = document.getElementById('report-sched-status');
    if (en) en.checked = !!sch.enabled;
    if (cron) cron.value = sch.cron || '';
    if (rec) rec.value = (sch.recipients || []).join(', ');
    if (status) status.textContent = sch.last_run
      ? `Last sent ${timeAgo(sch.last_run)}` : 'Never sent yet.';
  }
  loadReportDefs();   // v3.14.0: custom report builder
}

async function loadReportsCapacity() {
  const out = document.getElementById('reports-capacity');
  if (!out) return;
  const r = await api('GET', '/fleet/capacity').catch(() => null);
  if (!r) { out.innerHTML = '<div class="c-red">Failed to load capacity.</div>'; return; }
  const cell = (k, agg, unit) => `<div class="rep-cell"><div class="rep-k">${k}</div>`
    + `<div class="rep-v">${agg.avg != null ? agg.avg : '—'}<span class="rep-unit">${unit} avg</span></div>`
    + `<div class="rep-sub c-muted">max ${agg.max != null ? agg.max + unit : '—'}</div></div>`;
  const d = r.disk || {};
  const tops = (label, arr, unit) => arr && arr.length
    ? `<div class="cap-top"><div class="rep-k">${label}</div>`
      + arr.map(x => `<div class="cap-top-row"><span>${escHtml(x.name)}</span><span class="mono-12">${x.value}${unit}</span></div>`).join('')
      + `</div>` : '';
  out.innerHTML =
    `<div class="rep-grid">`
    + cell('CPU', r.cpu || {}, '%')
    + cell('Memory', r.memory || {}, '%')
    + cell('Swap', r.swap || {}, '%')
    + `<div class="rep-cell"><div class="rep-k">Disk</div><div class="rep-v">${d.percent != null ? d.percent : '—'}<span class="rep-unit">% used</span></div><div class="rep-sub c-muted">${d.used_gb || 0} / ${d.total_gb || 0} GB</div></div>`
    + `</div>`
    + `<div class="fs-12 c-muted mt-6">${r.devices_counted || 0} online device(s) counted</div>`
    + `<div class="cap-tops">${tops('Top CPU', r.top_cpu, '%')}${tops('Top memory', r.top_memory, '%')}${tops('Top disk', r.top_disk, '%')}</div>`;
}

async function loadReportsIntegrity() {
  const out = document.getElementById('reports-integrity');
  if (!out) return;
  const r = await api('GET', '/fleet/agent-integrity').catch(() => null);
  if (!r) { out.innerHTML = '<div class="c-red">Failed to load agent integrity.</div>'; return; }
  const c = r.counts || {};
  const pills = `<div class="row-8-center mb-12">`
    + `<span class="sev-pill sev-success">${c.verified || 0} verified</span>`
    + `<span class="sev-pill sev-critical">${c.mismatch || 0} mismatch</span>`
    + `<span class="sev-pill sev-low">${c.unknown || 0} unknown</span>`
    + `<span class="fs-12 c-muted">canonical ${escHtml(r.canonical_sha256 || '—')} · v${escHtml(r.server_version || '')}</span></div>`;
  // Only list the non-verified ones (the actionable rows); verified is the count pill.
  const actionable = (r.devices || []).filter(d => d.status !== 'verified');
  const sorted = tableCtl.sortRows('reports_integrity', actionable, d => ({
    device: d.name, version: d.version || '', status: d.status, hash: d.agent_sha256 || '',
  }));
  const rows = sorted.map(d => {
    const cls = d.status === 'mismatch' ? 'sev-critical' : 'sev-low';
    return `<tr><td>${escHtml(d.name)}</td><td class="mono-12">${escHtml(d.version || '—')}</td>`
      + `<td><span class="sev-pill ${cls}">${escHtml(d.status)}</span></td>`
      + `<td class="mono-12">${escHtml(d.agent_sha256 || '—')}</td></tr>`;
  }).join('');
  out.innerHTML = pills + (rows
    ? `<div class="table-card"><table><thead id="reports-integrity-thead"><tr><th data-col="device">Device</th><th data-col="version">Version</th><th data-col="status">Status</th><th data-col="hash">Reported hash</th></tr></thead><tbody>${rows}</tbody></table></div>`
    : '<div class="c-muted fs-13">All reporting agents verified.</div>');
  tableCtl.wireSortOnly('reports-integrity-thead', 'reports_integrity', loadReportsIntegrity);
}

// v3.4.2: software metering / license compliance.
async function loadReportsMetering() {
  const out = document.getElementById('metering-results');
  if (!out) return;
  // Prefill the config textarea from /config.
  const cfg = await api('GET', '/config').catch(() => null);
  const ta = document.getElementById('metering-config');
  if (ta && cfg && Array.isArray(cfg.software_meters)) {
    // Syntax: "name = limit" with optional "| alias1, alias2" normalization.
    ta.value = cfg.software_meters.map(m => {
      const base = `${m.name} = ${m.limit || 0}`;
      const al = (m.aliases || []).filter(Boolean);
      return al.length ? `${base} | ${al.join(', ')}` : base;
    }).join('\n');
  }
  const r = await api('GET', '/inventory/metering').catch(() => null);
  if (!r) { out.innerHTML = ''; return; }
  const meters = Array.isArray(r.meters) ? r.meters : [];
  if (!meters.length) { out.innerHTML = '<div class="c-muted fs-13">No software meters configured yet.</div>'; return; }
  const sorted = tableCtl.sortRows('metering', meters.slice(), m => ({
    software: m.name, installed: m.installed, reclaim: m.reclaimable || 0,
  }));
  const rows = sorted.map(m => {
    const cls = m.over ? 'c-red fw-500' : '';
    const lim = m.limit ? ` / ${m.limit}` : '';
    const aliasNote = (m.aliases && m.aliases.length) ? `<div class="fs-11 c-muted">+ ${escHtml(m.aliases.join(', '))}</div>` : '';
    const reclaim = m.reclaimable
      ? `<span class="c-amber" title="Installed but not seen running on: ${escAttr((m.reclaim_hosts || []).join(', '))}">${m.reclaimable} reclaimable</span>`
      : '<span class="c-muted">—</span>';
    return `<tr><td>${escHtml(m.name)}${aliasNote}</td><td class="${cls}">${m.installed}${lim}${m.over ? ' ⚠' : ''}</td>`
      + `<td class="fs-12">${reclaim}</td>`
      + `<td class="fs-12 c-muted">${escHtml(m.devices.join(', '))}</td></tr>`;
  }).join('');
  out.innerHTML = `<div class="table-card"><table><thead id="metering-thead"><tr><th data-col="software">Software</th><th data-col="installed">Installed</th><th data-col="reclaim">Reclaim</th><th>Devices</th></tr></thead><tbody>${rows}</tbody></table></div>`
    + `<div class="fs-11 c-muted mt-4">Reclaimable = installed but not seen in running processes / listening ports. Syntax: <code>name = limit | alias1, alias2</code> (aliases map name variants onto one entry).</div>`;
  tableCtl.wireSortOnly('metering-thead', 'metering', loadReportsMetering);
}

async function saveMetering() {
  const ta = document.getElementById('metering-config');
  const meters = (ta.value || '').split('\n').map(l => l.trim()).filter(Boolean).map(l => {
    // "name = limit | alias1, alias2"
    const pipe = l.split('|');
    const left = pipe[0];
    const aliases = (pipe[1] || '').split(',').map(s => s.trim()).filter(Boolean);
    const m = left.split('=');
    const name = (m[0] || '').trim();
    const limit = parseInt((m[1] || '0').trim(), 10) || 0;
    if (!name) return null;
    const entry = { name, limit };
    if (aliases.length) entry.aliases = aliases;
    return entry;
  }).filter(Boolean);
  const r = await api('POST', '/config', { software_meters: meters }).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Failed', 'error'); return; }
  const st = document.getElementById('metering-status'); if (st) st.textContent = `${meters.length} meter(s) saved`;
  loadReportsMetering();
}

async function loadReportsAnomalies() {
  const out = document.getElementById('reports-anomalies');
  if (!out) return;
  const r = await api('GET', '/fleet/anomalies').catch(() => null);
  if (!r) { out.innerHTML = '<div class="c-red">Failed to load anomalies.</div>'; return; }
  const a = r.anomalies || [];
  if (!a.length) { out.innerHTML = '<div class="c-muted fs-13">No resource anomalies detected.</div>'; return; }
  const sorted = tableCtl.sortRows('reports_anomalies', a, x => ({
    device: x.device_name, metric: x.label, latest: x.value, baseline: x.mean, deviation: x.z,
  }));
  const rows = sorted.map(x => {
    const arrow = x.direction === 'high' ? '▲' : '▼';
    const cls = x.direction === 'high' ? 'c-red' : 'c-amber';
    return `<tr><td>${escHtml(x.device_name)}</td><td>${escHtml(x.label)}</td>`
      + `<td class="${cls} fw-500">${arrow} ${x.value}</td>`
      + `<td class="mono-12">${x.mean} ±${x.stdev}</td>`
      + `<td class="mono-12">z=${x.z}</td></tr>`;
  }).join('');
  out.innerHTML = `<div class="table-card"><table><thead id="reports-anomalies-thead"><tr><th data-col="device">Device</th><th data-col="metric">Metric</th><th data-col="latest">Latest</th><th data-col="baseline">Baseline</th><th data-col="deviation">Deviation</th></tr></thead><tbody>${rows}</tbody></table></div>`;
  tableCtl.wireSortOnly('reports-anomalies-thead', 'reports_anomalies', loadReportsAnomalies);
}

let _slaRows = [];
async function loadReportsSla() {
  const out = document.getElementById('reports-sla');
  if (!out) return;
  const days = document.getElementById('sla-days')?.value || '30';
  const r = await api('GET', '/fleet/sla?days=' + encodeURIComponent(days)).catch(() => null);
  if (!r) { out.innerHTML = '<div class="c-red">Failed to load uptime.</div>'; return; }
  const fl = document.getElementById('sla-fleet');
  if (fl) {
    if (r.fleet_uptime_pct != null) {
      const tgt = r.fleet_sla_target != null ? ` · target ${r.fleet_sla_target}%${r.fleet_sla_met === false ? ' (breached)' : ''}` : '';
      let eb = '';
      const b = r.fleet_error_budget;
      if (b) {
        const fd = s => !s ? '0' : Math.abs(s) >= 86400 ? Math.round(s / 86400) + 'd' : Math.abs(s) >= 3600 ? Math.round(s / 3600) + 'h' : Math.round(s / 60) + 'm';
        eb = ` · error budget ${b.remaining_seconds < 0 ? 'exhausted' : fd(b.remaining_seconds) + ' left'} (${b.used_pct}% used)`;
      }
      fl.textContent = `fleet ${r.fleet_uptime_pct}% over ${r.days}d${tgt}${eb}`;
    } else {
      fl.textContent = 'no data yet';
    }
  }
  _slaRows = r.devices || [];
  _renderReportsSla();
}
function _renderReportsSla() {
  const out = document.getElementById('reports-sla');
  if (!out) return;
  if (!_slaRows.length) { out.innerHTML = '<div class="c-muted fs-13">No uptime data yet.</div>'; return; }
  // v4.10.0: omnisearch the per-device SLA table by device name or group.
  const q = (document.getElementById('sla-search')?.value || '').trim().toLowerCase();
  const base = q
    ? _slaRows.filter(r => (r.name || '').toLowerCase().includes(q) || (r.group || '').toLowerCase().includes(q))
    : _slaRows;
  if (!base.length) { out.innerHTML = `<div class="c-muted fs-13">No device matches “${escHtml(q)}”.</div>`; return; }
  const fmtPct = p => p == null ? '—' : p + '%';
  const fmtDown = s => !s ? '0' : s >= 86400 ? Math.round(s / 86400) + 'd' : s >= 3600 ? Math.round(s / 3600) + 'h' : Math.round(s / 60) + 'm';
  const sorted = tableCtl.sortRows('sla', base.slice(), r => ({
    device: r.name, group: r.group, uptime: r.uptime_pct == null ? -1 : r.uptime_pct,
    downtime: r.downtime_seconds, target: r.sla_target == null ? -1 : r.sla_target,
    budget: r.error_budget ? r.error_budget.used_pct : -1,
  }));
  const rows = sorted.map(r => {
    // Colour uptime against its SLA target when one is set, else the static
    // 99.9 / 99 thresholds.
    let cls = 'c-muted';
    if (r.uptime_pct != null) {
      if (r.sla_met === true) cls = 'c-green';
      else if (r.sla_met === false) cls = 'c-red';
      else cls = r.uptime_pct >= 99.9 ? 'c-green' : r.uptime_pct >= 99 ? 'c-amber' : 'c-red';
    }
    let tgt = '<span class="hint">—</span>';
    if (r.sla_target != null) {
      const lbl = r.sla_met === false ? ' <span class="c-red fs-11">breached</span>'
                : r.sla_met === true ? ' <span class="c-green fs-11">met</span>' : '';
      tgt = `${r.sla_target}%${lbl}`;
    }
    let budget = '<span class="hint">—</span>';
    if (r.error_budget) {
      const eb = r.error_budget, rem = eb.remaining_seconds;
      const bcls = rem < 0 ? 'c-red' : eb.used_pct >= 80 ? 'c-amber' : 'c-green';
      budget = `<span class="${bcls}">${rem < 0 ? '−' + fmtDown(-rem) + ' over' : fmtDown(rem) + ' left'}</span> <span class="hint fs-11">${eb.used_pct}%</span>`;
    }
    return `<tr><td>${escHtml(r.name)}</td><td class="hint">${escHtml(r.group || '—')}</td>`
      + `<td class="${cls} fw-500">${r.covered ? fmtPct(r.uptime_pct) : 'unknown'}</td>`
      + `<td class="mono-12">${r.covered ? fmtDown(r.downtime_seconds) : '—'}</td>`
      + `<td class="mono-12">${tgt}</td>`
      + `<td>${budget}</td></tr>`;
  }).join('');
  out.innerHTML = `<div class="table-card"><table><thead id="sla-thead"><tr><th data-col="device">Device</th><th data-col="group">Group</th><th data-col="uptime">Uptime</th><th data-col="downtime">Downtime</th><th data-col="target">SLA target</th><th data-col="budget">Error budget</th></tr></thead><tbody>${rows}</tbody></table></div>`;
  tableCtl.wireSortOnly('sla-thead', 'sla', _renderReportsSla);
}

// ── SLA targets editor (set per device / tag / group / default) ──────────────
let _slaTargets = null;
let _slaTargetRows = [];   // [{scope:'group'|'tag'|'device', key, pct}]
async function toggleSlaTargets() {
  const ed = document.getElementById('sla-targets-editor');
  if (!ed) return;
  if (!ed.classList.contains('hidden')) { ed.classList.add('hidden'); return; }
  ed.classList.remove('hidden');
  ed.innerHTML = '<div class="c-muted fs-12">Loading…</div>';
  const r = await api('GET', '/fleet/sla-targets').catch(() => null);
  _slaTargets = r || { default: null, groups: {}, tags: {}, devices: {} };
  _slaTargetRows = [];
  [['groups', 'group'], ['tags', 'tag'], ['devices', 'device']].forEach(([lvl, scope]) => {
    Object.entries(_slaTargets[lvl] || {}).forEach(([k, v]) => _slaTargetRows.push({ scope, key: k, pct: v }));
  });
  _renderSlaTargetsEditor();
}
function _readSlaTargetRowsFromDom() {
  return Array.from(document.querySelectorAll('#sla-targets-editor .sla-tgt-row')).map(el => ({
    scope: el.querySelector('.sla-tgt-scope').value,
    key:   el.querySelector('.sla-tgt-key').value.trim(),
    pct:   el.querySelector('.sla-tgt-pct').value.trim(),
  }));
}
function slaTargetAddRow() { _slaTargetRows = _readSlaTargetRowsFromDom(); _slaTargetRows.push({ scope: 'group', key: '', pct: '' }); _renderSlaTargetsEditor(); }
function slaTargetRemoveRow(i) { _slaTargetRows = _readSlaTargetRowsFromDom(); _slaTargetRows.splice(Number(i), 1); _renderSlaTargetsEditor(); }
function _renderSlaTargetsEditor() {
  const ed = document.getElementById('sla-targets-editor');
  if (!ed) return;
  const def = (_slaTargets && _slaTargets.default != null) ? _slaTargets.default : '';
  const rowsHtml = _slaTargetRows.map((row, i) => `
    <div class="sla-tgt-row row-8-center mb-6">
      <select class="sla-tgt-scope form-input input-auto fs-12">
        <option value="group"${row.scope === 'group' ? ' selected' : ''}>Group</option>
        <option value="tag"${row.scope === 'tag' ? ' selected' : ''}>Tag</option>
        <option value="device"${row.scope === 'device' ? ' selected' : ''}>Device id</option>
      </select>
      <input class="sla-tgt-key form-input fs-12" placeholder="name / id" title="The device name/id, tag, or group this target applies to (leave blank for the Default scope)." value="${escAttr(row.key || '')}">
      <input class="sla-tgt-pct form-input input-auto fs-12" type="number" step="0.001" min="0" max="100" placeholder="%" title="Target uptime %, e.g. 99.9. Devices below it over the report window are flagged as breaching their SLA / error budget." value="${escAttr(String(row.pct == null ? '' : row.pct))}">
      <button class="btn-secondary fs-12" data-action="slaTargetRemoveRow" data-arg="${i}">Remove</button>
    </div>`).join('');
  ed.innerHTML = `<div class="dash-card p-12">
    <div class="row-8-center mb-8"><strong class="fs-13">SLA targets</strong>
      <span class="hint fs-11">most specific wins: device → tag → group → default</span></div>
    <div class="row-8-center mb-8"><label class="fs-12">Default target %</label>
      <input id="sla-tgt-default" class="form-input input-auto fs-12" type="number" step="0.001" min="0" max="100" placeholder="e.g. 99.9" value="${escAttr(String(def))}"></div>
    ${rowsHtml}
    <div class="row-8-center mt-8">
      <button class="btn-secondary fs-12" data-action="slaTargetAddRow">Add override</button>
      <button class="btn-primary fs-12" data-action="saveSlaTargets">Save targets</button>
    </div></div>`;
}
async function saveSlaTargets() {
  const rows = _readSlaTargetRowsFromDom();
  const body = { default: null, groups: {}, tags: {}, devices: {} };
  const defv = (document.getElementById('sla-tgt-default')?.value || '').trim();
  if (defv) body.default = parseFloat(defv);
  rows.forEach(r => {
    if (!r.key || r.pct === '') return;
    const p = parseFloat(r.pct);
    if (!(p > 0 && p <= 100)) return;
    const lvl = r.scope === 'group' ? 'groups' : r.scope === 'tag' ? 'tags' : 'devices';
    body[lvl][r.key] = p;
  });
  const res = await api('PUT', '/fleet/sla-targets', body).catch(() => null);
  if (!res) { toast('Failed to save SLA targets', 'error'); return; }
  toast('SLA targets saved', 'success');
  loadReportsSla();
}

// ── Automation rules (v3.4.2) ────────────────────────────────────────────────
let _autoRules = [];
let _autoScripts = [];   // [{id,name}]
let _autoDests = [];     // [{id,name}] webhook destinations

async function loadAutomation() {
  const list = document.getElementById('automation-list');
  if (!list) return;
  closeAutomationEditor();
  const [rules, scripts, cfg] = await Promise.all([
    api('GET', '/automation/rules').catch(() => null),
    api('GET', '/scripts').catch(() => null),
    api('GET', '/config').catch(() => null),
  ]);
  _autoScripts = (Array.isArray(scripts) ? scripts : (scripts && scripts.scripts) || [])
    .map(s => ({ id: s.id, name: s.name || s.id }));
  _autoDests = ((cfg && cfg.webhook_urls) || [])
    .filter(d => d && d.id).map(d => ({ id: d.id, name: d.name || d.url || d.id }));
  // Populate editor dropdowns.
  const sSel = document.getElementById('auto-script');
  if (sSel) sSel.innerHTML = '<option value="">— none —</option>'
    + _autoScripts.map(s => `<option value="${escAttr(s.id)}">${escHtml(s.name)}</option>`).join('');
  const nSel = document.getElementById('auto-notify');
  if (nSel) nSel.innerHTML = '<option value="">— none —</option>'
    + _autoDests.map(d => `<option value="${escAttr(d.id)}">${escHtml(d.name)}</option>`).join('');
  _autoRules = (rules && rules.rules) || [];
  _renderAutomationList();
}

function _autoRuleSummary(r) {
  const m = r.match || {};
  const evs = (m.events || []).length ? (m.events || []).join(', ') : 'any event';
  const sev = (m.severities || []).length ? ` [${m.severities.join('/')}]` : '';
  const dm = m.device_match || {};
  let where = 'any device';
  if (dm.device_id) where = 'device ' + dm.device_id;
  else if (dm.group || (dm.tags || []).length) where = [dm.group ? 'group ' + dm.group : '', (dm.tags || []).length ? 'tags ' + dm.tags.join(',') : ''].filter(Boolean).join(' + ');
  const acts = (r.actions || []).map(a => {
    if (a.type === 'run_script') { const s = _autoScripts.find(x => x.id === a.script_id); return 'run ' + (s ? s.name : a.script_id); }
    if (a.type === 'notify') { const d = _autoDests.find(x => x.id === a.dest_id); return 'notify ' + (d ? d.name : a.dest_id); }
    return a.type;
  }).join(', ');
  return `when <b>${escHtml(evs)}</b>${escHtml(sev)} on <b>${escHtml(where)}</b> → <b>${escHtml(acts)}</b>`;
}

function _renderAutomationList() {
  const list = document.getElementById('automation-list');
  if (!list) return;
  if (!_autoRules.length) {
    list.innerHTML = `<div class="empty-state"><div class="empty-icon">${_icon('zap', 28)}</div>`
      + `<div class="empty-title">No automation rules</div>`
      + `<div class="empty-text">Click <b>New rule</b> to react to events automatically — e.g. restart a service when it goes down.</div></div>`;
    return;
  }
  list.innerHTML = _autoRules.map(r =>
    `<div class="auto-rule${r.enabled ? '' : ' auto-off'}">`
    + `<div class="auto-rule-main">`
    +   `<div class="auto-rule-name">${escHtml(r.name || 'Rule')}${r.enabled ? '' : ' <span class="sev-pill sev-low">disabled</span>'}</div>`
    +   `<div class="auto-rule-sum">${_autoRuleSummary(r)}</div>`
    +   `<div class="meta-sm-nm">fired ${r.fire_count || 0}×${r.cooldown_seconds ? ` · cooldown ${r.cooldown_seconds}s` : ''}</div>`
    + `</div>`
    + `<div class="auto-rule-acts">`
    +   `<button class="btn-icon" data-action="toggleAutomationRule" data-arg="${escAttr(r.id)}">${r.enabled ? 'Disable' : 'Enable'}</button>`
    +   `<button class="btn-icon" title="Edit" data-action="openAutomationEditor" data-arg="${escAttr(r.id)}">${_icon('edit',14)}</button>`
    +   `<button class="btn-icon c-danger-outline" title="Delete" data-action="deleteAutomationRule" data-arg="${escAttr(r.id)}">${_icon('trash',14)}</button>`
    + `</div></div>`).join('');
}

function openAutomationEditor(ruleId) {
  const ed = document.getElementById('automation-editor');
  if (!ed) return;
  const r = ruleId ? _autoRules.find(x => x.id === ruleId) : null;
  document.getElementById('automation-editor-title').textContent = r ? 'Edit rule' : 'New rule';
  document.getElementById('auto-rule-id').value = r ? r.id : '';
  document.getElementById('auto-name').value = r ? (r.name || '') : '';
  const m = (r && r.match) || {};
  document.getElementById('auto-events').value = (m.events || []).join(', ');
  const sevSet = new Set(m.severities || []);
  document.querySelectorAll('#auto-sevs input[type=checkbox]').forEach(cb => { cb.checked = sevSet.has(cb.value); });
  const dm = m.device_match || {};
  document.getElementById('auto-group').value = dm.group || '';
  document.getElementById('auto-tags').value = (dm.tags || []).join(', ');
  const acts = (r && r.actions) || [];
  document.getElementById('auto-script').value = (acts.find(a => a.type === 'run_script') || {}).script_id || '';
  document.getElementById('auto-notify').value = (acts.find(a => a.type === 'notify') || {}).dest_id || '';
  document.getElementById('auto-cooldown').value = r ? (r.cooldown_seconds != null ? r.cooldown_seconds : 60) : 60;
  document.getElementById('auto-editor-status').textContent = '';
  ed.classList.remove('d-none');
  ed.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function closeAutomationEditor() {
  const ed = document.getElementById('automation-editor');
  if (ed) ed.classList.add('d-none');
}

async function saveAutomationRule() {
  const id = document.getElementById('auto-rule-id').value;
  const events = document.getElementById('auto-events').value.split(',').map(s => s.trim()).filter(Boolean);
  const severities = [...document.querySelectorAll('#auto-sevs input:checked')].map(cb => cb.value);
  const tags = document.getElementById('auto-tags').value.split(',').map(s => s.trim()).filter(Boolean);
  const actions = [];
  const sid = document.getElementById('auto-script').value;
  const did = document.getElementById('auto-notify').value;
  if (sid) actions.push({ type: 'run_script', script_id: sid });
  if (did) actions.push({ type: 'notify', dest_id: did });
  if (!actions.length) { toast('Pick at least one action (script or notify)', 'error'); return; }
  if (!events.length && !severities.length) { toast('Specify at least one event or severity', 'error'); return; }
  const rule = {
    name: document.getElementById('auto-name').value.trim() || 'Rule',
    enabled: true,
    match: { events, severities, device_match: { group: document.getElementById('auto-group').value.trim(), tags } },
    actions,
    cooldown_seconds: parseInt(document.getElementById('auto-cooldown').value, 10) || 0,
  };
  // Preserve enabled state when editing.
  if (id) { const ex = _autoRules.find(x => x.id === id); if (ex) rule.enabled = ex.enabled; }
  const r = id
    ? await api('PUT', '/automation/rules/' + encodeURIComponent(id), rule).catch(() => null)
    : await api('POST', '/automation/rules', rule).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Save failed', 'error'); return; }
  toast('Rule saved', 'success');
  loadAutomation();
}

async function toggleAutomationRule(id) {
  const r = _autoRules.find(x => x.id === id);
  if (!r) return;
  const rule = { name: r.name, enabled: !r.enabled, match: r.match, actions: r.actions, cooldown_seconds: r.cooldown_seconds };
  const res = await api('PUT', '/automation/rules/' + encodeURIComponent(id), rule).catch(() => null);
  if (!res || res.error) { toast((res && res.error) || 'Failed', 'error'); return; }
  loadAutomation();
}

async function deleteAutomationRule(id) {
  if (!await uiConfirm('Delete this automation rule?')) return;
  const r = await api('DELETE', '/automation/rules/' + encodeURIComponent(id)).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Delete failed', 'error'); return; }
  toast('Rule deleted', 'success');
  loadAutomation();
}

// ── Fleet query (v3.4.2) — ad-hoc device filter + saved queries (localStorage) ─
const _FQ_FIELDS = {
  group: 'fq-group', tag: 'fq-tag', os: 'fq-os', online: 'fq-online',
  pending_gt: 'fq-pending', integrity: 'fq-integrity', cve_min: 'fq-cve',
  version: 'fq-version', pkg_manager: 'fq-pkgmgr', has_package: 'fq-haspkg',
  monitored: 'fq-monitored', agentless: 'fq-agentless', quarantined: 'fq-quarantined',
  reboot: 'fq-reboot', failed: 'fq-failed', kernel_outdated: 'fq-kernel',
  tp_pending: 'fq-tp', disk_gt: 'fq-disk', mem_gt: 'fq-mem', offline_days: 'fq-offline-days',
  // v4.1.0: resource + posture + identity filters
  cpu_gt: 'fq-cpu', swap_gt: 'fq-swap', load_gt: 'fq-load',
  kernel: 'fq-kernel-c', platform: 'fq-platform',
  drift: 'fq-drift', mount_issue: 'fq-mount', port_world: 'fq-portworld',
  storage_degraded: 'fq-storage', clock_skew: 'fq-clock',
  gateway_unreachable: 'fq-gw', oom_recent: 'fq-oom',
  // v4.1.0: uptime / cores / container state / timers
  uptime_gt: 'fq-uptime-gt', uptime_lt: 'fq-uptime-lt',
  cores_gt: 'fq-cores-gt', cores_lt: 'fq-cores-lt',
  container_stopped: 'fq-cstopped', container_restarting: 'fq-crestart',
  timer_failed: 'fq-timerfail',
  // v4.1.0: security / hardware posture
  brute_force: 'fq-brute', smart_failure: 'fq-smart', ups_on_battery: 'fq-ups',
  temp_high: 'fq-temp',
  // v4.1.0: capacity exhaustion (inode / fd / conntrack)
  inode_gt: 'fq-inode', fd_gt: 'fq-fd', conntrack_gt: 'fq-conntrack',
};
function _fqFields() {
  const out = {};
  for (const [param, id] of Object.entries(_FQ_FIELDS)) {
    const el = document.getElementById(id);
    if (el) out[param] = (el.value || '').trim();
  }
  return out;
}
// v5.0.0 (#U1): one generic copy-to-clipboard action used across the UI
// (device IDs, API keys, command output, enrolment commands). CSP-safe.
function copyText(text) {
  if (text == null || text === '') return;
  const ok = () => { if (typeof toast === 'function') toast('Copied to clipboard', 'success'); };
  const no = () => { if (typeof toast === 'function') toast('Copy failed — clipboard blocked', 'error'); };
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(String(text)).then(ok, no);
  } else {
    const ta = document.createElement('textarea');
    ta.value = String(text); document.body.appendChild(ta); ta.select();
    try { document.execCommand('copy'); ok(); } catch (e) { no(); }
    document.body.removeChild(ta);
  }
}

function copyApiKeyValue() { copyText(document.getElementById('apikey-value-display')?.textContent || ''); }

function loadFleetQuery() { _renderSavedQueries(); }
function _savedQueries() {
  try { return JSON.parse(localStorage.getItem('rp_fleet_queries') || '[]'); } catch (_) { return []; }
}
function _renderSavedQueries() {
  const wrap = document.getElementById('fq-saved');
  if (!wrap) return;
  const qs = _savedQueries();
  // v5.0.0 (#U5): each saved query gets rename + duplicate + delete actions.
  wrap.innerHTML = qs.map((q, i) =>
    `<span class="tl-chip" data-action="applyFleetQuery" data-arg="${i}" title="Apply this query">${escHtml(q.name)}</span>`
    + `<button class="btn-icon fs-11" data-action="renameFleetQuery" data-arg="${i}" title="Rename">${_icon('edit', 12)}</button>`
    + `<button class="btn-icon fs-11" data-action="duplicateFleetQuery" data-arg="${i}" title="Duplicate">${_icon('copy', 12)}</button>`
    + `<button class="btn-icon fs-11" data-action="deleteFleetQuery" data-arg="${i}" title="Delete saved query">${_icon('trash', 12)}</button>`).join('');
}
async function renameFleetQuery(i) {
  const qs = _savedQueries(); const q = qs[i]; if (!q) return;
  const name = await uiPrompt({ message: 'Rename query:', value: q.name });
  if (!name) return;
  q.name = name.slice(0, 40);
  localStorage.setItem('rp_fleet_queries', JSON.stringify(qs));
  _renderSavedQueries();
}
function duplicateFleetQuery(i) {
  const qs = _savedQueries(); const q = qs[i]; if (!q) return;
  qs.splice(i + 1, 0, { name: (q.name + ' copy').slice(0, 40), f: { ...(q.f || {}) } });
  localStorage.setItem('rp_fleet_queries', JSON.stringify(qs.slice(0, 50)));
  _renderSavedQueries();
  toast('Query duplicated', 'success');
}
async function saveFleetQuery() {
  const name = await uiPrompt({message: 'Name this query:'});
  if (!name) return;
  const qs = _savedQueries();
  qs.push({ name: name.slice(0, 40), f: _fqFields() });
  localStorage.setItem('rp_fleet_queries', JSON.stringify(qs.slice(0, 50)));
  _renderSavedQueries();
  toast(`Saved query "${name.slice(0, 40)}"`, 'success');
}
function applyFleetQuery(i) {
  const q = _savedQueries()[i]; if (!q) return;
  const f = q.f || {};
  for (const [param, id] of Object.entries(_FQ_FIELDS)) {
    const el = document.getElementById(id);
    if (el) el.value = f[param] || '';
  }
  runFleetQuery();
}
function deleteFleetQuery(i) {
  const qs = _savedQueries(); qs.splice(i, 1);
  localStorage.setItem('rp_fleet_queries', JSON.stringify(qs));
  _renderSavedQueries();
}
async function runFleetQuery() {
  const out = document.getElementById('fq-results');
  // Eager wire-up (CLAUDE.md): wire sort before the fetch / empty branches so
  // the ↕ indicator is present even on loading/empty states.
  tableCtl.wireSortOnly('fq-thead', 'fleet_query', runFleetQuery);
  const f = _fqFields();
  const params = new URLSearchParams();
  Object.entries(f).forEach(([k, v]) => { if (v) params.set(k, v); });
  out.innerHTML = '<div class="c-muted">Querying…</div>';
  const r = await api('GET', '/fleet/query?' + params.toString()).catch(() => null);
  if (!r) { out.innerHTML = '<div class="c-red">Query failed.</div>'; return; }
  if (!Array.isArray(r.devices) || !r.devices.length) { out.innerHTML = '<div class="c-muted fs-13">No devices match.</div>'; return; }
  const sorted = tableCtl.sortRows('fleet_query', r.devices.slice(), d => ({
    device: d.name, group: d.group || '', os: d.os || '',
    status: d.online ? 1 : 0,
    pending: (d.pending == null ? -1 : d.pending),
    cpu: (d.cpu == null ? -1 : d.cpu),
    mem: (d.mem == null ? -1 : d.mem),
    cve: (d.cve_high == null ? -1 : d.cve_high),
  }));
  // v3.13.0: when the query filtered on "has package", show the matched
  // package + its INSTALLED VERSION as a column.
  const hasPkgCol = r.devices.some(d => d.pkg_match);
  const rows = sorted.map(d =>
    `<tr><td><button class="tl-devchip" data-action="openDeviceTimeline" data-arg="${escAttr(d.device_id)}">${escHtml(d.name)}</button></td>`
    + `<td class="hint">${escHtml(d.group || '—')}</td><td class="fs-12">${escHtml((d.os || '').substring(0, 28))}</td>`
    + `<td><span class="mon-status ${d.online ? 'up' : 'down'}">${d.online ? 'Online' : 'Offline'}</span></td>`
    + `<td class="ta-center">${d.pending == null ? '—' : d.pending}</td>`
    + `<td class="ta-center">${d.cpu == null ? '—' : Math.round(d.cpu) + '%'}</td>`
    + `<td class="ta-center">${d.mem == null ? '—' : Math.round(d.mem) + '%'}</td>`
    + (hasPkgCol ? `<td class="fs-12 mono-12">${escHtml(d.pkg_match || '—')}</td>` : '')
    + `<td class="ta-center">${d.cve_high == null ? '—' : d.cve_high}</td></tr>`).join('');
  out.innerHTML = `<div class="fs-12 c-muted mb-6">${r.total} device(s)</div>`
    + `<div class="table-card"><table><thead id="fq-thead"><tr><th data-col="device">Device</th><th data-col="group">Group</th><th data-col="os">OS</th><th data-col="status">Status</th><th data-col="pending" class="ta-center">Pending</th><th data-col="cpu" class="ta-center">CPU%</th><th data-col="mem" class="ta-center">Mem%</th>`
    + (hasPkgCol ? `<th>Matched package</th>` : '')
    + `<th data-col="cve" class="ta-center">CVE</th></tr></thead><tbody>${rows}</tbody></table></div>`;
  tableCtl.wireSortOnly('fq-thead', 'fleet_query', runFleetQuery);
}

// v4.1.0: export the CURRENT fleet-query result set. CSV/XML download via an
// authed fetch→blob (honours the strict CSP — no inline anything); PDF via the
// standalone print page fleet-query.html (external css/js, same pattern as the
// posture report) so the CSP isn't broken.
function _fqParamString() {
  const f = _fqFields();
  const params = new URLSearchParams();
  Object.entries(f).forEach(([k, v]) => { if (v) params.set(k, v); });
  return params;
}
function _exportFleetQuery(format) {
  const params = _fqParamString();
  params.set('format', format);
  fetch('/api/fleet/query?' + params.toString(), { headers: { 'X-Token': getToken() } })
    .then(r => { if (!r.ok) throw new Error('failed'); return r.blob(); })
    .then(blob => {
      const u = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = u;
      a.download = `fleet-query-${new Date().toISOString().slice(0, 10)}.${format}`;
      a.click();
      URL.revokeObjectURL(u);
      toast(`${format.toUpperCase()} downloaded`, 'success');
    })
    .catch(() => toast('Export failed', 'error'));
}
function exportFleetQueryCsv() { _exportFleetQuery('csv'); }
function exportFleetQueryXml() { _exportFleetQuery('xml'); }
function printFleetQuery() {
  // Standalone print page (external assets, CSP-clean) — it re-runs the same
  // query from the params we pass and renders a light, printable document.
  const w = window.open('fleet-query.html?' + _fqParamString().toString(), '_blank');
  if (!w) { toast('Allow pop-ups to open the printable report', 'error'); return; }
  toast('Opened the printable report in a new tab', 'success');
}

// ── Release signing (v3.4.2) ─────────────────────────────────────────────────
async function loadSigning() {
  const box = document.getElementById('signing-status');
  if (!box) return;
  const s = await api('GET', '/signing/status').catch(() => null);
  if (!s) { box.innerHTML = '<div class="c-red">Failed to load signing status.</div>'; return; }
  const pk = document.getElementById('signing-pubkey');
  if (pk) pk.value = s.public_key || '';
  if (!s.gpg_available) {
    box.innerHTML = '<div class="settings-section"><p class="c-red">gpg is not installed on the server — server-side signing is unavailable. Install gpg, or sign off-server in CI.</p></div>';
    return;
  }
  const sigPill = {
    valid: '<span class="sev-pill sev-success">signed &amp; valid</span>',
    invalid: '<span class="sev-pill sev-critical">signed but INVALID</span>',
    unsigned: '<span class="sev-pill sev-low">unsigned</span>',
    unverifiable: '<span class="sev-pill sev-medium">signed (unverifiable)</span>',
  }[s.signature_status] || '';
  const enPill = s.enabled ? '<span class="sev-pill sev-success">on</span>' : '<span class="sev-pill sev-low">off</span>';
  // Explain an INVALID result (almost always: binary re-baked after signing).
  const sigWhy = (s.signature_status === 'invalid' && s.signature_detail)
    ? `<div class="fs-12 c-red mb-12">${escHtml(s.signature_detail)}. Click <strong>Sign current agent</strong> to re-sign.</div>`
    : '';
  box.innerHTML = `<div class="settings-section">
    <div class="row-8-center mb-12"><strong>Enforcement</strong> ${enPill}
      <strong class="ml-8">Current release</strong> ${sigPill}</div>
    ${sigWhy}
    <div class="fs-13 c-muted mb-12">${s.has_key
      ? `Server signing key: <code class="ff-mono">${escHtml(s.fingerprint)}</code>`
      : 'No server signing key yet.'}</div>
    <div class="row-8-center">
      ${s.has_key
        ? `<button class="btn-primary fs-12" data-action="signingSignNow">Sign current agent</button>
           <button class="btn-secondary fs-12" data-action="signingToggle" data-arg="${s.enabled ? '0' : '1'}">${s.enabled ? 'Disable' : 'Enable'} enforcement</button>
           <button class="btn-secondary fs-12" data-action="signingGenerate" data-arg="force">Regenerate key</button>`
        : `<button class="btn-primary fs-12" data-action="signingGenerate" data-arg="">Generate signing key</button>`}
      <span id="signing-action-status" class="fs-12 c-muted"></span>
    </div>
  </div>
  <div id="signing-rejections"></div>`;
  _loadSigningRejections();
}

async function _loadSigningRejections() {
  const out = document.getElementById('signing-rejections');
  if (!out) return;
  const r = await api('GET', '/fleet/agent-integrity').catch(() => null);
  const rej = ((r && r.devices) || []).filter(d => d.update_rejected);
  if (!rej.length) { out.innerHTML = ''; return; }
  out.innerHTML = `<div class="settings-section"><h3>Agents that refused an update</h3>`
    + `<p class="hint">These agents declined a self-update because it wasn't validly signed — tamper, a missing signature, or the wrong key.</p>`
    + `<div class="table-card"><table><thead><tr><th>Device</th><th>Reason</th></tr></thead><tbody>`
    + rej.map(d => `<tr><td>${escHtml(d.name)}</td><td class="c-red fs-12">${escHtml(d.update_rejected)}</td></tr>`).join('')
    + `</tbody></table></div></div>`;
}

async function signingGenerate(force) {
  const msg = force === 'force'
    ? 'Regenerate the server signing key? Agents pinned to the OLD public key will reject updates until you redistribute the new key.'
    : 'Generate a server-held signing key? The private key is stored on this server (convenient, but weaker than CI signing — see the note above).';
  if (!await uiConfirm(msg)) return;
  const st = document.getElementById('signing-action-status'); if (st) st.textContent = 'Generating…';
  const r = await api('POST', '/signing/generate', force === 'force' ? { force: true } : {}).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Failed', 'error'); if (st) st.textContent = ''; return; }
  toast('Signing key generated — now distribute the public key to agents', 'success');
  loadSigning();
}

async function signingSignNow() {
  // Signing is what every agent trusts — re-verify the admin password. uiPrompt
  // with type:'password' masks the input (the native prompt() showed cleartext).
  const pw = await uiPrompt({ title: 'Sign agent release', type: 'password', confirmText: 'Sign',
    message: 'Enter your admin password to confirm — this signature is what every agent trusts.' });
  if (!pw) return;   // cancelled or empty
  const st = document.getElementById('signing-action-status'); if (st) st.textContent = 'Signing…';
  const r = await api('POST', '/signing/sign', { password: pw }).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Failed', 'error'); if (st) st.textContent = ''; return; }
  toast('Agent release signed', 'success');
  loadSigning();
}

async function signingToggle(on) {
  const enable = on === '1' || on === 1;
  const body = { enabled: enable };
  if (!enable) {
    // Disabling enforcement is a security downgrade — re-verify the admin password (masked).
    const pw = await uiPrompt({ title: 'Disable signing enforcement', type: 'password',
      confirmText: 'Disable', danger: true,
      message: 'Enter your admin password to confirm this security downgrade.' });
    if (!pw) return;            // cancelled or empty
    body.password = pw;
  }
  const r = await api('POST', '/signing/toggle', body).catch(() => null);
  if (!r || r.error) { toast((r && r.error) || 'Failed', 'error'); return; }
  toast(r.enabled ? 'Signature enforcement on' : 'Enforcement off', 'success');
  loadSigning();
}

// v3.5.0: SBOM (CycloneDX / SPDX) downloads. Streams the file via fetch with
// the auth token and honours the server's Content-Disposition filename.
function _downloadAuthed(url, fallbackName, okLabel) {
  fetch(url, { headers: { 'X-Token': getToken() } })
    .then(r => { if (!r.ok) throw new Error('failed');
      const cd = r.headers.get('Content-Disposition') || '';
      const m = /filename=([^;]+)/.exec(cd);
      const name = m ? m[1].trim().replace(/^"|"$/g, '') : fallbackName;
      return r.blob().then(b => ({ b, name })); })
    .then(({ b, name }) => {
      const u = URL.createObjectURL(b);
      const a = document.createElement('a');
      a.href = u; a.download = name; a.click();
      URL.revokeObjectURL(u);
      toast(okLabel || 'Downloaded', 'success');
    })
    .catch(() => toast('Export failed', 'error'));
}

// v5.4.1 (G1): verify the latest backup is actually restorable.
async function testRestore() {
  const el = document.getElementById('test-restore-result');
  if (el) el.textContent = 'Testing…';
  const r = await api('POST', '/backup/test-restore');
  if (r?.ok) { toast('Backup restore test passed', 'success'); if (el) el.textContent = '✓ ' + (r.message || 'Restorable.'); }
  else { toast(r?.error || 'Restore test failed', 'error'); if (el) el.textContent = (r?.error || r?.message || 'Failed'); }
}

// v5.4.1 (C9): rotate the export-signing key used for the evidence pack +
// audit-archive signatures.
async function rotateExportKey() {
  if (!await uiConfirm('Rotate the export-signing key? New exports will use the new key; exports already issued keep their original signature.')) return;
  const r = await api('POST', '/security/rotate-export-key');
  const el = document.getElementById('export-key-result');
  if (r?.ok) { toast('Export-signing key rotated', 'success'); if (el) el.textContent = r.message || 'Rotated.'; }
  else { toast(r?.error || 'Failed', 'error'); if (el) el.textContent = r?.error || 'Failed'; }
}

