// ══ v2.9.1: Client-side debug logging ════════════════════════════════════════
// When enabled in Settings → Advanced, all UI events (button clicks, API calls,
// toasts, errors) are batched and posted to /api/debug-log. The server appends
// them to /var/lib/remotepower/debug.log along with its own request log, giving
// a single unified timeline useful for diagnosing UI bugs.
// Enabled state lives in localStorage so it survives reloads and is read fresh
// on every check — no stale closure captures.
// ═════════════════════════════════════════════════════════════════════════════

function _dbgIsEnabled() {
  return localStorage.getItem('rp_debug') === '1';
}

let _dbgBuffer   = [];
let _dbgFlushing = false;
let _dbgFlushTimer = null;

function dbg(msg, tag = 'ui') {
  if (!msg || !_dbgIsEnabled()) return;
  const ts = new Date().toISOString().slice(0, 19);
  const entry = { ts, tag, msg: String(msg).slice(0, 1024) };
  console.log('%c[dbg]%c [%s] %s', 'color:#888', '', String(tag), String(msg));
  _dbgBuffer.push(entry);
  // Debounce flushes so a burst of events makes one HTTP request
  if (_dbgFlushTimer) clearTimeout(_dbgFlushTimer);
  _dbgFlushTimer = setTimeout(_dbgFlush, 250);
}

async function _dbgFlush() {
  if (_dbgFlushing || !_dbgBuffer.length) return;
  _dbgFlushing = true;
  const batch = _dbgBuffer.splice(0, 50);
  try {
    // Use direct fetch with the real auth token — calling api() here would
    // recurse infinitely (since api() is instrumented to call dbg())
    await fetch('/api/debug-log', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Token':      (typeof getToken === 'function' ? getToken() : '')
      },
      body: JSON.stringify({ entries: batch }),
    });
  } catch (e) { /* swallow — no infinite recursion */ }
  finally { _dbgFlushing = false; }
}

// Sync localStorage with server config on page load
(async function _dbgInit() {
  // v5.0.0: only when authenticated — pre-login this 401s /api/config on the
  // login screen. Re-synced on the next load once a session exists.
  if (!getToken()) return;
  try {
    const cfg = await api('GET', '/config');
    if (cfg?.debug_logging) {
      localStorage.setItem('rp_debug', '1');
      console.info('%c[RemotePower] Debug logging ON — events stream to /var/lib/remotepower/debug.log',
                   'color:#ffa726;font-weight:bold');
      dbg('Page loaded: ' + location.pathname, 'nav');
    } else {
      localStorage.removeItem('rp_debug');
    }
  } catch(_) {}
})();

// Secrets must never reach the debug log (console or /var/lib/remotepower/
// debug.log). Mask values of credential-shaped keys in request bodies and
// responses before they're stringified for logging. Covers api_secret /
// api_key (OPNsense), password (RouterOS, login, vault), community (SNMP),
// token, passphrase, private_key, etc. — case-insensitive, recursive.
const _DBG_SECRET_RX = /(password|passwd|secret|api_?key|token|passphrase|private_key|community|credential)/i;
// budget = {n} shared across the recursion: stop expanding after ~200 nodes.
// Without this the wrapper deep-cloned AND JSON.stringified the ENTIRE response
// (megabytes for fleet endpoints like /cve/findings or /patches) just to keep
// 300 chars — seconds of main-thread work per api() call, which froze the page
// during a multi-request fleet scan. Bounding the node count makes both the
// clone and the stringify O(200) regardless of payload size.
function _dbgScrub(v, depth, budget) {
  if (depth > 6 || v == null || typeof v !== 'object') return v;
  budget = budget || { n: 200 };
  if (budget.n <= 0) return '…';
  if (Array.isArray(v)) {
    const out = [];
    for (const x of v) {
      if (--budget.n <= 0) { out.push('…'); break; }
      out.push(_dbgScrub(x, depth + 1, budget));
    }
    return out;
  }
  const out = {};
  for (const k in v) {
    if (--budget.n <= 0) { out['…'] = '…'; break; }
    out[k] = _DBG_SECRET_RX.test(k) ? '<redacted>' : _dbgScrub(v[k], depth + 1, budget);
  }
  return out;
}

// Instrument api() — wrap it to log every request and response
const _origApi = window.api;
if (typeof _origApi === 'function') {
  window.api = async function(method, path, body, ...rest) {
    // Debug is off by default — short-circuit BEFORE any _dbgScrub/JSON.stringify
    // string-building (those clone+stringify the whole payload and ran on EVERY
    // api() call, freezing the page during multi-request fleet scans).
    if (!_dbgIsEnabled()) return _origApi(method, path, body, ...rest);
    const t0 = performance.now();
    dbg(`→ ${method} ${path}` + (body ? ' body=' + JSON.stringify(_dbgScrub(body, 0)).slice(0,200) : ''), 'api');
    try {
      // Forward ALL args (incl. the 4th `extra` carrying signal / custom headers
      // like X-RP-Vault-Key) — dropping it silently broke vault-keyed DNS calls.
      const r = await _origApi(method, path, body, ...rest);
      const dt = Math.round(performance.now() - t0);
      const resp = JSON.stringify(_dbgScrub(r || {}, 0)).slice(0, 300);
      dbg(`← ${method} ${path} (${dt}ms) ${resp}`, 'api');
      return r;
    } catch (e) {
      dbg(`✗ ${method} ${path} threw: ${e?.message || e}`, 'api');
      throw e;
    }
  };
}

// Instrument toast() — log every toast shown
const _origToast = window.toast;
if (typeof _origToast === 'function') {
  window.toast = function(msg, type) {
    dbg(`toast(${type || 'info'}): ${msg}`, 'toast');
    return _origToast(msg, type);
  };
}

// Catch all uncaught errors & promise rejections
window.addEventListener('error', e => {
  dbg(`JS error: ${e.message} at ${e.filename}:${e.lineno}:${e.colno}`, 'error');
});
window.addEventListener('unhandledrejection', e => {
  dbg(`Unhandled rejection: ${e.reason?.message || e.reason}`, 'error');
});

// Log every button click (with target text/id for traceability)
document.addEventListener('click', e => {
  if (!_dbgIsEnabled()) return;
  const btn = e.target.closest('button, a.btn-primary, a.btn-secondary');
  if (!btn) return;
  const label = (btn.textContent || '').trim().slice(0, 40) ||
                btn.id || btn.className || 'unknown';
  dbg(`click: "${label}"`, 'click');
}, true);

// Replace saveDebugLogging on window so HTML onclick gets the new version that
// updates localStorage. Must be window.X = ..., not bare assignment, because
// the HTML attribute resolves against the global object.
window.saveDebugLogging = async function(enabled) {
  if (enabled) {
    localStorage.setItem('rp_debug', '1');
    dbg('Debug logging enabled via Settings', 'system');
  } else {
    dbg('Debug logging disabled via Settings', 'system');
    // Flush remaining buffer before disabling
    await _dbgFlush();
    localStorage.removeItem('rp_debug');
  }
  const r = await api('POST', '/config', { debug_logging: enabled });
  if (r?.ok) toast(enabled
    ? 'Debug logging enabled — open DevTools (F12) Console + tail /var/lib/remotepower/debug.log'
    : 'Debug logging disabled', 'info');
  else toast(r?.error || 'Failed', 'error');
};

// ══ Report an issue → GitHub (no credentials, public-safe) ═══════════════════
// A small always-on ring of recent client errors so a bug report carries
// something useful even when debug logging is off. Independent of rp_debug.
const _recentErrors = [];
function _pushClientError(s) {
  if (!s) return;
  // Strip anything token/secret-shaped before it can land in a public issue:
  // bearer-ish query params, `token=…`, and long opaque base64url blobs.
  const safe = String(s).slice(0, 300)
    .replace(/([?&](?:token|key|secret|password|passwd|access_token|id_token|code)=)[^&\s]+/gi, '$1<redacted>')
    .replace(/\b[A-Za-z0-9_-]{40,}\b/g, '<redacted>');
  _recentErrors.push(new Date().toISOString().slice(11, 19) + ' ' + safe);
  if (_recentErrors.length > 15) _recentErrors.shift();
}
window.addEventListener('error', e => _pushClientError(`JS error: ${e.message} @ ${(e.filename||'').split('/').pop()}:${e.lineno}`));
window.addEventListener('unhandledrejection', e => _pushClientError(`Promise rejection: ${e.reason?.message || e.reason}`));

// Cache the version once so the report doesn't need a live fetch.
let _issueVersionCache = null;
async function _issueVersion() {
  if (_issueVersionCache) return _issueVersionCache;
  try {
    const v = await api('GET', '/version').catch(() => null);
    const a = await api('GET', '/agent/version').catch(() => null);
    _issueVersionCache = { server: v?.current || 'unknown', agent: a?.version || 'unknown' };
  } catch (_) { _issueVersionCache = { server: 'unknown', agent: 'unknown' }; }
  return _issueVersionCache;
}

// Build a GitHub "new issue" URL prefilled with a template + auto diagnostics.
// Deliberately carries NO fleet data and NO credentials — only the app version,
// the browser/environment, the current page, and recent (scrubbed) JS errors.
async function reportIssue() {
  const ver = await _issueVersion();
  // Prefill the bug_report.yml issue FORM by field id (blank issues are
  // disabled, so a free `?body=` link would just bounce to the chooser).
  const env = [
    `Browser: ${navigator.userAgent}`,
    `Viewport: ${window.innerWidth}×${window.innerHeight} @ ${window.devicePixelRatio || 1}x`,
    `Language: ${navigator.language || '—'}`,
    `Page: ${location.hash || '#/'}`,
    `Agent version: ${ver.agent}`,
    `Time: ${new Date().toISOString()}`,
  ].join('\n');
  const logs = _recentErrors.length
    ? 'Recent client errors (auto-captured, scrubbed):\n' + _recentErrors.join('\n')
    : 'No client errors captured this session.';
  // Field ids must match .github/ISSUE_TEMPLATE/bug_report.yml.
  const qp = new URLSearchParams({
    template: 'bug_report.yml',
    version:  ver.server,
    env:      env,
    logs:     logs,
  });
  let url = 'https://github.com/tyxak/remotepower/issues/new?' + qp.toString();
  if (url.length > 7800) url = url.slice(0, 7800);   // GitHub drops over-long prefills
  window.open(url, '_blank', 'noopener');
  if (typeof toast === 'function') toast('Opening a prefilled GitHub bug report — review it before submitting (no credentials are included).', 'info');
}
window.reportIssue = reportIssue;

